-- Schema for Domain: broadcast | Business: Sports Entertainment | Version: v1_ecm
-- Generated on: 2026-05-09 01:42:54

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `sports_entertainment_ecm`.`broadcast` COMMENT 'Media rights and distribution domain managing broadcast schedules, regional sports networks (RSN), OTT/IPTV streaming platforms, PPV event packaging, content delivery networks (CDN), and rights agreements. Owns media asset metadata, live feed distribution, blackout rules, DRM policies, replay content, and multi-platform delivery including linear TV and DTC streaming services. Critical for revenue generation through media rights deals.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`media_rights_deal` (
    `media_rights_deal_id` BIGINT COMMENT 'Unique surrogate identifier for the media rights deal record in the broadcast domain. Primary key for the media_rights_deal data product.',
    `broadcast_drm_policy_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_drm_policy. Business justification: media_rights_deal has drm_policy_id → content.drm_policy (cross-domain) but no FK to broadcast.broadcast_drm_policy. The broadcast DRM policy governs how content under the deal is protected during bro',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: Media rights deals create specific compliance obligations (anti-piracy, content quotas, watershed rules, data privacy requirements per territory). Compliance teams must map each rights deal to its gov',
    `ip_portfolio_id` BIGINT COMMENT 'Foreign key linking to legal.ip_portfolio. Business justification: Media rights deals license specific IP assets (league trademarks, broadcast marks, content copyrights) tracked in the IP portfolio. Legal teams must link each deal to the underlying IP being licensed ',
    `league_id` BIGINT COMMENT 'Reference to the sports league or governing body whose content is covered by this media rights deal (e.g., NFL, NBA, FIFA, MLS). Links to the league master data product.',
    `licensee_id` BIGINT COMMENT 'Foreign key linking to broadcast.licensee. Business justification: Media rights deals grant broadcast rights to licensees (the parties receiving the license). Every media rights deal must identify the licensee receiving the rights. This is essential for contract mana',
    `regulatory_license_id` BIGINT COMMENT 'Foreign key linking to legal.regulatory_license. Business justification: Media rights deals require the licensee to hold a valid broadcast regulatory license (FCC call sign, Ofcom license). Legal and compliance teams verify license validity before deal execution and at ren',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Media rights deals are the primary broadcast revenue source; finance maps each deal to a revenue stream for ASC 606 recognition, ARR tracking, and P&L segment reporting. A sports finance expert would ',
    `corporate_entity_id` BIGINT COMMENT 'Foreign key linking to legal.corporate_entity. Business justification: The rights_holder_name plain text field denormalizes the corporate entity that holds the broadcast rights. Legal entity management requires a proper FK to corporate_entity for entity hierarchy reporti',
    `rights_holder_id` BIGINT COMMENT 'Foreign key linking to broadcast.rights_holder. Business justification: Media rights deals are negotiated with rights holders who own the content rights being licensed. Every media rights deal must identify the rights holder granting the rights. This is a foundational rel',
    `tax_jurisdiction_id` BIGINT COMMENT 'Foreign key linking to finance.tax_jurisdiction. Business justification: Cross-border media rights deals are subject to withholding tax and VAT that vary by territory. Finance requires tax_jurisdiction linkage for deal-level withholding tax calculation, treaty application,',
    `vendor_id` BIGINT COMMENT 'Reference to the RSN affiliate entity associated with this deal when the deal type is rsn. Identifies the specific regional network carrying the broadcast rights within a defined geographic footprint.',
    `annual_rights_fee_usd` DECIMAL(18,2) COMMENT 'Annual rights fee payable by the licensee in US Dollars. Used for ARR (Annual Recurring Revenue) tracking, financial planning in Workday Adaptive Planning, and year-over-year revenue comparison.',
    `blackout_rules_applicable` BOOLEAN COMMENT 'Indicates whether geographic or platform-based blackout rules apply to content distributed under this deal. When true, the CDN and streaming platform must enforce territory-based content restrictions.',
    `blackout_territory_codes` STRING COMMENT 'Comma-separated list of ISO 3166-1 alpha-3 country or market codes where content blackout restrictions apply under this deal. Used by CDN geo-restriction and OTT/IPTV platform access control engines.',
    `cdn_provider_name` STRING COMMENT 'Name of the CDN provider responsible for delivering digital content under this deal (e.g., Akamai, Fastly, Cloudflare). Relevant for OTT/IPTV and DTC streaming deals. Supports SLA monitoring and CDN cost allocation.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the deals contractual currency (e.g., USD, GBP, EUR). Required for multi-currency rights deals in international markets.. Valid values are `^[A-Z]{3}$`',
    `dalet_contract_ref` STRING COMMENT 'External reference identifier from Dalet Galaxy Media Asset Management system linking this deal to the corresponding rights contract object in the broadcast workflow system. Supports data lineage from source system.',
    `data_privacy_compliance_flag` BOOLEAN COMMENT 'Indicates whether the deal includes contractual data privacy compliance obligations (GDPR, CCPA) governing fan data collected through the licensees broadcast and streaming platforms.',
    `deal_created_timestamp` TIMESTAMP COMMENT 'Timestamp when this media rights deal record was first created in the system. Audit trail field for data governance and SOX compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `deal_name` STRING COMMENT 'Human-readable descriptive name of the media rights deal (e.g., NFL Sunday Ticket RSN Agreement FY2025). Used for identification in reporting and dashboards.',
    `deal_number` STRING COMMENT 'Externally-known alphanumeric contract reference number assigned by the rights management system (Dalet Galaxy or Salesforce CRM) and used in all correspondence with broadcast partners. Serves as the BUSINESS_IDENTIFIER for this agreement.',
    `deal_status` STRING COMMENT 'Current lifecycle state of the media rights deal. Drives rights enforcement and blackout rule activation. Values: draft, pending_approval, active, suspended, expired, terminated.. Valid values are `draft|pending_approval|active|suspended|expired|terminated`',
    `deal_type` STRING COMMENT 'Classification of the deal by distribution channel or platform type. Values: linear_tv (traditional broadcast), rsn (Regional Sports Network), ott (Over-The-Top Streaming), iptv (Internet Protocol Television), ppv (Pay-Per-View), dtc (Direct-To-Consumer). [ENUM-REF-CANDIDATE: linear_tv|rsn|ott|iptv|ppv|dtc — promote to reference product if additional types emerge]. Valid values are `linear_tv|rsn|ott|iptv|ppv|dtc`',
    `deal_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this media rights deal record was most recently modified. Supports change data capture (CDC) in the Databricks Silver Layer and audit trail requirements. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `deal_value_usd` DECIMAL(18,2) COMMENT 'Total gross contract value of the media rights deal in US Dollars over the full contract term. Represents the headline financial commitment. Used for EBITDA reporting and ARR calculations.',
    `digital_streaming_rights_included` BOOLEAN COMMENT 'Indicates whether OTT/IPTV digital streaming rights are included in this deal, permitting distribution via internet-based platforms (e.g., DTC apps, OTT services).',
    `dispute_resolution_mechanism` STRING COMMENT 'Contractually agreed mechanism for resolving disputes arising from this deal. cas_arbitration refers to the Court of Arbitration for Sport, applicable for international sports rights disputes.. Valid values are `arbitration|litigation|mediation|cas_arbitration`',
    `effective_date` DATE COMMENT 'Calendar date on which the media rights deal becomes legally binding and rights entitlements are enforceable. Aligns with contract commencement date in Salesforce CRM.',
    `exclusivity_type` STRING COMMENT 'Defines whether the rights granted are exclusive to the licensee within the territory, non-exclusive (shared with other licensees), first-window (first broadcast rights before others), or co-exclusive (shared exclusivity with a limited number of partners).. Valid values are `exclusive|non_exclusive|first_window|co_exclusive`',
    `execution_date` DATE COMMENT 'The date on which all parties formally signed and executed the media rights agreement. Distinct from effective_date (when rights begin) and deal_created_timestamp (when the record was created in the system).',
    `expiry_date` DATE COMMENT 'Calendar date on which the media rights deal expires and all rights entitlements cease. Nullable for perpetual or open-ended agreements. Critical for rights window enforcement and renewal planning.',
    `governing_law_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the jurisdiction whose laws govern this media rights agreement (e.g., USA, GBR, CHE). Determines applicable regulatory frameworks and dispute resolution venue.. Valid values are `^[A-Z]{3}$`',
    `highlights_rights_included` BOOLEAN COMMENT 'Indicates whether rights to produce and distribute short-form highlight clips are included in this deal. Relevant for social media, news broadcasts, and digital platform distribution.',
    `live_rights_included` BOOLEAN COMMENT 'Indicates whether live broadcast rights for events are included in this deal. Drives live feed distribution scheduling and OB (Outside Broadcast) resource allocation.',
    `max_events_per_season` STRING COMMENT 'Maximum number of events the licensee may broadcast per season under this deal. Caps the licensees broadcast entitlement and protects rights holders ability to distribute remaining events to other partners.',
    `min_guaranteed_events` STRING COMMENT 'Contractually guaranteed minimum number of live events the licensee is entitled to broadcast under this deal per contract year. Triggers make-good provisions if not met.',
    `payment_schedule_type` STRING COMMENT 'Defines the frequency and structure of rights fee payments from the licensee to the rights holder. Drives accounts receivable scheduling in SAP S/4HANA SD.. Valid values are `annual|semi_annual|quarterly|monthly|lump_sum`',
    `ppv_rights_included` BOOLEAN COMMENT 'Indicates whether Pay-Per-View event packaging rights are included in this deal, allowing the licensee to offer individual event purchases to consumers.',
    `renewal_notice_days` STRING COMMENT 'Number of calendar days prior to expiry_date by which either party must provide written notice of intent to renew or terminate. Drives automated renewal alert workflows in Salesforce CRM.',
    `renewal_option_type` STRING COMMENT 'Type of renewal option included in the deal. Automatic renewal triggers without action; mutual_agreement requires both parties to agree; right_of_first_refusal gives the licensee priority to match competing offers; none means no renewal option exists.. Valid values are `automatic|mutual_agreement|right_of_first_refusal|none`',
    `replay_rights_included` BOOLEAN COMMENT 'Indicates whether replay/rebroadcast rights are included in this deal, allowing the licensee to air recorded versions of events after the live window closes.',
    `revenue_share_pct` DECIMAL(18,2) COMMENT 'Percentage of net broadcast revenue shared back to the rights holder or league under the revenue share structure of this deal. Expressed as a decimal percentage (e.g., 15.00 = 15%). Critical for financial settlement calculations.',
    `rights_categories` STRING COMMENT 'Comma-separated list of rights categories included in this deal. Typical values: live, replay, highlights, ppv, clip_licensing, archive, digital_streaming, radio. Captures the full scope of content rights granted. [ENUM-REF-CANDIDATE: live|replay|highlights|ppv|clip_licensing|archive|digital_streaming|radio — promote to reference product]',
    `rights_window_count` STRING COMMENT 'Total number of distinct rights windows (time-period/platform/territory entitlement combinations) defined under this deal. Supports rights window enforcement and deal complexity classification.',
    `rsn_affiliate_code` BIGINT COMMENT 'Reference to the RSN affiliate entity associated with this deal when the deal type is rsn. Identifies the specific regional network carrying the broadcast rights within a defined geographic footprint.',
    `salesforce_opportunity_reference` STRING COMMENT 'External reference identifier from Salesforce CRM linking this media rights deal record to the originating CRM opportunity or contract object. Supports data lineage and system-of-record traceability.',
    `sport_name` STRING COMMENT 'Name of the sport covered by this media rights deal (e.g., American Football, Basketball, Soccer, Baseball, Hockey). Supports multi-sport deal classification and rights analytics.',
    `sublicensing_permitted` BOOLEAN COMMENT 'Indicates whether the licensee is contractually permitted to sublicense the media rights to third parties (e.g., regional affiliates, streaming sub-platforms). Critical for IP (Intellectual Property) protection and rights chain management.',
    `termination_for_cause_permitted` BOOLEAN COMMENT 'Indicates whether either party may terminate the deal early for cause (e.g., breach of contract, regulatory non-compliance, PED violations affecting league integrity). Relevant for compliance and legal risk management.',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the primary geographic territory in which the broadcast rights are granted. Use WLD for worldwide deals. Drives blackout rule enforcement and CDN geo-restriction.. Valid values are `^[A-Z]{3}$`',
    `territory_scope` STRING COMMENT 'Categorical scope of the geographic territory covered by this deal. Distinguishes between national, regional (e.g., RSN footprint), local market, worldwide, or multi-territory agreements.. Valid values are `national|regional|local|worldwide|multi_territory`',
    CONSTRAINT pk_media_rights_deal PRIMARY KEY(`media_rights_deal_id`)
) COMMENT 'Master record of media rights agreements with broadcast partners (RSN, OTT, linear TV networks), including granular rights window definitions. Captures rights holder, territory, sport/league, exclusivity type, deal value, contract term, revenue share structure, rights categories (live, replay, highlights, PPV), and per-window platform/territory/time-period entitlements with sublicensing permissions. SSOT for all broadcast rights ownership, licensing terms, and rights window enforcement. Sourced from Dalet Galaxy and Salesforce CRM.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`broadcast_schedule` (
    `broadcast_schedule_id` BIGINT COMMENT 'Unique surrogate identifier for each broadcast schedule entry in the Dalet Galaxy broadcast workflow system. Primary key for the broadcast_schedule data product.',
    `broadcast_rights_window_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_rights_window. Business justification: broadcast_schedule has rights_window_id → content.rights_window (cross-domain) but no FK to broadcast.broadcast_rights_window. The in-domain broadcast_rights_window is the authoritative record definin',
    `capacity_config_id` BIGINT COMMENT 'Foreign key linking to venue.capacity_config. Business justification: Broadcast schedulers must reference the active venue capacity configuration to confirm camera positions, floor plan, and sellable capacity for production planning. capacity_config.broadcast_camera_pos',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel or platform (linear TV, OTT, IPTV, RSN) on which this schedule entry is assigned for distribution. Sourced from the content platform channel registry.',
    `content_drm_policy_id` BIGINT COMMENT 'Reference to the Digital Rights Management (DRM) policy applied to this broadcast schedule entry for content protection across OTT, IPTV, and DTC platforms. Ensures compliance with rights agreements and prevents unauthorized redistribution.',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: Sponsorship deals specify broadcast_mention_requirement obligations. The broadcast schedule is the operational record fulfilling those obligations. Linking enables compliance tracking of contractual b',
    `digital_touchpoint_id` BIGINT COMMENT 'Foreign key linking to platform.digital_touchpoint. Business justification: Broadcast scheduling operations require knowing which digital touchpoints (OTT app, web player, IPTV) deliver each scheduled broadcast. This drives platform-specific configuration, geo-restriction enf',
    `event_fixture_id` BIGINT COMMENT 'Reference to the sporting or entertainment event being broadcast in this schedule window. Links the broadcast schedule to the event domain for event-to-channel assignment tracking.',
    `fixture_id` BIGINT COMMENT 'Reference to the sporting or entertainment event being broadcast in this schedule window. Links the broadcast schedule to the event domain for event-to-channel assignment tracking.',
    `league_schedule_id` BIGINT COMMENT 'Foreign key linking to league.schedule. Business justification: Broadcast operations teams map air schedules to the leagues official game schedule for rights compliance, production planning, and blackout enforcement. A sports-entertainment domain expert would exp',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Broadcast scheduling is organized by league season for rights compliance, season-level viewership reporting, and upfront ad sales planning. Every broadcast schedule entry belongs to a specific league ',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to content.platform_channel. Business justification: Broadcast scheduling for OTT and digital platforms requires mapping schedule entries to content platform channels to validate platform capabilities (resolution, DRM, ad insertion). Distribution planni',
    `playoff_bracket_id` BIGINT COMMENT 'Foreign key linking to league.playoff_bracket. Business justification: Playoff broadcasts require scheduling tied to specific bracket rounds and matchups for rights compliance, PPV pricing, and production planning. Broadcast schedulers must know which playoff bracket slo',
    `production_team_id` BIGINT COMMENT 'Reference to the production crew or outside broadcast (OB) unit assigned to produce this broadcast schedule entry. Links to workforce and production assignment records for resource planning.',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to partner.vendor_contract. Business justification: Scheduled broadcasts are distributed under specific partner/distributor vendor contracts. This link replaces the denormalized broadcast_partner_name and enables contract-based rights compliance checks',
    `venue_id` BIGINT COMMENT 'Reference to the venue or facility from which this broadcast originates. Used for OB unit logistics, venue operations coordination, and geographic rights enforcement.',
    `actual_end_time` TIMESTAMP COMMENT 'Actual timestamp at which the broadcast feed concluded. Used alongside actual_start_time to compute true broadcast duration for rights compliance and billing reconciliation.',
    `actual_start_time` TIMESTAMP COMMENT 'Actual timestamp at which the broadcast feed went live or playback commenced. Compared against scheduled_start_time for on-time performance reporting and SLA compliance tracking.',
    `ad_break_count` STRING COMMENT 'Number of planned commercial advertisement breaks within this broadcast schedule entry. Used for sponsorship inventory management, ad sales planning, and revenue forecasting.',
    `ad_break_duration_minutes` STRING COMMENT 'Total planned duration of all commercial advertisement breaks in minutes for this broadcast schedule entry. Used for ad inventory capacity planning and sponsor commitment fulfillment tracking.',
    `air_date` DATE COMMENT 'Calendar date on which the broadcast is scheduled to air. Used for day-level scheduling, program guide publication, and rights window validation.',
    `audio_description_required` BOOLEAN COMMENT 'Indicates whether audio description (video description for visually impaired viewers) is required for this broadcast. Driven by FCC accessibility mandates and ADA compliance requirements for broadcast content.',
    `blackout_applicable` BOOLEAN COMMENT 'Indicates whether broadcast blackout rules apply to this schedule entry. When True, the blackout_rule_id and blackout_region_code must be evaluated before distribution to enforce territorial rights restrictions.',
    `broadcast_type` STRING COMMENT 'Classification of the broadcast feed type indicating whether the content is transmitted live, on a tape-delay basis, as a replay, as a highlight package, or as a Pay-Per-View (PPV) event. Drives rights enforcement, DRM policy application, and CDN routing logic.. Valid values are `live|tape_delay|replay|highlight|ppv`',
    `cdn_profile_code` STRING COMMENT 'Code identifying the Content Delivery Network (CDN) configuration profile used to distribute this broadcast. Determines routing, caching, and failover behavior for digital platform delivery.',
    `closed_caption_required` BOOLEAN COMMENT 'Indicates whether closed captioning is required for this broadcast schedule entry. Mandatory for FCC compliance under the Twenty-First Century Communications and Video Accessibility Act (CVAA) and ADA accessibility requirements.',
    `commentary_language_code` STRING COMMENT 'ISO 639-1/639-2 language code for the commentary/play-by-play audio track, which may differ from the primary broadcast language. Relevant for international feed distribution and multi-language OTT packaging.. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this broadcast schedule record was first created in the Dalet Galaxy system and ingested into the Silver Layer. Supports audit trail, data lineage, and SOX financial controls compliance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the PPV price and any associated financial values on this schedule entry (e.g., USD, GBP, EUR). Required for multi-currency international broadcast markets.. Valid values are `^[A-Z]{3}$`',
    `feed_format` STRING COMMENT 'Technical broadcast feed format specifying the video quality standard for this schedule entry (e.g., HD, 4K, SD, HDR, VR). Used for CDN capacity planning, encoder assignment, and viewer experience reporting.. Valid values are `HD|4K|SD|HDR|VR`',
    `international_feed` BOOLEAN COMMENT 'Indicates whether this broadcast schedule entry uses an international feed (world feed) as opposed to a domestic production feed. Relevant for FIFA, IOC, and other international governing body rights distribution.',
    `language_code` STRING COMMENT 'ISO 639-1/639-2 language code for the primary audio track of this broadcast (e.g., en, es, fr-CA). Supports multi-language distribution and regional audience targeting.. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `league_code` STRING COMMENT 'Code identifying the sports league or governing body associated with the event being broadcast (e.g., NFL, NBA, MLB, NHL, MLS, FIFA, UFC, ATP). Used for rights segmentation, league governance reporting, and audience analytics.',
    `ob_unit_code` STRING COMMENT 'Identifier for the Outside Broadcast (OB) truck or mobile production unit assigned to this broadcast schedule entry. Used for equipment scheduling, logistics coordination, and production cost allocation.',
    `platform_type` STRING COMMENT 'Category of the distribution platform for this broadcast schedule entry. Distinguishes linear TV, Over-The-Top (OTT) streaming, Internet Protocol Television (IPTV), Regional Sports Network (RSN), Direct-To-Consumer (DTC), and Pay-Per-View (PPV) platform delivery modes.. Valid values are `linear_tv|ott|iptv|rsn|dtc|ppv_platform`',
    `ppv_event` BOOLEAN COMMENT 'Indicates whether this broadcast schedule entry is a Pay-Per-View (PPV) event requiring individual purchase or access authorization. When True, triggers PPV pricing, access control, and revenue tracking workflows.',
    `ppv_price` DECIMAL(18,2) COMMENT 'Retail price charged to consumers for access to this Pay-Per-View (PPV) broadcast event. Applicable only when ppv_event is True. Used for revenue forecasting, pricing strategy analysis, and consumer billing.',
    `program_duration_minutes` STRING COMMENT 'Planned duration of the broadcast program in minutes as scheduled in the program guide. Used for slot allocation, ad break planning, and rights window compliance verification.',
    `rating_classification` STRING COMMENT 'Content rating classification assigned to this broadcast as per the TV Parental Guidelines system (e.g., TV-G, TV-PG, TV-14, TV-MA). Required for FCC compliance, parental control enforcement, and OTT platform content filtering.. Valid values are `TV-G|TV-PG|TV-14|TV-MA|TV-Y|TV-Y7`',
    `reference_code` STRING COMMENT 'Externally-known alphanumeric code assigned by Dalet Galaxy to uniquely identify this broadcast schedule entry across systems. Used for cross-system reconciliation and operational communication with broadcast partners.',
    `region_code` STRING COMMENT 'ISO 3166-1 alpha-3 country or territory code identifying the primary broadcast market for this schedule entry (e.g., USA, GBR, CAN). Used for rights territory enforcement, blackout rule application, and regional audience analytics.. Valid values are `^[A-Z]{3}$`',
    `rsn_affiliate_code` STRING COMMENT 'Code identifying the Regional Sports Network (RSN) affiliate carrying this broadcast. Applicable for regional distribution entries. Used for affiliate rights tracking, revenue sharing calculations, and regional audience reporting.',
    `schedule_status` STRING COMMENT 'Current lifecycle state of the broadcast schedule entry within the Dalet Galaxy workflow. Drives operational readiness and downstream distribution actions. [ENUM-REF-CANDIDATE: draft|confirmed|on_air|completed|cancelled|postponed — promote to reference product if additional states are required]. Valid values are `draft|confirmed|on_air|completed|cancelled|postponed`',
    `scheduled_end_time` TIMESTAMP COMMENT 'Precise date and timestamp at which the broadcast window is scheduled to conclude, including timezone offset. Used for slot duration calculation, back-to-back scheduling, and CDN resource planning.',
    `scheduled_start_time` TIMESTAMP COMMENT 'Precise date and timestamp at which the broadcast window is scheduled to begin, including timezone offset. Principal real-world event time for this schedule entry. Stored in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX).',
    `simulcast_flag` BOOLEAN COMMENT 'Indicates whether this broadcast schedule entry is a simultaneous multi-platform broadcast (simulcast) airing on multiple channels or platforms at the same time. Used for rights management and audience deduplication in ratings reporting.',
    `sport_type` STRING COMMENT 'Category of sport or entertainment content being broadcast (e.g., American Football, Basketball, Soccer, Baseball, Hockey, Tennis, MMA, Concert). Used for content classification, audience segmentation, and rights categorization. [ENUM-REF-CANDIDATE: american_football|basketball|soccer|baseball|hockey|tennis|mma|concert|other — promote to reference product]',
    `time_zone` STRING COMMENT 'IANA time zone identifier for the primary broadcast market (e.g., America/New_York, Europe/London). Required for accurate local air time display in program guides and blackout rule enforcement.',
    `title` STRING COMMENT 'Human-readable title of the broadcast schedule entry as it appears in the Dalet Galaxy workflow and on-air program guides. Typically includes event name, league, and broadcast type (e.g., NFL Sunday Night Football — Live).',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this broadcast schedule record was last modified in the source system or Silver Layer. Used for change detection, incremental data loading, and audit trail maintenance.',
    CONSTRAINT pk_broadcast_schedule PRIMARY KEY(`broadcast_schedule_id`)
) COMMENT 'Operational schedule of all planned and confirmed broadcast windows across linear TV, OTT, IPTV, and RSN platforms. Tracks event-to-channel assignments, air time, time zone, blackout applicability, feed type (live, tape-delay, replay), and production assignments. Core operational backbone for broadcast distribution — every broadcast begins as a schedule entry. Sourced from Dalet Galaxy broadcast workflow.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`channel` (
    `channel_id` BIGINT COMMENT 'Primary key for channel',
    `broadcast_drm_policy_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_drm_policy. Business justification: channel has drm_policy_code (STRING) which is a denormalized reference to the DRM policy governing the channels content protection. Replacing with a FK to broadcast_drm_policy enables proper DRM poli',
    `corporate_entity_id` BIGINT COMMENT 'Foreign key linking to legal.corporate_entity. Business justification: The platform_operator plain text field denormalizes the corporate entity that operates the channel. Legal entity management, intercompany agreements, and SOX reporting require a proper FK to corporate',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Each broadcast channel is a cost center in finance — channel operations (transmission, staffing, licensing fees) are tracked per channel for budget management and P&L. A sports broadcast finance exper',
    `distributor_id` BIGINT COMMENT 'Foreign key linking to broadcast.distributor. Business justification: Broadcast channels are operated and distributed by distributors (cable operators, satellite providers, OTT platforms). Adding distributor_id enables tracking which distributor operates each channel. T',
    `governing_body_id` BIGINT COMMENT 'Foreign key linking to compliance.governing_body. Business justification: Broadcast channels are regulated by specific governing bodies (FCC, Ofcom, CRTC). The governing_body table has a broadcast_regulatory_authority flag confirming this relationship. Compliance officers',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Each broadcast channel generates revenue (subscriptions, ad sales) tracked in a dedicated profit center for segment reporting and EBITDA analysis. Finance uses channel-level profit centers for channel',
    `regulatory_license_id` BIGINT COMMENT 'Foreign key linking to legal.regulatory_license. Business justification: Each broadcast channel must hold a valid regulatory license (FCC call sign, Ofcom license, cable franchise). The regulatory_license product has broadcast_license_call_sign and broadcast_frequency_band',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Each broadcast channel maps to a primary revenue stream (e.g., linear TV subscription, OTT streaming) for finance revenue reporting. Finance tracks channel-level revenue streams for distribution platf',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to partner.vendor_contract. Business justification: Broadcast channels are distributed via CDN/platform operators under vendor contracts. This link enables contract-based uptime SLA monitoring, renewal tracking, and distribution cost allocation per cha',
    `vendor_id` BIGINT COMMENT 'Foreign key linking this distribution agreement to the vendor (CDN, IPTV operator, satellite provider) responsible for distributing the channel.',
    `ad_insertion_enabled` BOOLEAN COMMENT 'Indicates whether dynamic ad insertion (DAI) is enabled for this channel. When True, the channel supports server-side or client-side ad insertion for CPM (Cost Per Mille) based advertising revenue. Critical for sponsorship and advertising revenue planning.',
    `audio_format` STRING COMMENT 'Audio encoding format delivered by this channel (e.g., stereo, 5.1 surround, Dolby Atmos). Used for broadcast technical compliance, production scheduling, and premium tier packaging.. Valid values are `stereo|5.1|7.1|Dolby_Atmos|mono`',
    `bitrate_kbps` STRING COMMENT 'Target or maximum video bitrate for this channel measured in kilobits per second (Kbps). Used for CDN bandwidth capacity planning, SLA definition, and quality tier differentiation between SD, HD, and 4K tiers.',
    `blackout_rule_code` STRING COMMENT 'Code identifying the blackout restriction rule set applied to this channel. Blackout rules restrict broadcast of specific events in defined geographic territories per league agreements (e.g., NFL, NBA, MLB local blackout policies). Enforced at the channel level for linear and OTT distribution.',
    `broadcast_format` STRING COMMENT 'Primary content delivery format of this channel. Live = real-time event broadcast; Replay = time-shifted full event replay; VOD (Video on Demand) = on-demand library content; Simulcast = simultaneous broadcast across multiple platforms; Highlights = short-form curated content.. Valid values are `live|replay|VOD|simulcast|highlights`',
    `channel_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the channel, used in rights agreements, scheduling systems, and Dalet Galaxy media asset management workflows. Serves as the natural key across operational systems.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `channel_name` STRING COMMENT 'Official human-readable name of the broadcast channel or distribution outlet (e.g., ESPN Regional Sports Network East, Sports Entertainment OTT HD). Used in scheduling, rights contracts, and fan-facing interfaces.',
    `channel_number` STRING COMMENT 'Logical channel number assigned by the platform operator or cable/satellite provider for linear channel lineup placement (e.g., channel 720 on DirecTV). Used for EPG (Electronic Program Guide) integration and subscriber navigation.',
    `channel_status` STRING COMMENT 'Current operational lifecycle status of the channel. Active = currently distributing content; Inactive = temporarily off-air; Suspended = distribution halted due to rights or compliance issue; Pending Launch = configured but not yet live; Decommissioned = permanently retired.. Valid values are `active|inactive|suspended|pending_launch|decommissioned`',
    `channel_type` STRING COMMENT 'Categorical classification of the channels distribution model. Linear = traditional scheduled broadcast; OTT (Over-The-Top) = internet streaming; IPTV (Internet Protocol Television) = managed IP delivery; DTC (Direct-To-Consumer) = owned streaming service; PPV (Pay-Per-View) = event-based purchase; RSN (Regional Sports Network) = regional linear affiliate.. Valid values are `linear|OTT|IPTV|DTC|PPV|RSN`',
    `closed_caption_supported` BOOLEAN COMMENT 'Indicates whether this channel supports closed captioning for accessibility compliance. Required for ADA (Americans with Disabilities Act) and FCC closed captioning mandates for broadcast channels serving US audiences.',
    `content_category` STRING COMMENT 'Primary content category classification for this channel. Used for audience segmentation, advertising targeting, rights categorization, and regulatory classification with the FCC.. Valid values are `sports|entertainment|news|mixed|documentary`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code representing the primary country of broadcast license or registration for this channel (e.g., USA, GBR, CAN). Used for regulatory compliance, blackout rule enforcement, and rights territory mapping.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this channel record was first created in the system, in ISO 8601 format with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides audit trail for data governance and lineage tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the monthly_rights_fee and any financial amounts associated with this channel (e.g., USD, EUR, GBP). Required for multi-currency financial reporting and SAP S/4HANA FI integration.. Valid values are `^[A-Z]{3}$`',
    `decommission_date` DATE COMMENT 'Calendar date on which this channel was or is scheduled to be permanently decommissioned and removed from distribution. Nullable for active channels. Used for rights wind-down planning and regulatory notification.',
    `distribution_territory` STRING COMMENT 'The geographic territory or market in which this vendor is authorized to distribute the channel under this agreement. A single channel may have different vendors authorized for different territories (e.g., US West, EMEA, APAC).',
    `effective_from` DATE COMMENT 'The calendar date on which this distribution agreement between the channel and vendor becomes effective and the vendor is authorized to begin distribution.',
    `effective_until` DATE COMMENT 'The calendar date on which this distribution agreement expires or is scheduled to terminate. Null indicates an open-ended agreement.',
    `encoding_standard` STRING COMMENT 'Video encoding/compression standard used for this channels stream (e.g., H.264/AVC, H.265/HEVC, AV1). Determines device compatibility, CDN efficiency, and streaming quality at given bitrates.. Valid values are `H.264|H.265|AV1|MPEG-2|VP9`',
    `epg_code` STRING COMMENT 'External identifier used by Electronic Program Guide (EPG) data providers (e.g., Tribune Media, Gracenote) to reference this channel in scheduling and guide data feeds. Enables automated schedule ingestion and viewer guide population.',
    `frame_rate` DECIMAL(18,2) COMMENT 'Video frame rate specification for this channel (e.g., 25fps for PAL markets, 30fps for NTSC markets, 60fps for premium sports HD). Impacts production compatibility, CDN bandwidth, and broadcast technical standards compliance.',
    `geographic_coverage` STRING COMMENT 'Textual description or structured list of geographic markets, regions, or territories this channel is licensed to serve (e.g., Northeast USA, Western Europe, Global excluding China). Distinct from country_code which captures the registration country; this field captures the full distribution footprint for rights enforcement.',
    `language_code` STRING COMMENT 'Primary broadcast language of the channel expressed as an ISO 639-1 or ISO 639-2 language code (e.g., en, es, fr-CA). Used for audience segmentation, rights territory management, and multi-language distribution planning.. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this channel record, in ISO 8601 format with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change data capture (CDC), data lineage, and audit compliance.',
    `launch_date` DATE COMMENT 'Calendar date on which this channel was officially launched and made available to audiences. Used for channel lifecycle tracking, anniversary reporting, and rights agreement effective date alignment.',
    `max_concurrent_streams` STRING COMMENT 'Maximum number of simultaneous viewer streams permitted on this channel as defined by rights agreements or platform capacity constraints. Used for CDN capacity planning and rights compliance enforcement during peak events.',
    `monthly_rights_fee` DECIMAL(18,2) COMMENT 'Monthly fee paid to or received from the platform operator or rights holder for distribution of this channel, expressed in the channels billing currency. Confidential commercial term used for revenue management and EBITDA reporting.',
    `multiview_supported` BOOLEAN COMMENT 'Indicates whether this channel supports simultaneous multi-angle or multi-game viewing (multiview) for premium subscribers. A differentiating feature for OTT and DTC channels used in fan engagement and premium tier upsell strategies.',
    `ob_unit_required` BOOLEAN COMMENT 'Indicates whether this channel requires an OB (Outside Broadcast) unit for live event production. When True, triggers OB unit scheduling and resource allocation workflows in the broadcast operations team.',
    `parental_rating` STRING COMMENT 'Content parental advisory rating assigned to this channel per FCC and TV Parental Guidelines standards (e.g., TV-G, TV-PG, TV-14, TV-MA). Used for parental control enforcement, platform compliance, and audience targeting restrictions.. Valid values are `TV-G|TV-PG|TV-14|TV-MA|NR`',
    `platform_type` STRING COMMENT 'The technical platform or delivery mechanism through which this vendor distributes the channel under this agreement. Determines infrastructure requirements and may affect revenue share terms.',
    `ppv_enabled` BOOLEAN COMMENT 'Indicates whether this channel supports PPV (Pay-Per-View) event packaging and transactional purchase by viewers. When True, the channel can be used to distribute PPV events with individual purchase requirements rather than subscription access.',
    `resolution_tier` STRING COMMENT 'Video resolution quality tier offered by this channel. SD (Standard Definition), HD (High Definition), 4K (Ultra High Definition), 8K (Super Hi-Vision). Drives CDN (Content Delivery Network) bandwidth planning, rights packaging, and subscriber pricing tiers.. Valid values are `SD|HD|4K|8K`',
    `revenue_share_pct` DECIMAL(18,2) COMMENT 'The percentage of distribution revenue allocated to the vendor under this agreement. This is a commercially sensitive term unique to each channel-vendor distribution deal and cannot reside on either the channel or vendor master record.',
    `rsn_affiliate_name` STRING COMMENT 'Name of the RSN (Regional Sports Network) affiliate associated with this channel, where applicable. Populated only for channels of type RSN or linear with regional affiliation agreements. Used for RSN rights revenue allocation and affiliate relationship management.',
    `signal_type` STRING COMMENT 'Technical signal delivery mechanism for this channel. Determines infrastructure requirements, regulatory classification, and distribution partner compatibility. [ENUM-REF-CANDIDATE: digital|analog|IP|satellite|cable|terrestrial|fiber|microwave — promote to reference product]. Valid values are `digital|analog|IP|satellite|cable|terrestrial`',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this channel record was originated or last updated (e.g., DALET for Dalet Galaxy MAM, SALESFORCE for Salesforce CRM). Used for data lineage, reconciliation, and Silver layer provenance tracking in the Databricks Lakehouse.. Valid values are `DALET|SALESFORCE|SAP|MANUAL|ARCHTICS`',
    `stream_url` STRING COMMENT 'Primary ingest or origin stream URL for OTT, IPTV, or DTC channel types. Confidential as it represents a direct access endpoint to live feed infrastructure. Used by broadcast operations and CDN configuration teams.',
    `subscriber_count` BIGINT COMMENT 'Current number of active subscribers or authorized viewers for this channel. For OTT/DTC/IPTV channels, reflects platform subscription count. For linear channels, reflects reported household reach. Used for ARPU (Average Revenue Per User) calculation and rights fee negotiations.',
    `time_zone` STRING COMMENT 'IANA time zone identifier for the channels primary broadcast schedule reference (e.g., America/New_York, Europe/London). Used for EPG scheduling, live event timing, and blackout rule time-window enforcement.',
    `uptime_sla_pct` DECIMAL(18,2) COMMENT 'Contractually committed uptime percentage for this channel as defined in the SLA (Service Level Agreement) with the platform operator or CDN provider (e.g., 99.95). Used for operational performance monitoring and penalty clause management.',
    CONSTRAINT pk_channel PRIMARY KEY(`channel_id`)
) COMMENT 'Master catalog of all broadcast channels and distribution outlets managed by Sports Entertainment — including RSN affiliates, OTT streaming channels, IPTV feeds, linear TV networks, and DTC streaming services. Captures channel name, type (linear/OTT/IPTV/DTC), platform operator, geographic coverage, language, resolution tier (SD/HD/4K), and active status.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`blackout_rule` (
    `blackout_rule_id` BIGINT COMMENT 'Unique surrogate identifier for the blackout rule record in the broadcast rights management system.',
    `broadcast_drm_policy_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_drm_policy. Business justification: blackout_rule has drm_policy_id → content.drm_policy (cross-domain) but no FK to broadcast.broadcast_drm_policy. The broadcast DRM policy is the technical enforcement mechanism for blackout rules (geo',
    `broadcast_rights_window_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_rights_window. Business justification: blackout_rule has rights_window_id → content.rights_window (cross-domain) but no FK to broadcast.broadcast_rights_window. A blackout rule is derived from and governed by a specific broadcast rights wi',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel or platform (linear TV, OTT, IPTV, RSN) on which this blackout rule is enforced. Links to the platform channel catalog.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the specific event (game, match, concert, PPV event) to which this blackout rule applies. Null if the rule applies to all events under a league or rights window.',
    `fixture_id` BIGINT COMMENT 'Reference to the specific event (game, match, concert, PPV event) to which this blackout rule applies. Null if the rule applies to all events under a league or rights window.',
    `media_rights_deal_id` BIGINT COMMENT 'Reference to the media rights agreement that mandates or authorizes this blackout rule. Links the rule to its contractual basis.',
    `rights_agreement_id` BIGINT COMMENT 'Reference to the media rights agreement that mandates or authorizes this blackout rule. Links the rule to its contractual basis.',
    `rights_holder_id` BIGINT COMMENT 'Foreign key linking to broadcast.rights_holder. Business justification: Blackout rules are contractual obligations mandated by rights holders to protect territorial exclusivity and ticket sales. Every blackout rule must identify which rights holder mandated the restrictio',
    `applies_to_highlights` BOOLEAN COMMENT 'Indicates whether this blackout rule also restricts distribution of highlight clips and short-form content derived from the blacked-out event.',
    `applies_to_replay` BOOLEAN COMMENT 'Indicates whether this blackout rule extends to replay, VOD (Video on Demand), and time-shifted viewing of the event content, in addition to the live broadcast.',
    `approval_date` DATE COMMENT 'The date on which this blackout rule was formally approved by the designated authority for operational enforcement.',
    `approved_by` STRING COMMENT 'Name or identifier of the individual or organizational role that formally approved this blackout rule for enforcement (e.g., VP Broadcast Rights, League Office - Media Committee).',
    `blackout_lift_condition` STRING COMMENT 'Narrative description of the condition(s) under which this blackout rule is automatically lifted or deactivated (e.g., Blackout lifted when 85% of venue capacity is sold 72 hours prior to event start).',
    `blackout_type` STRING COMMENT 'Classification of the blackout scope: local (home market territory), national (entire country), international (cross-border), rsn_exclusivity (Regional Sports Network exclusive window), ppv (Pay-Per-View event blackout), ott (Over-The-Top streaming platform blackout).. Valid values are `local|national|international|rsn_exclusivity|ppv|ott`',
    `blackout_window_hours` STRING COMMENT 'Number of hours before and/or after the event start time during which the blackout is enforced. Defines the temporal scope of the blackout window around the event.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this blackout rule record was first created in the broadcast rights management system.',
    `distribution_platform` STRING COMMENT 'The delivery platform type on which the blackout is enforced: linear_tv (traditional broadcast), ott (Over-The-Top streaming), iptv (Internet Protocol Television), rsn (Regional Sports Network), ppv (Pay-Per-View), dtc (Direct-To-Consumer), cable, satellite. [ENUM-REF-CANDIDATE: linear_tv|ott|iptv|rsn|ppv|dtc|cable|satellite — 8 candidates stripped; promote to reference product]',
    `effective_from` DATE COMMENT 'The calendar date from which this blackout rule becomes binding and enforceable, aligned with the rights agreement or league mandate start date.',
    `effective_until` DATE COMMENT 'The calendar date on which this blackout rule ceases to be enforceable. Null for open-ended rules that remain active until explicitly terminated.',
    `enforcement_mechanism` STRING COMMENT 'Technical method used to enforce the blackout rule: geo_ip_block (IP geolocation blocking), drm_token (DRM token restriction), cdn_restriction (CDN-level content blocking), access_control (platform access control list), manual (manual operator action), api_enforcement (API-level enforcement).. Valid values are `geo_ip_block|drm_token|cdn_restriction|access_control|manual|api_enforcement`',
    `geo_precision_level` STRING COMMENT 'Granularity of geographic enforcement for this blackout rule: country, state, dma (Designated Market Area), zip_code, city. Determines how precisely the blackout territory is defined and enforced.. Valid values are `country|state|dma|zip_code|city`',
    `last_reviewed_date` DATE COMMENT 'The most recent date on which this blackout rule was reviewed for accuracy, compliance alignment, and continued applicability by the rights management team.',
    `league_code` STRING COMMENT 'Standardized code identifying the sports league or governing body that mandated this blackout rule (e.g., NFL, NBA, MLB, NHL, MLS, FIFA, UFC).. Valid values are `^[A-Z]{2,10}$`',
    `mandate_source` STRING COMMENT 'The originating source of the blackout mandate: league_cba (Collective Bargaining Agreement), rights_contract (media rights deal terms), regulatory (FCC or government regulation), venue_agreement (venue exclusivity clause), network_policy (broadcaster internal policy).. Valid values are `league_cba|rights_contract|regulatory|venue_agreement|network_policy`',
    `notes` STRING COMMENT 'Free-text field for broadcast operations staff to capture additional context, exceptions, or operational instructions related to this blackout rule that are not captured in structured fields.',
    `notification_lead_hours` STRING COMMENT 'Number of hours in advance that notification must be submitted to the relevant authority before the blackout rule is activated or lifted. Applicable when notification_required is True.',
    `notification_required` BOOLEAN COMMENT 'Indicates whether advance notification to the league office, rights holder, or regulatory body is required before activating or lifting this blackout rule.',
    `override_authority` STRING COMMENT 'The organizational role or body authorized to approve an override of this blackout rule: league_office, rights_holder, network_ops (Network Operations), legal, executive. Applicable only when override_eligible is True.. Valid values are `league_office|rights_holder|network_ops|legal|executive`',
    `override_eligible` BOOLEAN COMMENT 'Indicates whether this blackout rule can be overridden under specific conditions (e.g., emergency broadcast, league waiver, special event designation). True = override is permissible with authorization.',
    `penalty_clause` STRING COMMENT 'Description of contractual or regulatory penalties applicable if this blackout rule is violated or improperly enforced, as defined in the rights agreement or league mandate.',
    `post_event_blackout_hours` STRING COMMENT 'Number of hours after event conclusion during which the blackout remains enforced. Protects replay and VOD rights windows for RSN and rights holders.',
    `pre_event_blackout_hours` STRING COMMENT 'Number of hours prior to event start time during which the blackout is enforced. Used to protect live gate attendance and RSN exclusivity windows.',
    `rsn_exclusivity` BOOLEAN COMMENT 'Indicates whether this blackout rule is driven by RSN exclusivity rights. True = an RSN holds exclusive broadcast rights in the territory, triggering the blackout on competing platforms.',
    `rsn_partner_name` STRING COMMENT 'Name of the RSN partner holding exclusive broadcast rights that trigger this blackout (e.g., Bally Sports, MSG Network, ROOT Sports). Populated when rsn_exclusivity is True.',
    `rule_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this blackout rule, used in league governance documents, RSN contracts, and broadcast operations systems.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `rule_description` STRING COMMENT 'Detailed narrative description of the blackout rule, including its business rationale, contractual basis, and operational scope.',
    `rule_name` STRING COMMENT 'Human-readable name describing the blackout rule (e.g., NFL Home Market Local Blackout, RSN Exclusivity Window - Pacific Northwest).',
    `rule_status` STRING COMMENT 'Current lifecycle state of the blackout rule: active (currently enforced), inactive (not enforced), pending (awaiting activation), suspended (temporarily halted), expired (past effective period), draft (under review).. Valid values are `active|inactive|pending|suspended|expired|draft`',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this blackout rule was sourced (e.g., DALET_GALAXY, MANUAL_ENTRY, LEAGUE_FEED). Supports data lineage in the Databricks Silver Layer.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `sport_type` STRING COMMENT 'The sport or entertainment category to which this blackout rule applies (e.g., American Football, Basketball, Baseball, Hockey, Soccer, MMA, Concert). Enables cross-sport analytics and rule management.',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code or alpha-2 code identifying the primary geographic territory to which this blackout rule applies (e.g., USA, CAN, GBR).. Valid values are `^[A-Z]{2,3}$`',
    `territory_region` STRING COMMENT 'Sub-national region, DMA (Designated Market Area), or RSN coverage zone within the territory where the blackout applies (e.g., New York DMA, Pacific Northwest RSN Zone). Complements territory_code for granular geographic enforcement.',
    `ticket_sales_threshold_pct` DECIMAL(18,2) COMMENT 'The minimum percentage of venue capacity that must be sold for the blackout to be lifted (e.g., 85.00 means 85% of tickets must be sold). Applicable when trigger_condition is ticket_sales_threshold or sellout_rule.',
    `trigger_condition` STRING COMMENT 'The business condition that activates this blackout rule: ticket_sales_threshold (blackout lifted when ticket sales meet threshold), rsn_exclusivity (RSN holds exclusive rights), league_mandate (governing body requirement), rights_agreement (contractual obligation), ppv_purchase (PPV event requiring purchase), sellout_rule (event sold out). [ENUM-REF-CANDIDATE: ticket_sales_threshold|rsn_exclusivity|league_mandate|rights_agreement|ppv_purchase|sellout_rule|capacity_threshold|broadcast_window — promote to reference product]. Valid values are `ticket_sales_threshold|rsn_exclusivity|league_mandate|rights_agreement|ppv_purchase|sellout_rule`',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent modification to this blackout rule record, supporting audit trail and change management requirements.',
    `version_number` STRING COMMENT 'Incremental version number tracking amendments and revisions to this blackout rule over its lifecycle. Supports audit trail and change management for rights compliance.',
    CONSTRAINT pk_blackout_rule PRIMARY KEY(`blackout_rule_id`)
) COMMENT 'Business rules governing broadcast blackouts by territory, event, channel, and rights agreement. Captures blackout type (local, national, international), triggering conditions (ticket sales threshold, RSN exclusivity, league mandate), effective date range, override eligibility, and enforcement mechanism. Critical for rights compliance and RSN exclusivity protection. Sourced from league governance and media rights deal terms.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`broadcast_drm_policy` (
    `broadcast_drm_policy_id` BIGINT COMMENT 'Unique surrogate identifier for a Digital Rights Management (DRM) policy record governing content protection and playback restrictions across OTT, IPTV, and DTC streaming platforms.',
    `parent_policy_broadcast_drm_policy_id` BIGINT COMMENT 'Reference to a parent DRM policy from which this policy inherits base settings. Supports hierarchical policy structures where sport-specific or event-specific policies extend a master DRM policy template.',
    `analytics_tracking_enabled` BOOLEAN COMMENT 'Indicates whether playback analytics and DRM license event tracking are enabled for content governed by this policy. Supports ARPU analysis, concurrent stream monitoring, and rights compliance reporting in Adobe Experience Platform.',
    `approved_by` STRING COMMENT 'Name or identifier of the rights management or legal authority who approved this DRM policy for production deployment. Supports governance and audit trail requirements for IP protection compliance.',
    `approved_timestamp` TIMESTAMP COMMENT 'Timestamp when this DRM policy was formally approved for production use. Distinct from created_timestamp; captures the approval lifecycle event for governance and audit purposes.',
    `blackout_rule_enabled` BOOLEAN COMMENT 'Indicates whether local or regional blackout rules are enforced under this DRM policy. Blackout rules restrict live event streaming in local broadcast markets to protect RSN and linear TV rights agreements.',
    `cdn_profile_code` STRING COMMENT 'Identifier of the CDN delivery profile associated with this DRM policy. CDN profiles define token authentication, signed URL parameters, and edge caching rules that complement DRM enforcement.',
    `compliance_standard` STRING COMMENT 'Regulatory or industry compliance standard that this DRM policy is designed to satisfy (e.g., GDPR, CCPA, PCI-DSS, FCC). Supports compliance reporting and audit trail requirements for content protection governance.',
    `concurrent_stream_limit` STRING COMMENT 'Maximum number of simultaneous active streams permitted per subscriber entitlement under this DRM policy. Enforced at the CDN and streaming platform level to prevent credential sharing and protect media rights revenue.',
    `content_tier` STRING COMMENT 'Content access tier to which this DRM policy applies, aligning with subscription or entitlement levels. VIP tiers may include exclusive live events or athlete content; PPV tiers apply to pay-per-view events such as UFC or boxing matches.. Valid values are `premium|standard|free|vip|ppv`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this DRM policy record was first created in the system. Used for audit trail, data lineage, and compliance reporting. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `device_authentication_required` BOOLEAN COMMENT 'Indicates whether device-level authentication and registration is required before DRM license issuance. When true, only registered and authenticated devices may receive license keys for protected content.',
    `download_permitted` BOOLEAN COMMENT 'Indicates whether offline download of protected content is permitted under this DRM policy. When true, download-to-own or rental download workflows are enabled subject to license expiry rules.',
    `drm_technology` STRING COMMENT 'The DRM technology stack applied to enforce content protection. Widevine is used for Android/Chrome, FairPlay for Apple devices, PlayReady for Microsoft/Smart TVs, and multi_drm indicates a combined approach for cross-platform delivery.. Valid values are `Widevine|FairPlay|PlayReady|ClearKey|Marlin|multi_drm`',
    `effective_from` DATE COMMENT 'Date from which this DRM policy becomes active and enforceable on streaming platforms. Aligns with the start of the associated media rights agreement or broadcast season.',
    `effective_until` DATE COMMENT 'Date on which this DRM policy expires and is no longer enforceable. Null for open-ended policies. Aligns with the expiry of the associated media rights agreement.',
    `encryption_standard` STRING COMMENT 'Cryptographic encryption standard applied to protected content streams. AES-128 and AES-256 are common for HLS, CENC (Common Encryption) is used for DASH multi-DRM, and CBCS is the Apple FairPlay encryption scheme.. Valid values are `AES-128|AES-256|SAMPLE-AES|CBCS|CENC`',
    `geo_blocked_territories` STRING COMMENT 'Comma-separated list of ISO 3166-1 alpha-3 country codes explicitly blocked from content playback under this DRM policy. Supports blackout rules for RSN exclusivity and international rights restrictions.',
    `geo_permitted_territories` STRING COMMENT 'Comma-separated list of ISO 3166-1 alpha-3 country codes (e.g., USA,CAN,GBR) where content playback is permitted under this DRM policy. Used to enforce broadcast rights territorial restrictions for RSN, OTT, and DTC platforms.',
    `geo_restriction_enabled` BOOLEAN COMMENT 'Indicates whether geographic access restrictions are enforced under this DRM policy. When true, content playback is limited to permitted territories defined in the geo_permitted_territories and geo_blocked_territories fields.',
    `hdcp_version_required` STRING COMMENT 'Minimum HDCP version required on the display output for content playback under this DRM policy. HDCP 2.2 or higher is typically required for 4K UHD premium sports content.. Valid values are `HDCP_1.4|HDCP_2.0|HDCP_2.2|HDCP_2.3|none`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this DRM policy record was last updated. Tracks policy changes for audit, compliance, and version control purposes. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `license_duration_hours` STRING COMMENT 'Duration in hours for which a DRM license key is valid after issuance to a device. After expiry, the device must re-request a license from the license server. Controls content access windows for rental and PPV models.',
    `license_renewal_required` BOOLEAN COMMENT 'Indicates whether the DRM license must be renewed (re-fetched from the license server) during active playback sessions. When true, the player must periodically contact the license server to maintain uninterrupted playback.',
    `license_server_url` STRING COMMENT 'HTTPS endpoint URL of the DRM license server responsible for issuing and validating license keys for content governed by this policy. Must use HTTPS. Configured per DRM technology (Widevine, FairPlay, PlayReady).. Valid values are `^https://.*`',
    `max_registered_devices` STRING COMMENT 'Maximum number of devices a subscriber may register for DRM license delivery under this policy. Limits credential sharing and protects media rights revenue across OTT and DTC platforms.',
    `offline_playback_duration_hours` STRING COMMENT 'Maximum number of hours a downloaded content item may be played back offline before the DRM license expires and re-authentication is required. Null when download is not permitted.',
    `output_protection_required` BOOLEAN COMMENT 'Indicates whether HDCP (High-bandwidth Digital Content Protection) or equivalent output protection is required on connected display outputs. Enforced for premium and PPV content to prevent unauthorized recording.',
    `platform_type` STRING COMMENT 'Delivery platform category to which this DRM policy applies. OTT (Over-The-Top), IPTV (Internet Protocol Television), DTC (Direct-To-Consumer), linear TV broadcast, mobile app, or web browser. Determines applicable DRM technology and encryption requirements.. Valid values are `OTT|IPTV|DTC|linear_tv|mobile|web`',
    `policy_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the DRM policy, used in rights agreements, vendor contracts, and system integrations with Dalet Galaxy and CDN platforms. Format: DRM- followed by 4-20 uppercase alphanumeric characters.. Valid values are `^DRM-[A-Z0-9]{4,20}$`',
    `policy_description` STRING COMMENT 'Free-text description of the DRM policys purpose, scope, and any special enforcement conditions. Used by rights management and broadcast operations teams for policy governance and documentation.',
    `policy_name` STRING COMMENT 'Human-readable name of the DRM policy used for identification in broadcast operations, rights management workflows, and reporting dashboards (e.g., NFL Sunday Ticket PPV Standard, OTT Premium Tier FairPlay).',
    `policy_status` STRING COMMENT 'Current lifecycle state of the DRM policy. Active policies are enforced on streaming platforms; deprecated policies are retained for historical audit and compliance purposes.. Valid values are `active|inactive|draft|deprecated|under_review`',
    `policy_type` STRING COMMENT 'Classification of the DRM policy by monetization model: subscription (SVOD), pay-per-view (PPV), rental (TVOD), download-to-own (EST), free ad-supported (AVOD), or preview. Drives entitlement logic and revenue reporting. [ENUM-REF-CANDIDATE: subscription|ppv|rental|download_to_own|free_ad_supported|preview — promote to reference product]. Valid values are `subscription|ppv|rental|download_to_own|free_ad_supported|preview`',
    `policy_version` STRING COMMENT 'Version number of the DRM policy definition, following semantic versioning (e.g., 1.0, 2.1.3). Enables tracking of policy changes over time and supports rollback in case of compliance issues.. Valid values are `^[0-9]+.[0-9]+(.[0-9]+)?$`',
    `resolution_restriction` STRING COMMENT 'Maximum video resolution permitted for playback under this DRM policy. Resolution restrictions may be applied based on device capability, subscription tier, or rights agreement terms (e.g., SD-only for non-authenticated devices).. Valid values are `SD|HD|FHD|4K_UHD|8K|unrestricted`',
    `rights_agreement_ref` STRING COMMENT 'External reference code or contract number of the media rights agreement that mandates this DRM policy. Links DRM enforcement requirements back to the contractual obligation with leagues (NFL, NBA, FIFA) or broadcast partners.',
    `rights_window_type` STRING COMMENT 'Type of content rights window governed by this DRM policy: live (real-time broadcast), VOD (video on demand), replay (post-event catch-up), archive (long-term library), or preview (short promotional clip). Determines applicable DRM enforcement rules.. Valid values are `live|vod|replay|archive|preview`',
    `robustness_level` STRING COMMENT 'Widevine/PlayReady robustness level required for license issuance, defining the security tier of the decryption environment. HW_SECURE_ALL requires hardware-level TEE (Trusted Execution Environment) and is mandated for 4K UHD premium sports content.. Valid values are `SW_SECURE_CRYPTO|SW_SECURE_DECODE|HW_SECURE_CRYPTO|HW_SECURE_DECODE|HW_SECURE_ALL`',
    `screen_capture_blocked` BOOLEAN COMMENT 'Indicates whether screen capture and screen recording are blocked on supported platforms under this DRM policy. Enforced via OS-level DRM APIs on Android (Widevine) and iOS (FairPlay) to prevent unauthorized content capture.',
    `token_auth_required` BOOLEAN COMMENT 'Indicates whether a signed authentication token (e.g., JWT) is required when requesting a DRM license. Token authentication prevents unauthorized license acquisition and is standard for premium and PPV content.',
    `token_expiry_seconds` STRING COMMENT 'Duration in seconds after which the authentication token used for DRM license requests expires. Short expiry windows reduce the risk of token replay attacks on premium sports content.',
    `watermark_type` STRING COMMENT 'Type of watermarking applied to protected content: forensic (invisible, embedded in bitstream for piracy tracing), visible (on-screen overlay), both, or none. Forensic watermarking is standard for live PPV and premium sports events.. Valid values are `forensic|visible|both|none`',
    `watermarking_required` BOOLEAN COMMENT 'Indicates whether forensic or visible watermarking must be applied to content streams under this DRM policy. Watermarking enables source tracing of unauthorized redistribution and piracy detection.',
    CONSTRAINT pk_broadcast_drm_policy PRIMARY KEY(`broadcast_drm_policy_id`)
) COMMENT 'Digital Rights Management policy definitions governing content protection, encryption standards, device authentication, and playback restrictions for OTT, IPTV, and DTC streaming platforms. Captures DRM technology (Widevine, FairPlay, PlayReady), content tier, geo-restriction rules, concurrent stream limits, download permissions, and watermarking requirements. Ensures IP protection and rights compliance.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`live_feed` (
    `live_feed_id` BIGINT COMMENT 'Unique surrogate identifier for each live broadcast feed record in the Sports Entertainment broadcast domain. Primary key for the live_feed data product.',
    `backup_feed_id` BIGINT COMMENT 'Reference to the designated backup or failover live feed that will be activated if this primary feed fails. Enables automated failover management and redundancy tracking in broadcast operations.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to broadcast.channel. Business justification: A live feed is distributed on a specific broadcast channel. While live_feed has boolean flags (is_ott_enabled, is_iptv_enabled, is_linear_tv_enabled), it lacks a direct FK to the channel master record',
    `broadcast_drm_policy_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_drm_policy. Business justification: live_feed has drm_policy_id → content.drm_policy (cross-domain) but no FK to the in-domain broadcast.broadcast_drm_policy. The broadcast DRM policy governs encryption, device limits, and geo-restricti',
    `production_id` BIGINT COMMENT 'Foreign key linking to broadcast.production. Business justification: A live feed is the technical output of a broadcast production. Linking live_feed to production enables crew, equipment, and production metadata to be associated with the feed. This supports post-event',
    `broadcast_rights_window_id` BIGINT COMMENT 'Reference to the media rights agreement governing distribution of this live feed across licensed territories and platforms.',
    `broadcast_schedule_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_schedule. Business justification: A live feed is produced for a specific broadcast schedule window. This FK links the operational feed record to its scheduled broadcast slot, enabling operational tracking of which feed serves which sc',
    `content_rights_window_id` BIGINT COMMENT 'Foreign key linking to content.content_rights_window. Business justification: Live feed activation for a territory/platform must be validated against the content rights window to confirm live streaming rights are active. Feed operations teams perform this rights check before en',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Live feeds incur significant costs (CDN delivery, OB unit operations, satellite uplinks) tracked against cost centers in finance. Finance requires live feed-to-cost-center linkage for production cost ',
    `asset_id` BIGINT COMMENT 'Identifier of the corresponding media asset record in the Dalet Galaxy Media Asset Management (MAM) system. Enables traceability between the operational live feed record and the media asset management workflow for ingest, archiving, and content repurposing.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the scheduled sporting or entertainment event for which this live feed is being produced and distributed.',
    `fixture_id` BIGINT COMMENT 'Reference to the scheduled sporting or entertainment event for which this live feed is being produced and distributed.',
    `media_rights_deal_id` BIGINT COMMENT 'Reference to the media rights agreement governing distribution of this live feed across licensed territories and platforms.',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to content.platform_channel. Business justification: Live feed OTT distribution requires referencing the content platform channel to configure CDN endpoints, DRM requirements, and geo-restriction rules. Feed engineers need this link to route live feeds ',
    `sla_policy_id` BIGINT COMMENT 'Foreign key linking to platform.sla_policy. Business justification: Live feeds during events are governed by SLA policies defining uptime targets, CDN failover thresholds, and latency SLAs. Operations teams reference the SLA policy to trigger failover and report SLA c',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to partner.vendor_contract. Business justification: Live feed delivery (OB units, CDN services) is governed by specific vendor contracts. Linking enables SLA breach tracking, invoice reconciliation, and vendor performance reporting against actual feed ',
    `venue_id` BIGINT COMMENT 'Reference to the source venue from which this live feed originates, used for routing and signal path management.',
    `actual_end_time` TIMESTAMP COMMENT 'Actual date and time (UTC) when this live feed concluded transmission. Used for post-event reporting, content ingest triggering, and broadcast duration billing. Null if feed is still active.',
    `actual_start_time` TIMESTAMP COMMENT 'Actual date and time (UTC) when this live feed began transmitting. Compared against scheduled_start_time to measure on-air punctuality and SLA (Service Level Agreement) compliance. Null if feed has not yet started.',
    `aspect_ratio` STRING COMMENT 'Width-to-height ratio of the video frame for this live feed. 16:9 is the standard widescreen format for HD and 4K broadcast; 4:3 is legacy SD format. Determines display compatibility across linear TV and OTT (Over-The-Top) platforms.. Valid values are `16:9|4:3|21:9|1:1`',
    `audio_format` STRING COMMENT 'Audio channel configuration and encoding format for the primary audio track of the live feed. Dolby Atmos and 7.1 surround are premium formats for high-end broadcast and streaming platforms.. Valid values are `stereo|5.1_surround|7.1_surround|mono|dolby_atmos`',
    `audio_track_count` STRING COMMENT 'Total number of discrete audio tracks embedded in the live feed. Multiple tracks support stereo, 5.1 surround, and separate commentary language channels. Relevant for multi-language broadcast distribution and accessibility compliance.',
    `bitrate_kbps` STRING COMMENT 'Target encoding bitrate of the live feed in kilobits per second (Kbps). Determines bandwidth consumption, CDN (Content Delivery Network) capacity requirements, and viewer quality of experience. Typical values range from 1,500 Kbps (SD) to 50,000+ Kbps (4K HDR).',
    `blackout_rule_applied` BOOLEAN COMMENT 'Indicates whether a territorial blackout restriction is currently applied to this live feed, preventing distribution in specific geographic markets per media rights agreements. Critical for rights compliance and RSN (Regional Sports Network) exclusivity enforcement.',
    `blackout_territory` STRING COMMENT 'Comma-separated list of ISO 3166-1 alpha-3 country codes or designated market area codes where this live feed is blacked out per media rights agreements. Null if no blackout applies. Used for geo-fencing enforcement on DTC (Direct-To-Consumer) and OTT (Over-The-Top) platforms.. Valid values are `^[A-Z]{3}(,[A-Z]{3})*$`',
    `cdn_origin_endpoint` STRING COMMENT 'Primary CDN (Content Delivery Network) origin ingest URL or endpoint address from which the live feed is distributed to downstream delivery nodes and OTT (Over-The-Top) platforms. Core operational field for live distribution monitoring.',
    `commentary_language` STRING COMMENT 'ISO 639-1 or ISO 639-2 language code for the primary commentary audio track on this live feed (e.g., en for English, es for Spanish, fr for French). Drives regional distribution routing and RSN (Regional Sports Network) assignment.. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when this live feed record was first created in the system, typically during pre-event broadcast planning. Supports audit trail, data lineage, and Silver Layer ingestion tracking.',
    `distribution_tier` STRING COMMENT 'Geographic scope of distribution authorized for this live feed under the applicable media rights agreement. Global feeds are distributed worldwide; regional feeds are limited to a geographic zone; national feeds are country-specific; local feeds are limited to a designated market area (DMA).. Valid values are `global|regional|national|local`',
    `encoding_format` STRING COMMENT 'Video codec standard used to compress and encode the live feed signal. H.264 (AVC) and H.265 (HEVC) are the dominant standards for broadcast and OTT (Over-The-Top) streaming delivery. Impacts bandwidth, quality, and platform compatibility.. Valid values are `H.264|H.265|AV1|MPEG-2|JPEG2000|ProRes`',
    `failover_activated` BOOLEAN COMMENT 'Indicates whether the backup or redundancy failover mechanism was triggered during this live feeds transmission. Used for post-event incident analysis, SLA (Service Level Agreement) reporting, and broadcast reliability KPI (Key Performance Indicator) tracking.',
    `failover_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when the failover mechanism was activated for this live feed. Null if failover_activated is false. Used for incident root cause analysis and SLA (Service Level Agreement) breach assessment.',
    `feed_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this live feed within broadcast operations and Dalet Galaxy media asset management workflows. Used for signal routing, scheduling, and inter-system reference.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `feed_name` STRING COMMENT 'Human-readable descriptive name for the live feed, typically including event name, feed type, and language (e.g., NFL Championship - World Feed - English). Used in operational dashboards and scheduling systems.',
    `feed_status` STRING COMMENT 'Current operational lifecycle status of the live feed. Active indicates the feed is live and distributing; standby is ready but not transmitting; failed indicates a signal loss or error condition; backup indicates a redundancy feed has taken over; scheduled indicates pre-event readiness; terminated indicates the feed has ended.. Valid values are `active|standby|failed|backup|scheduled|terminated`',
    `feed_type` STRING COMMENT 'Classification of the live feed by its production and distribution purpose. World feed is the primary international signal; clean feed has no graphics; ISO feed is an isolated camera angle; PPV (Pay-Per-View) and OTT (Over-The-Top) feeds are platform-specific variants. [ENUM-REF-CANDIDATE: world_feed|clean_feed|commentary_feed|iso_feed|backup_feed|ppv_feed|ott_feed — promote to reference product]',
    `frame_rate` DECIMAL(18,2) COMMENT 'Number of video frames per second (fps) for this live feed. Common values include 25, 29.97, 50, 59.94, and 60 fps. Affects motion smoothness, storage requirements, and compatibility with broadcast standards across regions (PAL vs NTSC).',
    `hdr_format` STRING COMMENT 'High Dynamic Range (HDR) format applied to the live feed for enhanced color and brightness reproduction. HDR10 and HLG (Hybrid Log-Gamma) are the broadcast standards; Dolby Vision is a premium streaming format. None indicates standard dynamic range (SDR).. Valid values are `none|HDR10|HDR10+|HLG|Dolby_Vision`',
    `is_iptv_enabled` BOOLEAN COMMENT 'Indicates whether this live feed is authorized and configured for distribution via IPTV (Internet Protocol Television) networks, including managed IPTV services provided by telecommunications operators.',
    `is_linear_tv_enabled` BOOLEAN COMMENT 'Indicates whether this live feed is authorized and configured for distribution via traditional linear television broadcast channels, including RSN (Regional Sports Network) and national broadcast network affiliates.',
    `is_ott_enabled` BOOLEAN COMMENT 'Indicates whether this live feed is authorized and technically configured for distribution via OTT (Over-The-Top) streaming platforms, including DTC (Direct-To-Consumer) services and third-party streaming partners.',
    `is_ppv` BOOLEAN COMMENT 'Indicates whether this live feed is designated as a PPV (Pay-Per-View) event feed, requiring consumer purchase or entitlement before access is granted. Drives entitlement checks on DTC (Direct-To-Consumer) and OTT (Over-The-Top) platforms.',
    `latency_mode` STRING COMMENT 'Configured latency mode for this live feed delivery. Ultra-low latency (sub-3 seconds) is required for interactive and betting-adjacent use cases; low latency (3-10 seconds) for OTT (Over-The-Top) sports streaming; standard (10-30 seconds) for traditional broadcast; high for archive-quality delivery.. Valid values are `ultra_low|low|standard|high`',
    `ob_unit_code` STRING COMMENT 'Identifier of the Outside Broadcast (OB) truck or mobile production unit assigned to capture and produce this live feed at the source venue. Critical for resource scheduling and operational accountability.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `production_region` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the primary production region where this live feed is originated and managed. Used for regulatory compliance, rights territory management, and broadcast operations routing.. Valid values are `^[A-Z]{3}$`',
    `redundancy_config` STRING COMMENT 'Redundancy architecture configured for this live feed to ensure continuity in case of primary signal failure. 1+1 means one active and one standby path; N+1 means N active feeds with one shared backup. Critical for broadcast SLA (Service Level Agreement) compliance.. Valid values are `none|1+1|2+1|n+1|full_mesh`',
    `replay_enabled` BOOLEAN COMMENT 'Indicates whether this live feed is authorized and configured to generate replay or catch-up content after the live event concludes. Drives post-event content ingest workflows in Dalet Galaxy and DRM (Digital Rights Management) policy application for replay windows.',
    `replay_window_hours` STRING COMMENT 'Number of hours after the live event ends during which replay content derived from this feed is available to authorized viewers. Defined by the media rights agreement and DRM (Digital Rights Management) policy. Null if replay_enabled is false.',
    `resolution` STRING COMMENT 'Video resolution tier of the live feed. SD (Standard Definition) is 480p/576p; HD (High Definition) is 720p; FHD (Full HD) is 1080p/1080i; 4K is 2160p; 8K is 4320p. Determines bandwidth requirements, CDN (Content Delivery Network) capacity planning, and platform delivery eligibility.. Valid values are `SD|HD|FHD|4K|8K`',
    `scheduled_start_time` TIMESTAMP COMMENT 'Planned date and time (UTC) when this live feed is scheduled to begin transmission. Used for broadcast scheduling, CDN (Content Delivery Network) pre-warming, and OB (Outside Broadcast) unit coordination.',
    `signal_type` STRING COMMENT 'Physical or logical transport medium used to carry the live feed signal from the source venue to the broadcast facility or CDN (Content Delivery Network) origin. Determines redundancy planning and SLA (Service Level Agreement) requirements.. Valid values are `satellite|fiber|ip|microwave|bonded_cellular`',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when this live feed record was most recently modified. Tracks operational changes such as status transitions, failover events, and configuration updates throughout the feed lifecycle.',
    CONSTRAINT pk_live_feed PRIMARY KEY(`live_feed_id`)
) COMMENT 'Operational record of each live broadcast feed produced and distributed for a scheduled event. Captures source venue, OB (Outside Broadcast) unit assignment, signal type (satellite, fiber, IP), encoding format (H.264/H.265), resolution (SD/HD/4K/8K), audio tracks, commentary language, feed status (active, standby, failed, backup), CDN origin endpoint, and redundancy configuration. Core operational entity for live broadcast production, distribution monitoring, and failover management.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`ppv_package` (
    `ppv_package_id` BIGINT COMMENT 'Unique surrogate identifier for a PPV package record in the broadcast domain. Serves as the primary key for the ppv_package data product.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to broadcast.channel. Business justification: A PPV package is distributed on a specific broadcast channel. ppv_package has platform_availability (STRING) but no FK to the channel master record. This FK enables channel-level PPV inventory managem',
    `broadcast_drm_policy_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_drm_policy. Business justification: A PPV package requires broadcast-specific DRM protection governing stream encryption, device limits, and geo-restrictions. ppv_package has drm_policy_id → content.drm_policy (cross-domain) but no FK t',
    `broadcast_rights_window_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_rights_window. Business justification: A PPV package is governed by a specific broadcast rights window defining the permitted distribution territory, platform, and time period. This FK links the PPV package to its authoritative rights wind',
    `broadcast_schedule_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_schedule. Business justification: A PPV package is associated with a specific broadcast schedule window. This FK links the PPV package to the scheduled broadcast event, enabling schedule-driven PPV availability management and ensuring',
    `digital_touchpoint_id` BIGINT COMMENT 'Foreign key linking to platform.digital_touchpoint. Business justification: PPV packages are made available on specific digital touchpoints. The plain platform_availability text field is a denormalized reference. Linking to digital_touchpoint enables proper entitlement enforc',
    `event_fixture_id` BIGINT COMMENT 'Reference to the live event or fixture that this PPV package is associated with, linking the commercial package to the underlying sporting or entertainment event.',
    `fixture_id` BIGINT COMMENT 'Reference to the live event or fixture that this PPV package is associated with, linking the commercial package to the underlying sporting or entertainment event.',
    `loyalty_program_id` BIGINT COMMENT 'Foreign key linking to fan.loyalty_program. Business justification: PPV packages must specify which loyalty programs can be used for points redemption or earning. loyalty_program has ppv_earning_enabled flag; this FK on ppv_package enables loyalty-PPV redemption confi',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: A PPV package is governed by a media rights deal defining the rights to package and sell the event. ppv_package has rights_agreement_ref (STRING) which is a denormalized reference to the deal. Replaci',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: PPV packages are a distinct revenue stream category tracked separately in finance for ARR reporting, revenue mix analysis, and P&L. Finance maps each PPV package to its revenue stream for period reven',
    `syndication_deal_id` BIGINT COMMENT 'Reference to the syndication deal governing third-party distribution of this PPV package to external broadcast partners, RSN affiliates, or OTT sub-licensees.',
    `approved_by` STRING COMMENT 'Name or identifier of the business approver (e.g., Broadcast Operations Director) who authorized this PPV package for commercial release. Supports SOX financial controls and internal governance workflows.',
    `approved_date` DATE COMMENT 'Calendar date on which this PPV package received formal business approval for commercial distribution. Required for SOX financial controls and internal audit trails.',
    `blackout_rule_code` STRING COMMENT 'Identifier for the geographic blackout rule set applied to this PPV package, restricting access in specific markets per RSN territorial rights agreements or league governance mandates (e.g., NFL, NBA blackout policies).',
    `broadcast_language_code` STRING COMMENT 'ISO 639 language code for the primary audio commentary track included in this PPV package (e.g., en for English, es for Spanish). Relevant for multi-language broadcast rights and international distribution.. Valid values are `^[a-z]{2,3}$`',
    `bundle_description` STRING COMMENT 'Narrative description of the bundling options available with this PPV package, including any companion products, subscription tiers, or merchandise inclusions offered at point of sale.',
    `bundle_flag` BOOLEAN COMMENT 'Indicates whether this PPV package is offered as part of a bundled product (e.g., combined with a streaming subscription or merchandise package). True when bundling options are active for this package.',
    `cdn_profile_code` STRING COMMENT 'Identifier for the CDN delivery profile assigned to this PPV package, specifying origin server configuration, edge caching rules, and streaming quality tiers used during live and replay distribution.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `consumer_price` DECIMAL(18,2) COMMENT 'Standard retail price charged to end consumers (fans) for purchasing this PPV package on DTC and OTT platforms. Expressed in the currency defined by currency_code.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this PPV package record was first created in the system, capturing the initial configuration date for audit trail and data lineage purposes.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code in which all price fields (consumer, wholesale, international) for this package are denominated (e.g., USD, GBP, EUR).. Valid values are `^[A-Z]{3}$`',
    `distribution_window_end` TIMESTAMP COMMENT 'Date and time when consumer access to the PPV package expires. After this timestamp, purchased access tokens are invalidated and replay content is no longer served.',
    `distribution_window_start` TIMESTAMP COMMENT 'Date and time when the PPV package becomes available for consumer access and streaming. Defines the opening of the distribution window aligned with the live broadcast schedule.',
    `international_price` DECIMAL(18,2) COMMENT 'Price applicable to consumers purchasing the PPV package in international markets outside the primary domestic territory. Reflects regional pricing strategy and currency parity adjustments.',
    `is_ppv_exclusive` BOOLEAN COMMENT 'Indicates whether this event is exclusively available as a PPV purchase and is not broadcast on any free-to-air, subscription, or RSN channel. True signals exclusive PPV-only distribution.',
    `league_or_org_code` STRING COMMENT 'Short code identifying the league or organizing body whose event is featured in this PPV package (e.g., NFL, NBA, UFC, FIFA, MLB). Used for rights attribution, governance compliance, and revenue allocation.. Valid values are `^[A-Z0-9]{2,10}$`',
    `max_concurrent_streams` STRING COMMENT 'Maximum number of simultaneous streams permitted per purchased access token for this PPV package. Enforced by the DRM and streaming platform to prevent credential sharing.',
    `max_purchase_capacity` STRING COMMENT 'Maximum number of individual purchases permitted for this PPV package across all platforms. Null indicates unlimited capacity. Used for capacity-constrained PPV events or exclusive access packages.',
    `package_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the PPV package used in commercial communications, billing systems, and distribution partner integrations. Follows the format PPV-[ALPHANUMERIC].. Valid values are `^PPV-[A-Z0-9]{4,20}$`',
    `package_description` STRING COMMENT 'Long-form marketing and operational description of the PPV package content, including featured bouts, performers, pre-show details, and any exclusive content inclusions. Used in consumer-facing storefronts and internal catalog management.',
    `package_name` STRING COMMENT 'Human-readable commercial title of the PPV package as displayed to consumers on OTT platforms, linear TV guides, and DTC storefronts (e.g., UFC 300 Championship Night).',
    `package_status` STRING COMMENT 'Current lifecycle state of the PPV package governing whether it is available for purchase. Draft indicates pre-release configuration; active indicates live and purchasable; on_sale indicates promotional pricing active; sold_out indicates capacity reached; expired indicates distribution window closed; cancelled indicates package withdrawn.. Valid values are `draft|active|on_sale|sold_out|expired|cancelled`',
    `package_type` STRING COMMENT 'Classification of the PPV package by content scope. Single_event covers one live broadcast; multi_event_bundle covers a curated set of events; season_pass covers all events in a league season; replay_only covers post-event on-demand access without live rights.. Valid values are `single_event|multi_event_bundle|season_pass|replay_only`',
    `platform_availability` STRING COMMENT 'Comma-separated list of distribution platforms on which this PPV package is available (e.g., OTT app, IPTV, linear TV, DTC web, mobile). Drives platform-specific fulfillment routing. [ENUM-REF-CANDIDATE: ott|iptv|linear_tv|dtc_web|mobile_app|cable|satellite — promote to reference product]',
    `ppv_category` STRING COMMENT 'Content category classification of the PPV package used for catalog organization, rights management, and audience targeting. Drives platform merchandising and recommendation algorithms.. Valid values are `sports_live|sports_replay|concert|esports|special_event`',
    `promotional_discount_pct` DECIMAL(18,2) COMMENT 'Percentage discount applied to the consumer price during promotional campaigns (e.g., early-bird pricing, loyalty member discounts). Zero indicates no active promotion. Used in revenue reporting and campaign analytics.',
    `purchase_eligibility_rule` STRING COMMENT 'Business rule expression or rule code defining which consumer segments are eligible to purchase this PPV package (e.g., subscribers only, age-verified users, specific membership tiers, geographic restrictions).',
    `replay_access_hours` STRING COMMENT 'Number of hours after the live event broadcast ends during which purchasers retain on-demand replay access to the PPV content. Zero indicates live-only access with no replay entitlement.',
    `revenue_share_pct` DECIMAL(18,2) COMMENT 'Percentage of gross PPV revenue allocated to distribution partners under the revenue share terms of the broadcast rights agreement. Critical for partner settlement and financial reporting.',
    `rights_territory_code` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code identifying the primary territory in which this PPV package holds broadcast rights. Governs geographic access controls and blackout enforcement.. Valid values are `^[A-Z]{3}$`',
    `sale_end_date` DATE COMMENT 'Calendar date after which the PPV package can no longer be purchased. Typically aligned with the distribution window end or a defined post-event replay cutoff.',
    `sale_start_date` DATE COMMENT 'Calendar date on which the PPV package becomes available for purchase by consumers and distribution partners. Enables pre-sale revenue capture ahead of the live event.',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this PPV package record originated (e.g., Dalet Galaxy for media asset workflow, SAP S/4HANA SD for commercial packaging, Ticketmaster for access control integration). Supports data lineage in the Silver layer.. Valid values are `dalet_galaxy|sap_sd|ticketmaster|adobe_exp|manual`',
    `sport_or_genre` STRING COMMENT 'Sport or entertainment genre associated with this PPV package (e.g., Boxing, MMA/UFC, NFL Football, NBA Basketball, Concert). Used for audience segmentation, rights categorization, and analytics reporting. [ENUM-REF-CANDIDATE: boxing|mma|nfl_football|nba_basketball|mlb_baseball|nhl_hockey|mls_soccer|concert|esports|other — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this PPV package record, supporting change tracking, audit compliance, and incremental data pipeline processing in the Databricks Silver layer.',
    `video_resolution` STRING COMMENT 'Maximum video resolution tier available for this PPV package. Drives CDN bandwidth provisioning, platform compatibility checks, and consumer-facing product descriptions.. Valid values are `SD|HD|FHD|4K|8K`',
    `wholesale_price` DECIMAL(18,2) COMMENT 'Price charged to distribution partners (cable operators, RSN affiliates, IPTV providers) for carrying the PPV package. Typically lower than consumer price to accommodate partner margin.',
    CONSTRAINT pk_ppv_package PRIMARY KEY(`ppv_package_id`)
) COMMENT 'Master catalog of Pay-Per-View event packages and transactional record of PPV purchases. Captures PPV event name, associated event, pricing tiers (consumer, wholesale, international), distribution window, platform availability, bundling options, revenue share terms, and purchase eligibility rules. For transactions: buyer reference, purchase timestamp, platform, payment method, price, currency, promotional discount, access token, and fulfillment status. SSOT for PPV product definitions, commercial packaging, and purchase revenue. Integrates with PCI-DSS compliant payment processing.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`ppv_transaction` (
    `ppv_transaction_id` BIGINT COMMENT 'Unique surrogate identifier for each individual PPV purchase transaction record in the Silver layer lakehouse. Serves as the primary key for all downstream joins and lineage tracking.',
    `access_entitlement_id` BIGINT COMMENT 'Foreign key linking to ticketing.access_entitlement. Business justification: Dual-entitlement reconciliation for PPV events: a PPV purchase creates both an access_entitlement (venue/digital gate access in ticketing) and a ppv_transaction (streaming rights in broadcast). Linkin',
    `ar_invoice_id` BIGINT COMMENT 'Foreign key linking to finance.ar_invoice. Business justification: B2B wholesale PPV transactions (cable operators, distributors) generate AR invoices in finance for receivables management and revenue reconciliation. Finance needs the AR invoice linkage to track coll',
    `broadcast_drm_policy_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_drm_policy. Business justification: A PPV transaction grants access governed by a broadcast DRM policy. ppv_transaction has drm_policy_id → content.drm_policy (cross-domain) but no FK to broadcast.broadcast_drm_policy. This in-domain FK',
    `broadcast_schedule_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_schedule. Business justification: A PPV transaction purchases access to a specific broadcast event. Linking ppv_transaction to broadcast_schedule enables schedule-level PPV revenue reporting, capacity management, and broadcast window ',
    `buyer_fan_profile_id` BIGINT COMMENT 'Reference to the consumer or wholesale distributor who purchased the PPV package. Links to the fan or partner account record in the CRM or fan engagement platform.',
    `data_processing_record_id` BIGINT COMMENT 'Foreign key linking to compliance.data_processing_record. Business justification: PPV transactions process sensitive personal data (payment info, geo-location, device registration, IP address) under PCI-DSS and GDPR, requiring formal data processing records. The ppv_transaction has',
    `device_registration_id` BIGINT COMMENT 'The unique identifier of the device on which the PPV purchase was initiated or the content is authorized to stream. Used for device-binding DRM enforcement, fraud detection, and concurrent stream limiting.',
    `digital_touchpoint_id` BIGINT COMMENT 'Foreign key linking to platform.digital_touchpoint. Business justification: PPV purchases occur on specific digital touchpoints. Linking enables touchpoint-level PPV conversion rate analysis, platform revenue attribution, and purchase funnel optimization — essential for DTC r',
    `distributor_id` BIGINT COMMENT 'Reference to the wholesale distributor (e.g., cable operator, IPTV provider, RSN affiliate) through which this PPV transaction was processed, if applicable. Null for direct-to-consumer purchases. Used for wholesale revenue allocation and partner reporting.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the live sports or entertainment event that this PPV transaction grants access to. Used to correlate revenue with specific events for financial reporting.',
    `payment_method_id` BIGINT COMMENT 'Foreign key linking to fan.payment_method. Business justification: PPV transactions require a reference to the fans stored payment method for refund processing, fraud analysis, and PCI compliance. ppv_transaction has payment_method (text, denormalized type only) and',
    `fan_profile_id` BIGINT COMMENT 'Reference to the consumer or wholesale distributor who purchased the PPV package. Links to the fan or partner account record in the CRM or fan engagement platform.',
    `fixture_id` BIGINT COMMENT 'Reference to the live sports or entertainment event that this PPV transaction grants access to. Used to correlate revenue with specific events for financial reporting.',
    `media_rights_deal_id` BIGINT COMMENT 'Reference to the media rights agreement under which this PPV transaction is authorized. Links to the broadcast rights contract governing the event, territory, and platform. Used for rights compliance and royalty calculation.',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to merchandise.promotion. Business justification: Cross-domain promotional redemption: a PPV transaction may redeem a merchandise promotion (e.g., promo code entitles buyer to a merch discount). Linking ppv_transaction to the merchandise promotion en',
    `payment_id` BIGINT COMMENT 'The unique transaction identifier returned by the external PCI-DSS compliant payment gateway or processor for this PPV purchase. Used for payment reconciliation, chargeback management, and audit trails. Not the card number or sensitive cardholder data.',
    `payment_transaction_payment_id` BIGINT COMMENT 'The unique transaction identifier returned by the external PCI-DSS compliant payment gateway or processor for this PPV purchase. Used for payment reconciliation, chargeback management, and audit trails. Not the card number or sensitive cardholder data.',
    `ppv_package_id` BIGINT COMMENT 'Reference to the specific PPV content package being purchased, such as a championship fight, playoff game, or special event broadcast. Links to the PPV package catalog.',
    `rights_agreement_id` BIGINT COMMENT 'Reference to the media rights agreement under which this PPV transaction is authorized. Links to the broadcast rights contract governing the event, territory, and platform. Used for rights compliance and royalty calculation.',
    `tax_jurisdiction_id` BIGINT COMMENT 'Foreign key linking to finance.tax_jurisdiction. Business justification: PPV transactions are subject to entertainment tax, digital services tax, and state/local taxes based on buyer location. Finance requires tax_jurisdiction linkage per transaction for tax calculation, r',
    `ticket_order_id` BIGINT COMMENT 'Foreign key linking to ticketing.ticket_order. Business justification: PPV revenue reconciliation: when a fan purchases a PPV event, both a ticket_order (ticketing system) and ppv_transaction (broadcast system) are created. Linking them enables cross-system revenue recon',
    `vendor_id` BIGINT COMMENT 'Reference to the wholesale distributor (e.g., cable operator, IPTV provider, RSN affiliate) through which this PPV transaction was processed, if applicable. Null for direct-to-consumer purchases. Used for wholesale revenue allocation and partner reporting.',
    `access_token` STRING COMMENT 'The unique cryptographic token issued to the buyer upon successful payment, granting authenticated access to the PPV content stream. Tied to DRM policy enforcement and device binding. Must be treated as confidential and not exposed in public-facing reports.',
    `access_token_expiry` TIMESTAMP COMMENT 'The date and time at which the PPV content access token expires and the buyers viewing rights are revoked. Enforces time-limited access windows per the PPV package terms and DRM policy.',
    `access_window_hours` STRING COMMENT 'The number of hours the buyer is entitled to access the PPV content from the time of first playback or purchase, as defined by the PPV package terms. Supports replay and catch-up viewing rights management.',
    `arpu_segment` STRING COMMENT 'The ARPU-based segmentation tier assigned to the buyer at the time of this transaction, derived from historical spend patterns. Used for targeted marketing, pricing strategy, and LTV (Lifetime Value) analytics. Not a calculated metric — this is a pre-assigned segment label from the CRM.. Valid values are `low|mid|high|premium`',
    `blackout_applied` BOOLEAN COMMENT 'Indicates whether a broadcast blackout restriction was applied to this transaction based on the buyers geographic location and the applicable media rights agreement. True if the buyers region is subject to a blackout for this event.',
    `buyer_type` STRING COMMENT 'Classification of the purchasing party indicating whether the buyer is an individual consumer (Direct-To-Consumer / DTC), a wholesale distributor (e.g., cable operator, IPTV provider), a corporate account, or a reseller. Drives revenue reporting segmentation and rights management.. Valid values are `consumer|wholesale_distributor|corporate|reseller`',
    `cdn_provider` STRING COMMENT 'The name or identifier of the Content Delivery Network (CDN) provider used to deliver the PPV stream to the buyer. Used for CDN cost allocation, SLA monitoring, and quality-of-service reporting.',
    `concurrent_stream_limit` STRING COMMENT 'The maximum number of simultaneous streams permitted under this PPV transaction as defined by the DRM policy and package terms. Enforced at the CDN and access control layer to prevent unauthorized sharing.',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this PPV transaction record was first created in the data platform. Used for data lineage, SLA monitoring, and audit trail compliance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code representing the currency in which the PPV transaction was denominated (e.g., USD, GBP, EUR). Required for multi-currency revenue reporting across global markets.. Valid values are `^[A-Z]{3}$`',
    `device_code` STRING COMMENT 'The unique identifier of the device on which the PPV purchase was initiated or the content is authorized to stream. Used for device-binding DRM enforcement, fraud detection, and concurrent stream limiting.',
    `discount_amount` DECIMAL(18,2) COMMENT 'The monetary value of any promotional discount, coupon, or loyalty reward applied to this PPV transaction. Subtracted from gross_amount to derive net_amount. Zero if no promotion was applied.',
    `fulfillment_status` STRING COMMENT 'Current lifecycle state of the PPV transaction indicating whether the purchase has been processed, content access has been granted, or the transaction has been reversed. Drives operational workflows and revenue recognition. [ENUM-REF-CANDIDATE: pending|fulfilled|failed|refunded|cancelled|expired — promote to reference product]. Valid values are `pending|fulfilled|failed|refunded|cancelled|expired`',
    `gdpr_consent_flag` BOOLEAN COMMENT 'Indicates whether the buyer has provided explicit consent for personal data processing in accordance with GDPR requirements at the time of this PPV transaction. Mandatory for transactions involving EU-resident buyers.',
    `geo_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the buyers geographic location at the time of purchase, derived from IP geolocation or account registration. Used to enforce broadcast blackout rules, regional rights restrictions, and tax jurisdiction determination.. Valid values are `^[A-Z]{3}$`',
    `gross_amount` DECIMAL(18,2) COMMENT 'The full list price of the PPV package before any promotional discounts or adjustments are applied. Expressed in the transaction currency. Used as the base for revenue reporting and discount analysis.',
    `ip_address` STRING COMMENT 'The IP address of the buyers device at the time of the PPV purchase. Used for geographic blackout rule enforcement, fraud detection, and regulatory compliance with broadcast rights restrictions.',
    `is_replay_purchase` BOOLEAN COMMENT 'Indicates whether this PPV transaction is for replay or on-demand catch-up access to a previously broadcast event, as opposed to a live event purchase. Replay transactions may have different pricing and rights windows.',
    `net_amount` DECIMAL(18,2) COMMENT 'The final amount charged to the buyer after all promotional discounts have been applied (gross_amount minus discount_amount). This is the recognized revenue amount for this transaction.',
    `payment_method` STRING COMMENT 'The payment instrument used by the buyer to complete the PPV purchase (e.g., credit card, debit card, digital wallet such as PayPal or Apple Pay, direct carrier billing, voucher/gift card, bank transfer). Used for payment reconciliation and fraud analysis. [ENUM-REF-CANDIDATE: credit_card|debit_card|digital_wallet|direct_billing|voucher|bank_transfer|crypto — promote to reference product]. Valid values are `credit_card|debit_card|digital_wallet|direct_billing|voucher|bank_transfer`',
    `payment_status` STRING COMMENT 'The current status of the payment associated with this PPV transaction as reported by the payment gateway. Distinct from fulfillment_status which tracks content delivery. Used for financial reconciliation and dispute management.. Valid values are `authorized|captured|declined|refunded|chargeback`',
    `pci_tokenized_flag` BOOLEAN COMMENT 'Indicates whether the payment card data for this transaction has been tokenized by the PCI-DSS compliant payment processor, confirming that no raw cardholder data is stored in this record. Required for PCI DSS compliance attestation.',
    `platform_type` STRING COMMENT 'The delivery platform or channel through which the PPV content was purchased and distributed. Values include Over-The-Top (OTT) streaming, Internet Protocol Television (IPTV), cable, satellite, Direct-To-Consumer (DTC) app, or Regional Sports Network (RSN). Critical for platform-level revenue analytics. [ENUM-REF-CANDIDATE: OTT|IPTV|cable|satellite|DTC_app|RSN|linear_tv — promote to reference product]. Valid values are `OTT|IPTV|cable|satellite|DTC_app|RSN`',
    `promo_code` STRING COMMENT 'The alphanumeric promotional or discount code entered by the buyer at the time of purchase, if applicable. Used to track campaign effectiveness, redemption rates, and discount attribution in marketing analytics.',
    `purchase_channel` STRING COMMENT 'The interface or touchpoint through which the buyer completed the PPV purchase (e.g., web browser, mobile app, set-top box UI, call center agent, retail kiosk). Distinct from platform_type which describes the delivery medium. Used for conversion funnel and channel attribution analytics.. Valid values are `web|mobile_app|set_top_box|call_center|retail_kiosk`',
    `purchase_timestamp` TIMESTAMP COMMENT 'The exact date and time (with timezone offset) at which the consumer or distributor completed the PPV purchase transaction. This is the principal business event time used for revenue recognition and reporting. Conforms to ISO 8601 format yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `refund_reason` STRING COMMENT 'The business reason code for the refund issued on this PPV transaction. Used for root cause analysis, fraud detection, and consumer experience improvement. Null if no refund was issued.. Valid values are `technical_failure|duplicate_purchase|consumer_request|event_cancelled|fraud|other`',
    `refund_timestamp` TIMESTAMP COMMENT 'The date and time at which a refund was processed for this PPV transaction, if applicable. Null if no refund has been issued. Used for financial reconciliation and consumer protection compliance.',
    `rights_territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country or territory code identifying the licensed broadcast rights territory under which this PPV transaction was authorized. Determines which media rights agreement governs the sale.. Valid values are `^[A-Z]{3}$`',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this PPV transaction originated (e.g., Ticketmaster, AXS, OTT platform, IPTV gateway, cable operator system, DTC app). Used for data lineage, reconciliation, and system-of-record auditing in the Silver layer.. Valid values are `TICKETMASTER|AXS|OTT_PLATFORM|IPTV_GATEWAY|CABLE_OPERATOR|DTC_APP`',
    `stream_quality` STRING COMMENT 'The video quality tier selected or delivered for this PPV transaction (Standard Definition, High Definition, 4K Ultra HD, or 8K). Affects pricing tiers, CDN bandwidth costs, and consumer experience reporting.. Valid values are `SD|HD|4K|8K`',
    `tax_amount` DECIMAL(18,2) COMMENT 'The tax amount levied on this PPV transaction, calculated based on applicable jurisdiction tax rules. Included in the total charged to the buyer and reported separately for tax compliance.',
    `transaction_reference_number` STRING COMMENT 'Externally visible alphanumeric reference number assigned to this PPV purchase, used in consumer receipts, customer service lookups, and payment reconciliation. Sourced from the payment processing or ticketing platform.. Valid values are `^PPV-[A-Z0-9]{10,20}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording the most recent modification to this PPV transaction record, such as status updates, refund processing, or access token revocation.',
    CONSTRAINT pk_ppv_transaction PRIMARY KEY(`ppv_transaction_id`)
) COMMENT 'Transactional record of individual PPV purchases by consumers or wholesale distributors. Captures buyer reference, PPV package, purchase timestamp, platform (OTT, IPTV, cable), payment method, purchase price, currency, promotional discount applied, access token issued, and fulfillment status. Core revenue transaction for PPV monetization. Integrates with PCI-DSS compliant payment processing.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`streaming_subscription` (
    `streaming_subscription_id` BIGINT COMMENT 'Unique surrogate identifier for each streaming subscription record. Primary key for the streaming_subscription data product within the broadcast domain.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to broadcast.channel. Business justification: A streaming subscription grants access to a specific broadcast channel or service. streaming_subscription has platform and service_type (STRING) but no FK to the channel master record. This FK enables',
    `broadcast_drm_policy_id` BIGINT COMMENT 'Reference to the DRM (Digital Rights Management) policy profile assigned to this subscription tier. Governs content protection, concurrent stream limits, download rights, and device binding rules enforced by the CDN (Content Delivery Network) and streaming platform.',
    `data_processing_record_id` BIGINT COMMENT 'Foreign key linking to compliance.data_processing_record. Business justification: Streaming subscriptions process fan personal data (viewing behavior, payment info, device data, geo-location) under GDPR/CCPA, requiring documented data processing records. The streaming_subscription ',
    `device_registration_id` BIGINT COMMENT 'Anonymized or hashed identifier of the primary device registered to this subscription. Used for device-binding enforcement under DRM policies and concurrent stream management. May be considered PII in certain jurisdictions.',
    `digital_subscription_id` BIGINT COMMENT 'Reference to the subscription plan/tier definition record that governs the entitlements, pricing, and features associated with this subscription.',
    `digital_touchpoint_id` BIGINT COMMENT 'Foreign key linking to platform.digital_touchpoint. Business justification: Streaming subscriptions are activated on specific digital touchpoints (mobile app, web, smart TV). The plain platform column is a denormalized touchpoint reference. Linking to digital_touchpoint ena',
    `distributor_id` BIGINT COMMENT 'Foreign key linking to broadcast.distributor. Business justification: Streaming subscriptions may be sold through distributors (e.g., bundled with cable packages, sold through OTT aggregators). Adding distributor_id enables tracking which distributor facilitated each su',
    `fan_fan_profile_id` BIGINT COMMENT 'Reference to the fan/subscriber identity record in the fan domain. Links the subscription to the individual consumer. Aligns with Adobe Experience Platform fan profile.',
    `payment_method_id` BIGINT COMMENT 'Foreign key linking to fan.payment_method. Business justification: Streaming subscription recurring billing requires a reference to the fans stored tokenized payment method for charge processing, failed payment retry, and PCI compliance audit. streaming_subscription',
    `fan_profile_id` BIGINT COMMENT 'Reference to the fan/subscriber identity record in the fan domain. Links the subscription to the individual consumer. Aligns with Adobe Experience Platform fan profile.',
    `loyalty_program_id` BIGINT COMMENT 'Foreign key linking to fan.loyalty_program. Business justification: Streaming subscriptions are bundled with or earn points under specific loyalty programs (e.g., OTT subscribers auto-enroll in a digital loyalty tier). This link enables loyalty earning attribution per',
    `subscription_plan_id` BIGINT COMMENT 'Reference to the subscription plan/tier definition record that governs the entitlements, pricing, and features associated with this subscription.',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Streaming subscriptions are the primary recurring revenue source (ARR/MRR) in sports broadcasting. Finance maps each subscription plan to a revenue stream for ARR tracking, churn analysis, and subscri',
    `season_ticket_account_id` BIGINT COMMENT 'Foreign key linking to ticketing.season_ticket_account. Business justification: STH streaming benefit fulfillment: season ticket holders receive bundled streaming subscriptions as a package benefit. Linking streaming_subscription to the season_ticket_account enables benefit provi',
    `season_ticket_package_id` BIGINT COMMENT 'Foreign key linking to ticketing.season_ticket_package. Business justification: Package-level streaming benefit configuration: the season_ticket_package defines which streaming subscription tier is bundled (e.g., premium vs. standard). Linking streaming_subscription to the origin',
    `sla_policy_id` BIGINT COMMENT 'Foreign key linking to platform.sla_policy. Business justification: Streaming subscriptions are sold under specific SLA tiers (concurrent streams, uptime guarantees). Linking to sla_policy enables subscriber-tier SLA enforcement, breach credit calculation, and regulat',
    `tax_jurisdiction_id` BIGINT COMMENT 'Foreign key linking to finance.tax_jurisdiction. Business justification: Streaming subscriptions are subject to digital services tax, VAT, and state/local taxes by subscriber location. Finance requires tax_jurisdiction linkage for tax calculation, nexus determination, and ',
    `acquisition_channel` STRING COMMENT 'The marketing or distribution channel through which the subscriber was acquired. Used for CAC (Customer Acquisition Cost) attribution, ROI (Return on Investment) analysis, and channel performance reporting in Adobe Experience Platform. [ENUM-REF-CANDIDATE: organic|paid_search|social_media|email|partner|in_app|referral — 7 candidates stripped; promote to reference product]',
    `auto_renewal_flag` BOOLEAN COMMENT 'Indicates whether the subscription is configured to automatically renew at the end of each billing cycle without requiring explicit subscriber action. True = auto-renew enabled; False = subscription will expire at end_date unless manually renewed.',
    `billing_cycle` STRING COMMENT 'The recurring billing frequency for the subscription. Determines how often the subscriber is charged and when renewal events are triggered in the billing system.. Valid values are `monthly|quarterly|semi_annual|annual`',
    `billing_cycle_day` STRING COMMENT 'The day of the month (1–28) on which the recurring billing charge is processed. Used by the billing engine to schedule charge attempts and generate invoices.',
    `blackout_region_code` STRING COMMENT 'ISO country or region code identifying the geographic blackout restriction applied to this subscription. Enforces broadcast rights agreements and RSN (Regional Sports Network) territorial exclusivity. Null if no blackout applies.. Valid values are `^[A-Z]{2,3}$`',
    `cancellation_date` DATE COMMENT 'The date on which the subscriber initiated cancellation of the subscription. Distinct from end_date (which is the access expiry). Null if subscription has not been cancelled. Used for churn analysis and GDPR Article 17 right-to-erasure workflows.',
    `cancellation_reason` STRING COMMENT 'Subscriber-provided or system-inferred reason for cancellation. Used for churn root-cause analysis, content investment decisions, and win-back campaign targeting. Null if subscription is not cancelled. [ENUM-REF-CANDIDATE: price|content|technical|competitor|inactivity|payment_failure|other — 7 candidates stripped; promote to reference product]',
    `concurrent_stream_limit` STRING COMMENT 'Maximum number of simultaneous streams permitted under this subscription. Enforced by the streaming platform and CDN. Varies by plan tier (e.g., basic = 1, premium = 3, all-access = 5).',
    `consent_data_sharing_flag` BOOLEAN COMMENT 'Indicates whether the subscriber has consented to their viewing and behavioral data being shared with third-party analytics partners, sponsors, or league data programs. Required for GDPR Article 6 lawful basis and CCPA opt-out compliance.',
    `consent_marketing_flag` BOOLEAN COMMENT 'Indicates whether the subscriber has provided explicit consent to receive marketing communications related to their subscription and associated sports/entertainment content. Mandatory for GDPR and CCPA compliance in fan engagement workflows.',
    `consent_timestamp` TIMESTAMP COMMENT 'The timestamp at which the subscribers consent preferences (marketing and data sharing) were last captured or updated. Required for GDPR audit trail and proof-of-consent obligations.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp at which this streaming subscription record was first created in the system. Represents the RECORD_AUDIT_CREATED category for this MASTER_AGREEMENT entity. Used for data lineage, audit trails, and subscription cohort analysis.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code in which the subscription is billed (e.g., USD, GBP, EUR). Supports multi-market DTC/OTT operations across global territories.. Valid values are `^[A-Z]{3}$`',
    `device_code` STRING COMMENT 'Anonymized or hashed identifier of the primary device registered to this subscription. Used for device-binding enforcement under DRM policies and concurrent stream management. May be considered PII in certain jurisdictions.',
    `download_enabled_flag` BOOLEAN COMMENT 'Indicates whether the subscribers plan tier permits offline content downloads to their device. True = downloads permitted subject to DRM expiry rules; False = streaming only. Governed by content rights windows.',
    `drm_profile_code` STRING COMMENT 'Reference to the DRM (Digital Rights Management) policy profile assigned to this subscription tier. Governs content protection, concurrent stream limits, download rights, and device binding rules enforced by the CDN (Content Delivery Network) and streaming platform.',
    `end_date` DATE COMMENT 'The date on which the current subscription term ends. Nullable for open-ended subscriptions. For fixed-term plans this is the contractual expiry; for auto-renewing plans this is the next renewal date minus one day. Represents EFFECTIVE_UNTIL for this MASTER_AGREEMENT entity.',
    `geo_country_code` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code of the subscribers registered billing address. Used for geo-based rights enforcement, tax jurisdiction determination, GDPR/CCPA applicability, and regional content licensing compliance.. Valid values are `^[A-Z]{3}$`',
    `max_video_quality` STRING COMMENT 'The highest video resolution quality tier permitted under this subscription plan. Governs CDN (Content Delivery Network) stream quality caps and is a key differentiator between subscription tiers.. Valid values are `sd|hd|full_hd|uhd_4k`',
    `next_billing_date` DATE COMMENT 'The upcoming date on which the next recurring charge will be attempted for this subscription. Used for billing forecasting, dunning management, and subscriber communications.',
    `partner_bundle_code` STRING COMMENT 'Identifier of the third-party partner bundle or distribution agreement through which this subscription was provisioned (e.g., IPTV carrier bundle, telco partnership, OTT aggregator). Null for direct DTC subscriptions. Used for partner revenue share reporting.',
    `payment_method_type` STRING COMMENT 'The type of payment instrument used for recurring billing of this subscription. Stored as a tokenized reference type only — no raw card data is held in this product in compliance with PCI-DSS.. Valid values are `credit_card|debit_card|paypal|apple_pay|google_pay|direct_debit`',
    `plan_tier` STRING COMMENT 'The commercial tier of the streaming subscription defining the level of content access and features available to the subscriber. Tiers range from basic (limited content) to all-access (full DTC/OTT catalog including PPV events).. Valid values are `basic|standard|premium|all_access`',
    `ppv_access_flag` BOOLEAN COMMENT 'Indicates whether this subscription tier includes access to PPV (Pay-Per-View) events as part of the base plan entitlement. True = PPV events included; False = PPV requires separate purchase. Critical for revenue recognition and event packaging decisions.',
    `promo_code` STRING COMMENT 'The promotional or discount code applied at the time of subscription sign-up. Used to track campaign effectiveness, partner referral programs, and sponsorship-driven subscriber acquisition.',
    `promotional_rate` DECIMAL(18,2) COMMENT 'The discounted charge amount applied during a promotional period (e.g., introductory offer, bundle discount, loyalty reward). When populated, this rate overrides the standard subscription_charge for the promotional duration.',
    `promotional_rate_end_date` DATE COMMENT 'The date on which the promotional pricing expires and the subscriber reverts to the standard subscription_charge. Null if no promotion is active.',
    `service_type` STRING COMMENT 'Classifies the streaming service model under which this subscription operates. DTC (Direct-To-Consumer) = owned platform; OTT (Over-The-Top Streaming) = third-party app distribution; IPTV (Internet Protocol Television) = carrier-delivered; RSN (Regional Sports Network) = regional broadcast bundle; PPV (Pay-Per-View) = single-event purchase.. Valid values are `dtc|ott|iptv|rsn|ppv`',
    `source_system` STRING COMMENT 'The operational system of record from which this subscription record originated. Used for data lineage tracking, reconciliation, and Silver Layer provenance in the Databricks Lakehouse. Aligns with Adobe Experience Platform as the primary fan engagement and DTC subscription platform.. Valid values are `adobe_experience_platform|salesforce_crm|dtc_platform|ott_partner|manual`',
    `start_date` DATE COMMENT 'The date on which the subscription became or becomes effective and the subscriber gains access to entitled content. Represents the EFFECTIVE_FROM for this MASTER_AGREEMENT entity.',
    `subscription_charge` DECIMAL(18,2) COMMENT 'The gross recurring charge amount billed to the subscriber per billing cycle before any discounts or promotional adjustments. Expressed in the subscription currency.',
    `subscription_number` STRING COMMENT 'Externally-visible, human-readable subscription reference number used in customer communications, billing statements, and support interactions. Sourced from the DTC/OTT platform billing system.. Valid values are `^SUB-[A-Z0-9]{8,16}$`',
    `subscription_status` STRING COMMENT 'Current lifecycle state of the streaming subscription. Drives entitlement enforcement, billing actions, and fan engagement workflows. Active = currently billable and entitled; Trialing = within a free trial window; Suspended = temporarily paused; Cancelled = subscriber-initiated termination; Expired = end date passed without renewal.. Valid values are `active|suspended|cancelled|expired|pending|trialing`',
    `suspension_date` DATE COMMENT 'The date on which the subscription was placed into a suspended state (e.g., due to payment failure, voluntary pause, or compliance hold). Null if subscription has never been suspended.',
    `suspension_reason` STRING COMMENT 'The reason the subscription was placed into a suspended state. Used for operational triage, dunning management, and compliance reporting. Null if subscription has never been suspended.. Valid values are `payment_failure|voluntary_pause|fraud_review|compliance_hold|other`',
    `trial_end_date` DATE COMMENT 'The date on which the free trial period ends and the first paid billing cycle commences. Null if trial_flag is False. Critical for churn prediction and trial-to-paid conversion tracking.',
    `trial_flag` BOOLEAN COMMENT 'Indicates whether the subscription is currently within a free trial period. True = subscriber has not yet been charged; False = paid subscription. Used to distinguish trial cohorts from paying subscribers in ARPU (Average Revenue Per User) and LTV (Lifetime Value) analytics.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp at which this streaming subscription record was last modified. Used for change data capture (CDC) in the Databricks Silver Layer pipeline, audit trails, and detecting stale records.',
    CONSTRAINT pk_streaming_subscription PRIMARY KEY(`streaming_subscription_id`)
) COMMENT 'Master record of fan streaming subscriptions to DTC and OTT broadcast services. Captures subscriber reference, subscription plan tier (basic, premium, all-access), billing cycle, start/end dates, platform (mobile, web, connected TV), auto-renewal flag, promotional rate, and current status. SSOT for streaming subscription lifecycle within the broadcast domain. Complements fan domain identity records.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`media_asset` (
    `media_asset_id` BIGINT COMMENT 'Unique surrogate identifier for each media asset record in the broadcast domain master catalog. Primary key for the media_asset data product managed within Dalet Galaxy DAM.',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Broadcast talent clearance and content rights management require knowing which athlete is featured in each media asset (highlight, interview, feature segment). Rights compliance, NIL conflict checks, ',
    `broadcast_drm_policy_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_drm_policy. Business justification: media_asset has drm_policy_id → content.drm_policy (cross-domain) but no FK to broadcast.broadcast_drm_policy. The broadcast-specific DRM policy governs how the asset is protected and distributed acro',
    `production_id` BIGINT COMMENT 'Foreign key linking to broadcast.production. Business justification: A media asset is produced by a broadcast production. media_asset has production_company (STRING) but no FK to the production record. Linking to production enables crew attribution, production metadata',
    `broadcast_rights_window_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_rights_window. Business justification: A media assets distribution is governed by a broadcast rights window defining permitted territories, platforms, and time periods. media_asset has rights_territory and rights_expiry_date as denormaliz',
    `asset_id` BIGINT COMMENT 'Native asset identifier assigned by the Dalet Galaxy Digital Asset Management (DAM) system. Used to cross-reference records between the Silver Layer lakehouse and the operational DAM source system.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the live sports or entertainment event that this media asset was captured from or is associated with. Links the broadcast asset to the event domain for scheduling, venue, and competition context.',
    `fixture_id` BIGINT COMMENT 'Reference to the live sports or entertainment event that this media asset was captured from or is associated with. Links the broadcast asset to the event domain for scheduling, venue, and competition context.',
    `ip_portfolio_id` BIGINT COMMENT 'Foreign key linking to legal.ip_portfolio. Business justification: Media assets (game recordings, highlights, branded content) are protected by IP rights tracked in the IP portfolio. The rights_clearance_status field confirms IP clearance workflows exist. Legal teams',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Media assets are catalogued by league season for archive management, rights clearance, and content licensing decisions. season_year on media_asset is a denormalized representation of the season entity',
    `live_feed_id` BIGINT COMMENT 'Foreign key linking to broadcast.live_feed. Business justification: A media asset (replay, highlight, recording) is produced from a live feed. media_asset has is_live_recording flag indicating this relationship. Linking media_asset to its source live_feed enables prov',
    `rights_clearance_id` BIGINT COMMENT 'Foreign key linking to content.rights_clearance. Business justification: Media asset distribution requires verified rights clearance. The rights_clearance_status plain attribute on media_asset is a denormalized copy of content.rights_clearance data. Linking to rights_clear',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to partner.vendor_contract. Business justification: Media assets are produced/delivered by external production companies under vendor contracts. Replaces denormalized production_company field. Enables vendor invoice matching against asset deliverables ',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the media asset passed quality control review and was approved for distribution. Marks the transition from qc_review to approved status in the broadcast workflow lifecycle.',
    `archive_location` STRING COMMENT 'Physical or logical storage path/URI where the media asset master file is archived (e.g., cloud object storage bucket path, SAN mount point, tape library reference). Used by the Dalet Galaxy DAM for asset retrieval and restore operations.',
    `archive_tier` STRING COMMENT 'Storage tier classification for the media asset based on access frequency and retention requirements. Hot: frequently accessed active assets; Warm: recent but less active; Cold: infrequently accessed; Deep Archive: long-term preservation. Drives storage cost allocation and retrieval SLA.. Valid values are `hot|warm|cold|deep_archive`',
    `aspect_ratio` STRING COMMENT 'Video aspect ratio of the media asset. Determines display compatibility across broadcast, OTT, and social media platforms. 16:9 is standard for HD/4K broadcast; 9:16 for vertical social media clips.. Valid values are `16:9|4:3|21:9|1:1|9:16`',
    `asset_status` STRING COMMENT 'Current state of the media asset within the Dalet Galaxy broadcast workflow lifecycle. Controls downstream distribution eligibility and archive processing. Values: draft (being created), ingest (being ingested), qc_review (under quality control review), approved (cleared for distribution), archived (moved to long-term storage), deleted (logically removed).. Valid values are `draft|ingest|qc_review|approved|archived|deleted`',
    `asset_type` STRING COMMENT 'Classification of the media asset by its production and editorial purpose within the broadcast workflow. Drives rights clearance rules, distribution eligibility, and archive retention policies. [ENUM-REF-CANDIDATE: live_recording|highlight_reel|replay|promo|interstitial|documentary|clip|raw_feed|press_conference|interview — promote to reference product if additional types are required]. Valid values are `live_recording|highlight_reel|replay|promo|interstitial|documentary`',
    `audio_channels` STRING COMMENT 'Number of audio channels in the media asset (e.g., 2 for stereo, 6 for 5.1 surround, 8 for 7.1 surround). Required for broadcast playout compatibility and OTT audio track configuration.',
    `blackout_rule_applicable` BOOLEAN COMMENT 'Indicates whether broadcast blackout rules apply to this media asset. When True, the asset is subject to geographic blackout restrictions per league media rights agreements (e.g., NFL local market blackouts, RSN territorial restrictions). Drives CDN geo-blocking logic.',
    `broadcast_date` DATE COMMENT 'Date on which this media asset was first broadcast or made available to audiences. Used for rights window calculations, replay eligibility, and archive classification.',
    `cdn_delivery_url` STRING COMMENT 'Primary CDN-hosted URL for streaming or downloading this media asset. Used by OTT, IPTV, and DTC platforms to serve content to end users. May be a signed or tokenized URL depending on DRM policy.',
    `checksum` STRING COMMENT 'SHA-256 cryptographic checksum of the media asset master file. Used to verify file integrity during ingest, transfer, and archive operations. Ensures no corruption or unauthorized modification of broadcast master content.. Valid values are `^[a-fA-F0-9]{64}$`',
    `codec` STRING COMMENT 'Video codec used to encode the media asset (e.g., H.264, H.265/HEVC, AVC, ProRes 422). Critical for transcoding decisions, CDN delivery optimization, and OTT/IPTV platform compatibility.',
    `content_rating` STRING COMMENT 'Television content rating assigned to the media asset per FCC/TV Parental Guidelines (e.g., TV-G, TV-PG, TV-14, TV-MA). Required for broadcast compliance, parental control enforcement on OTT platforms, and advertising eligibility.. Valid values are `TV-G|TV-PG|TV-14|TV-MA|NR`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the media asset record was first created in the Dalet Galaxy DAM system and propagated to the Silver Layer lakehouse. Audit trail field for data lineage and compliance reporting.',
    `distribution_channel` STRING COMMENT 'Primary distribution channel for which this media asset is packaged or cleared. Drives platform-specific encoding, DRM policy selection, and rights window application. [ENUM-REF-CANDIDATE: linear_tv|ott|iptv|dtc|rsn|ppv|social_media|vod|syndication — promote to reference product if additional channels required]',
    `duration_seconds` STRING COMMENT 'Total playback duration of the media asset in seconds. Used for broadcast scheduling, rights window calculations, PPV packaging, and CDN bandwidth planning.',
    `file_size_mb` DECIMAL(18,2) COMMENT 'Physical file size of the media asset in megabytes. Used for storage capacity planning, archive cost allocation, and CDN transfer cost estimation.',
    `format` STRING COMMENT 'Technical container or wrapper format of the media asset file (e.g., MXF for broadcast master, MP4 for OTT/DTC delivery, HLS for adaptive streaming). Determines compatibility with CDN delivery and playout systems. [ENUM-REF-CANDIDATE: MP4|MXF|MOV|HLS|DASH|ProRes|DNxHD — 7 candidates stripped; promote to reference product]',
    `frame_rate` DECIMAL(18,2) COMMENT 'Video frame rate of the media asset expressed in frames per second (fps), e.g., 23.98, 25.00, 29.97, 50.00, 59.94. Required for broadcast standards compliance and playout scheduling.',
    `ingest_source` STRING COMMENT 'Origin source from which the media asset was ingested into the Dalet Galaxy DAM system. OB (Outside Broadcast) truck, studio feed, satellite uplink, file transfer, API ingest, or third-party delivery. Used for provenance tracking and quality control routing.. Valid values are `ob_truck|studio_feed|satellite|file_transfer|api_ingest|third_party`',
    `ingest_timestamp` TIMESTAMP COMMENT 'Date and time when the media asset was first ingested into the Dalet Galaxy DAM system. Marks the start of the asset lifecycle and is used for SLA tracking, audit trails, and archive retention calculations.',
    `is_live_recording` BOOLEAN COMMENT 'Indicates whether this media asset is a live or near-live recording captured during an active broadcast event, as opposed to a pre-produced or post-produced asset. Drives priority ingest workflows and real-time CDN distribution rules.',
    `language_code` STRING COMMENT 'Primary spoken/audio language of the media asset expressed as an ISO 639-1 or ISO 639-2 language code (e.g., en, es, fr, pt-BR). Drives regional distribution rights and localization workflows.. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `league_code` STRING COMMENT 'Code identifying the professional league or governing body associated with the media asset (e.g., NFL, NBA, MLB, NHL, MLS, FIFA, UFC, ATP). Drives rights clearance rules, blackout policy application, and RSN distribution eligibility.',
    `metadata_tags` STRING COMMENT 'Comma-separated free-text metadata tags applied to the media asset for search, discovery, and content classification purposes within the Dalet Galaxy DAM (e.g., playoffs,overtime,game-winner,fourth-quarter). Supports AI/ML content recommendation and editorial search.',
    `ppv_eligible` BOOLEAN COMMENT 'Indicates whether this media asset is eligible for Pay-Per-View (PPV) packaging and monetization. When True, the asset may be included in PPV event bundles and premium access tiers.',
    `resolution` STRING COMMENT 'Video resolution classification of the media asset. Drives distribution tier eligibility (e.g., 4K for premium PPV, HD for standard broadcast, SD for legacy RSN feeds) and storage cost allocation.. Valid values are `SD|HD|FHD|4K|8K`',
    `rights_expiry_date` DATE COMMENT 'Date on which the media rights clearance for this asset expires. After this date, the asset must be withheld from distribution pending rights renewal. Critical for automated rights enforcement and compliance with media rights agreements.',
    `rights_territory` STRING COMMENT 'Geographic territory or territories in which this media asset is cleared for distribution, expressed as ISO 3166-1 alpha-3 country codes or a named territory group (e.g., USA, GBR, WORLDWIDE, EMEA). Drives blackout rule enforcement and regional RSN assignment.',
    `sport_type` STRING COMMENT 'Sport or athletic discipline associated with the media asset (e.g., American Football, Basketball, Soccer, Baseball, Hockey, Tennis, MMA). Used for rights segmentation, RSN assignment, and content discovery. [ENUM-REF-CANDIDATE: american_football|basketball|soccer|baseball|hockey|tennis|mma|golf|motorsport|olympics — promote to reference product]',
    `subtitle_available` BOOLEAN COMMENT 'Indicates whether closed captions or subtitles are available for this media asset. Required for ADA (Americans with Disabilities Act) compliance for broadcast content and OTT platform accessibility standards.',
    `title` STRING COMMENT 'Human-readable title of the media asset as catalogued in the DAM system (e.g., NBA Finals Game 7 Full Broadcast, Super Bowl LVIII Halftime Show Highlight Reel).',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when the media asset record was last modified in the source DAM system or Silver Layer. Used for incremental data pipeline processing, audit trails, and change data capture (CDC) workflows.',
    `version_number` STRING COMMENT 'Incremental version number of the media asset, incremented each time the asset is edited, re-encoded, or updated. Supports version control and ensures downstream systems consume the correct asset revision.',
    CONSTRAINT pk_media_asset PRIMARY KEY(`media_asset_id`)
) COMMENT 'Master catalog of broadcast media assets managed within the Dalet Galaxy DAM system. Captures asset ID, title, asset type (live recording, highlight reel, replay, promo, interstitial), format, duration, resolution, language, sport/league association, event association, rights clearance status, archive location, and metadata tags. SSOT for broadcast-owned media asset inventory distinct from content domain editorial assets.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`broadcast_rights_window` (
    `broadcast_rights_window_id` BIGINT COMMENT 'Unique surrogate identifier for each granular rights window record within the broadcast domain. Primary key for the broadcast_rights_window data product on the Databricks Silver Layer.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to broadcast.channel. Business justification: A broadcast rights window defines rights for a specific channel or distribution outlet. broadcast_rights_window has platform_type (STRING) but no FK to the channel master record. This FK enables chann',
    `broadcast_drm_policy_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_drm_policy. Business justification: broadcast_rights_window has drm_policy_id → content.drm_policy (cross-domain) but no FK to broadcast.broadcast_drm_policy. The broadcast DRM policy governs how content within the rights window is prot',
    `content_category_id` BIGINT COMMENT 'Reference to the content category classification governing what type of content is covered by this rights window (e.g., live match, highlight reel, documentary, PPV event).',
    `digital_touchpoint_id` BIGINT COMMENT 'Foreign key linking to platform.digital_touchpoint. Business justification: Rights windows specify which digital platforms are licensed for content distribution. The plain platform_type column is a classification. Linking to digital_touchpoint enables rights compliance enforc',
    `event_fixture_id` BIGINT COMMENT 'Reference to a specific sporting event or fixture covered by this rights window. Nullable for deal-level windows that cover a season or content category rather than a single event.',
    `fixture_id` BIGINT COMMENT 'Reference to a specific sporting event or fixture covered by this rights window. Nullable for deal-level windows that cover a season or content category rather than a single event.',
    `ip_portfolio_id` BIGINT COMMENT 'Foreign key linking to legal.ip_portfolio. Business justification: Rights windows grant use of specific IP assets (league marks, broadcast trademarks, content copyrights). Legal teams track which IP portfolio items are activated under each window for IP valuation, en',
    `league_id` BIGINT COMMENT 'Reference to the sports league or competition governing body whose content is covered by this rights window (e.g., NFL, NBA, FIFA, MLS). Enables league-level rights aggregation and reporting.',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Rights windows are scoped to specific league seasons for scheduling, rights compliance, and royalty calculation. season_year is a denormalized representation of the season entity. A direct FK to leagu',
    `licensee_id` BIGINT COMMENT 'Reference to the broadcaster, OTT platform, or network entity that has been granted the rights for this window (e.g., RSN, DTC streaming service, IPTV provider).',
    `matter_id` BIGINT COMMENT 'Foreign key linking to legal.legal_matter. Business justification: The rights_conflict_flag and conflict_resolution_status fields on broadcast_rights_window signal that territory and exclusivity conflicts generate legal matters. Legal teams need to link conflicted ri',
    `media_rights_deal_id` BIGINT COMMENT 'Reference to the parent media rights deal from which this window is derived. Links the granular window record back to the overarching rights agreement.',
    `corporate_entity_id` BIGINT COMMENT 'Reference to the organisation or party that holds the broadcast rights for this window (e.g., league, federation, production company). Supports rights enforcement and royalty attribution.',
    `regulatory_license_id` BIGINT COMMENT 'Foreign key linking to legal.regulatory_license. Business justification: Broadcasting in specific territories under a rights window requires a valid regulatory broadcast license for that territory. Legal and compliance teams validate license coverage before activating a ri',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Rights windows define revenue-generating periods mapped to finance revenue streams for period-by-period revenue recognition and rights fee allocation reporting. Finance maps each window to a revenue s',
    `rights_holder_id` BIGINT COMMENT 'Reference to the organisation or party that holds the broadcast rights for this window (e.g., league, federation, production company). Supports rights enforcement and royalty attribution.',
    `advertising_rights_included` BOOLEAN COMMENT 'Indicates whether the licensee has the right to sell advertising inventory (e.g., CPM-based ad slots) within the broadcast under this rights window. Impacts revenue share calculations and sponsorship conflict management.',
    `blackout_applicable` BOOLEAN COMMENT 'Indicates whether broadcast blackout rules apply to this rights window. When True, the CDN and DRM layer must enforce geographic or platform-based blackout restrictions as defined in the associated blackout policy.',
    `broadcast_window_type` STRING COMMENT 'Classifies the role of this rights window within the overall broadcast schedule. Primary windows cover live or first-run broadcasts; secondary covers repeat broadcasts; catch-up covers time-shifted viewing; archive covers library content; preview covers promotional clips.. Valid values are `primary|secondary|catch_up|archive|preview`',
    `catchup_window_days` STRING COMMENT 'Number of days after the original broadcast during which the licensee may make the content available for catch-up or time-shifted viewing. Zero or null indicates no catch-up rights are granted.',
    `concurrent_stream_limit` STRING COMMENT 'Maximum number of simultaneous streams permitted under this rights window for OTT, IPTV, or DTC platforms. Null indicates no contractual limit. Enforced at the CDN and streaming platform layer to prevent rights overrun.',
    `conflict_resolution_status` STRING COMMENT 'Current status of any rights conflict resolution process for this window. Populated only when rights_conflict_flag is True. Tracks progression from detection through resolution or escalation to CAS arbitration.. Valid values are `none|pending_review|resolved|escalated`',
    `content_type` STRING COMMENT 'Classifies the nature of the content covered by this rights window. Distinguishes live broadcast rights from replay, highlight, documentary, PPV event, and magazine show rights, each carrying different fee structures and DRM policies.. Valid values are `live|replay|highlight|documentary|ppv_event|magazine_show`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this rights window record was first created in the system. Supports audit trail requirements under SOX financial controls and GDPR data lineage obligations.',
    `effective_from` DATE COMMENT 'The calendar date from which this rights window record is considered valid for business use. Supports slowly changing dimension (SCD) patterns on the Silver Layer and enables point-in-time rights queries.',
    `effective_until` DATE COMMENT 'The calendar date until which this rights window record is considered valid. Nullable for currently active records. Supports SCD Type 2 history management on the Databricks Silver Layer.',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether the rights granted in this window are exclusive to the licensee within the defined territory and platform. True = exclusive; False = non-exclusive. Exclusive windows command premium rights fees and restrict sublicensing.',
    `language_code` STRING COMMENT 'ISO 639-1/639-2 language code specifying the language in which the content may be broadcast under this rights window (e.g., en, es, fr). Supports multi-language rights management for global markets.. Valid values are `^[a-z]{2,3}$`',
    `max_broadcast_count` STRING COMMENT 'The maximum number of times the content may be broadcast under this rights window. Null indicates unlimited broadcasts within the window period. Enforced by the DRM and broadcast scheduling systems.',
    `min_lead_time_hours` STRING COMMENT 'The minimum number of hours before the scheduled broadcast that the licensee must notify the rights holder or activate the content feed. Supports SLA (Service Level Agreement) compliance and OB (Outside Broadcast) logistics.',
    `notes` STRING COMMENT 'Free-text field for capturing additional contractual conditions, special provisions, or operational notes associated with this rights window that are not captured in structured fields (e.g., specific event carve-outs, force majeure clauses).',
    `payment_schedule_type` STRING COMMENT 'Defines the payment cadence for the rights fee associated with this window. Drives accounts receivable scheduling in SAP S/4HANA and cash flow forecasting in Workday Adaptive Planning.. Valid values are `upfront|annual|quarterly|per_event|milestone`',
    `resolution_tier` STRING COMMENT 'The maximum video resolution permitted for broadcast under this rights window (SD, HD, 4K, 8K). Higher resolution tiers typically command premium rights fees and require specific CDN and DRM capabilities.. Valid values are `sd|hd|4k|8k`',
    `revenue_share_pct` DECIMAL(18,2) COMMENT 'The percentage of broadcast revenue (e.g., subscription, PPV, advertising) that the licensee must remit to the rights holder under this window. Drives financial settlement and EBITDA reporting.',
    `rights_category` STRING COMMENT 'Broad classification of the rights type granted in this window. Distinguishes domestic broadcast rights from international, digital, mobile, radio, PPV (Pay-Per-View), and archive rights. [ENUM-REF-CANDIDATE: domestic|international|digital|mobile|radio|ppv|archive — promote to reference product]',
    `rights_conflict_flag` BOOLEAN COMMENT 'Indicates whether a rights conflict has been detected for this window (e.g., overlapping exclusivity with another window for the same content, platform, and territory). Triggers review workflow in the rights management system.',
    `rights_fee_allocation_pct` DECIMAL(18,2) COMMENT 'The percentage of the total parent deal rights fee allocated to this specific window. Enables proportional revenue recognition and financial reporting across multiple windows derived from a single deal.',
    `rights_fee_amount` DECIMAL(18,2) COMMENT 'The monetary value of the rights fee allocated to this specific window from the parent rights deal. Represents the portion of the total deal value attributable to this platform-territory-period combination. Used for revenue recognition and financial reporting.',
    `rights_fee_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the rights fee amount (e.g., USD, GBP, EUR). Required for multi-currency rights deals across global markets.. Valid values are `^[A-Z]{3}$`',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this rights window record was ingested (e.g., DALET_GALAXY, SAP_SD, SALESFORCE_CRM). Supports data lineage tracking on the Databricks Silver Layer.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `sublicensing_permitted` BOOLEAN COMMENT 'Indicates whether the licensee is contractually permitted to sublicense the broadcast rights to third parties within this window. Drives downstream rights conflict detection and IP (Intellectual Property) protection enforcement.',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code identifying the geographic territory in which this rights window is valid. Drives blackout rule enforcement and geo-restriction logic at the CDN layer.. Valid values are `^[A-Z]{3}$`',
    `territory_scope` STRING COMMENT 'Indicates the geographic breadth of the rights window beyond a single country code. Supports multi-territory deal structures where a single window covers a defined group of markets.. Valid values are `national|regional|local|global|multi_territory`',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this rights window record was last modified. Supports change data capture (CDC) pipelines on the Databricks Silver Layer and audit trail requirements under SOX.',
    `window_end` TIMESTAMP COMMENT 'The precise date and time (exclusive) after which the licensees broadcast rights under this window expire. Nullable for perpetual or open-ended windows. Critical for automated rights expiry enforcement.',
    `window_reference_code` STRING COMMENT 'Externally-known alphanumeric business identifier for this rights window, used in contracts, invoices, and rights management systems. Enables cross-system reconciliation with SAP S/4HANA and Dalet Galaxy.. Valid values are `^[A-Z0-9-]{4,30}$`',
    `window_start` TIMESTAMP COMMENT 'The precise date and time (inclusive) from which the licensee is permitted to broadcast content under this rights window. Used for real-time rights enforcement at the CDN and DRM layer.',
    `window_status` STRING COMMENT 'Current lifecycle state of the broadcast rights window. Drives rights enforcement logic: only active windows permit broadcast. Transitions follow deal negotiation and regulatory approval workflows.. Valid values are `active|pending|suspended|expired|terminated|draft`',
    CONSTRAINT pk_broadcast_rights_window PRIMARY KEY(`broadcast_rights_window_id`)
) COMMENT 'Granular rights window records derived from media rights deals, defining the specific time periods, platforms, and territories in which a rights holder may broadcast specific content. Captures rights deal reference, content category, platform type, territory, window start/end, exclusivity flag, sublicensing permission, and rights fee allocation. Enables precise rights enforcement at the content-platform-territory level.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`production` (
    `production_id` BIGINT COMMENT 'Primary key for production',
    `broadcast_drm_policy_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_drm_policy. Business justification: production has drm_policy_code (STRING) which is a denormalized reference to the DRM policy governing the productions content protection. Replacing with a FK to broadcast_drm_policy enables proper DR',
    `broadcast_schedule_id` BIGINT COMMENT 'Reference to the parent broadcast schedule entry that this production instance fulfills. Links physical production execution to the scheduled broadcast slot.',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.budget. Business justification: Broadcast productions have approved finance budgets for crew, equipment, and venue costs. Finance maps each production to its budget line for production cost variance analysis and approval workflows. ',
    `capacity_config_id` BIGINT COMMENT 'Foreign key linking to venue.capacity_config. Business justification: Broadcast production crews require the venue capacity configuration (camera positions, bowl orientation, floor plan version) for OB unit placement and technical setup. This is a standard venue technic',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Broadcast productions (OB units, crew, equipment) generate costs tracked against cost centers in finance for production budget management and variance analysis. Finance requires production-to-cost-cen',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: Productions include sponsor_billboard_count fulfilling sponsorship deal obligations. Linking enables tracking of which deals broadcast mention and billboard obligations a production fulfills — requir',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Broadcast production crew scheduling, union call-sheet compliance, and payroll differential processing require linking the production director and technical producer to their workforce employee record',
    `event_fixture_id` BIGINT COMMENT 'Reference to the sporting or entertainment event being produced and broadcast. Connects production execution to the event domain.',
    `fixture_id` BIGINT COMMENT 'Reference to the sporting or entertainment event being produced and broadcast. Connects production execution to the event domain.',
    `production_team_id` BIGINT COMMENT 'Foreign key linking to broadcast.production_team. Business justification: Production operations are executed by production teams. The production table tracks individual production instances but does not currently link to the production_team reference table. Adding productio',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to partner.vendor_contract. Business justification: Broadcast productions are executed by external production companies under vendor contracts. This link enables SLA measurement, vendor scorecard evaluation, and AP invoice matching for production servi',
    `venue_id` BIGINT COMMENT 'Reference to the venue or facility where the broadcast production is physically executed. Used for venue technical setup coordination.',
    `wbs_element_id` BIGINT COMMENT 'Foreign key linking to finance.wbs_element. Business justification: Major broadcast productions (championship events, season launches) are managed as projects under WBS elements in finance for project cost tracking, capex/opex classification, and settlement. Finance e',
    `actual_end_timestamp` TIMESTAMP COMMENT 'Actual date and time the broadcast production concluded. Used for rights window compliance, overtime cost tracking, and post-event reporting.',
    `actual_start_timestamp` TIMESTAMP COMMENT 'Actual date and time the broadcast production went on-air or began active production. Compared against scheduled_start_timestamp for SLA compliance and post-event reporting.',
    `broadcast_language` STRING COMMENT 'Primary language of the broadcast commentary and production, expressed as an IETF BCP 47 language tag (e.g., en, es, fr, pt-BR). Drives market designation and rights distribution.. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `cdn_origin_endpoint` STRING COMMENT 'URL or identifier of the Content Delivery Network (CDN) origin endpoint used to distribute the live or replay feed for this production. Supports multi-platform delivery and streaming SLA monitoring.',
    `color_analyst_name` STRING COMMENT 'Full name of the color analyst (expert commentator) assigned to this productions commentary team. Tracked for talent scheduling, contract compliance, and broadcast quality.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this broadcast production record was first created in the Dalet Galaxy system and ingested into the Silver layer. Supports audit trail and data lineage.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the PPV price and any production cost amounts (e.g., USD, GBP, EUR). Null for non-monetary productions.. Valid values are `^[A-Z]{3}$`',
    `distribution_platform` STRING COMMENT 'Primary platform through which this production is distributed to audiences. linear_tv = traditional broadcast; ott = Over-The-Top streaming; iptv = Internet Protocol Television; ppv = Pay-Per-View; dtc = Direct-To-Consumer streaming; rsn = Regional Sports Network; radio = audio broadcast. [ENUM-REF-CANDIDATE: linear_tv|ott|iptv|ppv|dtc|rsn|radio — 7 candidates stripped; promote to reference product]',
    `equipment_manifest_reference` STRING COMMENT 'Reference code or document identifier for the equipment manifest associated with this production, listing all cameras, audio rigs, transmission equipment, and OB unit inventory. Sourced from Dalet Galaxy asset tracking.',
    `frame_rate` DECIMAL(18,2) COMMENT 'Video frame rate (frames per second) for this broadcast production (e.g., 29.97, 50, 59.94). Governs technical compatibility with distribution platforms and replay content processing.',
    `graphics_package_version` STRING COMMENT 'Version identifier of the on-screen graphics package (lower thirds, scoreboards, transitions, sponsor overlays) deployed for this production. Critical for brand consistency and sponsor compliance.',
    `is_ppv` BOOLEAN COMMENT 'Indicates whether this broadcast production is packaged and distributed as a Pay-Per-View (PPV) event, requiring individual purchase by viewers. Drives revenue recognition and DRM policy application.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this broadcast production record in the source system or Silver layer. Supports change tracking, SLA monitoring, and incremental ETL processing.',
    `market_designation` STRING COMMENT 'Geographic market or territory for which this production is designated (e.g., US-National, RSN-Northeast, UK, LATAM-Spanish). Governs blackout rules, rights windows, and distribution platform routing. [ENUM-REF-CANDIDATE: promote to reference product for standardized market codes]',
    `notes` STRING COMMENT 'Free-text operational notes entered by the production team in Dalet Galaxy, capturing special instructions, contingency plans, or event-specific considerations for this broadcast production.',
    `ob_unit_identifier` STRING COMMENT 'Identifier of the Outside Broadcast (OB) truck or mobile production unit deployed for remote productions. Null for studio-based productions. Critical for equipment logistics and vendor billing.',
    `play_by_play_announcer` STRING COMMENT 'Full name of the primary play-by-play announcer assigned to this productions commentary team. Key talent assignment tracked for scheduling, NIL compliance, and audience analytics.',
    `postshow_duration_minutes` STRING COMMENT 'Planned duration in minutes of the post-show segment following the main event broadcast. Used for crew scheduling, sponsor slot allocation, and runsheet planning.',
    `ppv_price` DECIMAL(18,2) COMMENT 'Retail price charged to consumers for access to this Pay-Per-View (PPV) broadcast production. Null for non-PPV productions. Used in revenue management and financial reporting.',
    `preshow_duration_minutes` STRING COMMENT 'Planned duration in minutes of the pre-show segment preceding the main event broadcast. Used for crew scheduling, sponsor slot allocation, and runsheet planning.',
    `production_code` STRING COMMENT 'Externally-known alphanumeric code assigned by Dalet Galaxy to uniquely identify this broadcast production instance across systems and workflows. Used in runsheets, crew calls, and equipment manifests.. Valid values are `^PRD-[A-Z0-9]{4,12}$`',
    `production_status` STRING COMMENT 'Current lifecycle state of the broadcast production instance within the Dalet Galaxy workflow. draft = initial planning; confirmed = crew and equipment locked; in_production = active pre-show or live execution; on_air = currently broadcasting; completed = post-production wrap; cancelled = production cancelled.. Valid values are `draft|confirmed|in_production|on_air|completed|cancelled`',
    `production_type` STRING COMMENT 'Classification of the broadcast production method. live = real-time event coverage; studio = studio-based production; remote_ob = Outside Broadcast (OB) unit at venue; tape_delay = recorded and broadcast later; highlight = post-event highlight package. [ENUM-REF-CANDIDATE: live|studio|remote_ob|tape_delay|highlight|ppv — promote to reference product if additional types emerge]. Valid values are `live|studio|remote_ob|tape_delay|highlight`',
    `replay_availability_timestamp` TIMESTAMP COMMENT 'Date and time when replay or VOD content for this production becomes available to viewers on designated platforms. Null if replay_content_available is false. Governs rights window compliance.',
    `replay_content_available` BOOLEAN COMMENT 'Indicates whether replay/VOD content will be made available following the live broadcast of this production. Drives post-production workflow initiation and rights window activation in the content domain.',
    `rsn_affiliate_code` STRING COMMENT 'Code identifying the Regional Sports Network (RSN) affiliate carrying this production for regional linear TV distribution. Null for national or OTT-only productions.',
    `scheduled_end_timestamp` TIMESTAMP COMMENT 'Planned date and time when the broadcast production is scheduled to conclude, including post-show segments. Used for rights window management and crew scheduling.',
    `scheduled_start_timestamp` TIMESTAMP COMMENT 'Planned date and time (with timezone offset) when the broadcast production is scheduled to begin, including pre-show setup. Principal business event timestamp for scheduling and rights window alignment.',
    `sideline_reporter_name` STRING COMMENT 'Full name of the sideline reporter assigned to this production. May be null for studio-only productions. Tracked for talent scheduling and credential management.',
    `signal_format` STRING COMMENT 'Technical broadcast signal format used for this production (e.g., HD, 4K, 8K, SD, HDR). Determines equipment requirements, CDN bandwidth allocation, and platform delivery specifications.. Valid values are `HD|4K|8K|SD|HDR`',
    `sponsor_billboard_count` STRING COMMENT 'Number of sponsor billboard/branding slots allocated within this productions broadcast runsheet. Used for sponsorship fulfillment tracking and CPM reporting.',
    `title` STRING COMMENT 'Human-readable title of the broadcast production (e.g., NFL Sunday Night Football – Week 12 – Chiefs vs Eagles). Used in scheduling systems, crew communications, and broadcast runsheets.',
    CONSTRAINT pk_production PRIMARY KEY(`production_id`)
) COMMENT 'Operational record of each broadcast production instance for a scheduled event, including crew and commentary team assignments. Captures production type (live, studio, remote OB), director, technical producer, production company, equipment manifest, venue technical setup, graphics package version, pre-show/post-show segments, production status, and commentary team composition (play-by-play, color analyst, sideline reporter) with language and market designations. Links broadcast schedule to physical production execution. Sourced from Dalet Galaxy broadcast workflow.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`rights_violation` (
    `rights_violation_id` BIGINT COMMENT 'Unique surrogate identifier for each detected or reported media rights violation record in the broadcast domain.',
    `blackout_rule_id` BIGINT COMMENT 'Reference to the specific broadcast blackout rule that was violated, applicable when the violation type is blackout non-compliance. Links to the blackout rules configuration in the broadcast domain.',
    `broadcast_event_broadcast_schedule_id` BIGINT COMMENT 'Reference to the specific broadcast event (e.g., live match, PPV event, scheduled broadcast) that was subject to the rights violation.',
    `broadcast_rights_window_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_rights_window. Business justification: A rights violation occurs within the context of a specific broadcast rights window. rights_violation has rights_window_id → content.rights_window (cross-domain) but no FK to broadcast.broadcast_rights',
    `broadcast_schedule_id` BIGINT COMMENT 'Reference to the specific broadcast event (e.g., live match, PPV event, scheduled broadcast) that was subject to the rights violation.',
    `asset_id` BIGINT COMMENT 'Reference to the specific media content asset (e.g., broadcast clip, live feed, replay) that was subject to the rights violation, as tracked in Dalet Galaxy.',
    `content_drm_policy_id` BIGINT COMMENT 'Reference to the Digital Rights Management (DRM) policy that was circumvented or breached as part of this violation.',
    `incident_report_id` BIGINT COMMENT 'Foreign key linking to compliance.incident_report. Business justification: Rights violations (piracy, blackout breaches, unauthorized distribution) are compliance incidents requiring formal incident reporting, regulatory notification, and GDPR assessment. Compliance teams mu',
    `ip_enforcement_action_id` BIGINT COMMENT 'Foreign key linking to legal.ip_enforcement_action. Business justification: Broadcast rights violations (unauthorized streaming, piracy) directly trigger IP enforcement actions managed by the legal team. The ip_enforcement_action product has a broadcast_rights_related flag co',
    `litigation_case_id` BIGINT COMMENT 'Foreign key linking to legal.litigation_case. Business justification: The legal_case_reference plain text field on rights_violation denormalizes the litigation case. Rights violations that result in lawsuits must be linked to the formal litigation case for discovery, le',
    `live_feed_id` BIGINT COMMENT 'Foreign key linking to broadcast.live_feed. Business justification: A rights violation often involves unauthorized rebroadcast of a specific live feed. Linking rights_violation to live_feed enables feed-level piracy detection, enforcement action tracking, and estimate',
    `matter_id` BIGINT COMMENT 'Foreign key linking to legal.legal_matter. Business justification: Rights violations that escalate beyond automated takedowns become formal legal matters for cease-and-desist, damages claims, or settlement. Legal ops teams need to link violation records to active mat',
    `media_rights_deal_id` BIGINT COMMENT 'Reference to the media rights agreement that was violated, linking the violation to the specific broadcast rights contract.',
    `ap_invoice_id` BIGINT COMMENT 'Foreign key linking to finance.ap_invoice. Business justification: Rights violations resulting in financial penalties generate AP invoices for penalty payments to rights holders. Finance needs the AP invoice linkage to track penalty payables and match violation enfor',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Rights violations have an estimated_revenue_impact that must be attributed to the affected revenue stream for financial loss reporting, insurance claims, and revenue leakage analysis. Finance requires',
    `rights_agreement_id` BIGINT COMMENT 'Reference to the media rights agreement that was violated, linking the violation to the specific broadcast rights contract.',
    `rights_clearance_id` BIGINT COMMENT 'Foreign key linking to content.rights_clearance. Business justification: When a rights violation is detected, legal and compliance teams must cross-reference the content rights clearance record to determine the authorized scope, calculate financial exposure, and build the ',
    `sublicense_agreement_id` BIGINT COMMENT 'Foreign key linking to broadcast.sublicense_agreement. Business justification: A rights violation may be a breach of a sublicense agreement where the sublicensee exceeded their permitted distribution scope. This FK links the violation to the specific sublicense agreement being v',
    `content_type` STRING COMMENT 'Classification of the type of content that was infringed upon. Distinguishes between live broadcasts, replays, highlight clips, Pay-Per-View (PPV) events, documentaries, and interviews.. Valid values are `live_broadcast|replay|highlight_clip|ppv_event|documentary|interview`',
    `counter_notice_date` DATE COMMENT 'Date on which the DMCA counter-notice was received from the infringing party. Starts the statutory waiting period clock under DMCA Section 512(g)(2).',
    `counter_notice_received` BOOLEAN COMMENT 'Indicates whether the infringing party filed a DMCA counter-notice disputing the takedown. Triggers a mandatory 10-14 business day waiting period before content may be restored.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this rights violation record was first created in the system, used for audit trail and data lineage purposes.',
    `detected_timestamp` TIMESTAMP COMMENT 'The date and time when the rights violation was first detected or reported, representing the principal real-world event time. Critical for calculating response SLA and legal notice windows.',
    `detection_method` STRING COMMENT 'Method by which the rights violation was identified. Automated monitoring includes Content Delivery Network (CDN) and watermarking tools; third-party reports come from rights monitoring vendors; partner notifications from licensees.. Valid values are `automated_monitoring|manual_review|third_party_report|fan_report|partner_notification`',
    `detection_tool` STRING COMMENT 'Name of the automated tool, monitoring service, or third-party vendor that identified the violation (e.g., Audible Magic, Vobile, MarkMonitor, internal CDN monitoring). Supports vendor performance tracking.',
    `enforcement_action` STRING COMMENT 'Type of enforcement action taken in response to the rights violation. DMCA takedown is the primary tool for online infringement; cease-and-desist and financial penalties apply to commercial infringers.. Valid values are `dmca_takedown|cease_and_desist|financial_penalty|account_suspension|legal_proceedings|no_action`',
    `enforcement_action_date` DATE COMMENT 'Date on which the enforcement action (e.g., DMCA takedown notice, cease-and-desist letter) was formally initiated or submitted against the infringing party.',
    `estimated_audience_reach` BIGINT COMMENT 'Estimated number of viewers or users who accessed the infringing content. Used to assess the commercial impact of the violation and inform penalty calculations.',
    `estimated_revenue_impact` DECIMAL(18,2) COMMENT 'Estimated monetary value of revenue lost or at risk due to this rights violation, used for rights deal enforcement reporting and EBITDA impact analysis. Expressed in the currency of the associated rights agreement.',
    `evidence_reference` STRING COMMENT 'Reference identifier or storage path to the evidence package associated with this violation, including screenshots, stream captures, and recording samples stored in the Digital Asset Management (DAM) system.',
    `financial_penalty_amount` DECIMAL(18,2) COMMENT 'Monetary value of the financial penalty assessed against the infringing party as part of the enforcement action. Expressed in the currency specified by penalty_currency_code.',
    `gdpr_data_subject_notified` BOOLEAN COMMENT 'Indicates whether the data subject (infringing individual) has been notified in accordance with GDPR requirements when personal data was processed during the investigation of this violation. Applicable for EU-territory violations.',
    `infringing_content_duration_seconds` STRING COMMENT 'Duration in seconds of the infringing content that was broadcast or streamed without authorization. Used to assess severity of the violation and calculate proportional penalties.',
    `infringing_party_name` STRING COMMENT 'Name of the individual, organization, or platform identified as the infringing party responsible for the rights violation. May be a broadcaster, streaming service, social media account, or individual user.',
    `infringing_party_type` STRING COMMENT 'Classification of the infringing party responsible for the violation. Distinguishes between individuals, broadcasters, Over-The-Top (OTT) platforms, social media accounts, Internet Protocol Television (IPTV) providers, and Regional Sports Networks (RSN).. Valid values are `individual|broadcaster|ott_platform|social_media_account|iptv_provider|rsn`',
    `infringing_url` STRING COMMENT 'The URL or URI of the infringing content as identified at the time of detection. Used as primary evidence in DMCA takedown notices and cease-and-desist correspondence.',
    `is_repeat_infringer` BOOLEAN COMMENT 'Indicates whether the infringing party has been identified as a repeat infringer with prior violations on record. Repeat infringer status triggers escalated enforcement under DMCA repeat infringer policy.',
    `notes` STRING COMMENT 'Free-text field for additional context, investigator observations, or enforcement correspondence summaries related to this rights violation record.',
    `penalty_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the financial penalty amount assessed against the infringing party (e.g., USD, EUR, GBP).. Valid values are `^[A-Z]{3}$`',
    `platform_name` STRING COMMENT 'Name of the digital platform or channel on which the rights violation was detected (e.g., YouTube, Facebook, Twitch, unauthorized IPTV service, pirate streaming site).',
    `platform_type` STRING COMMENT 'Categorical classification of the platform type where the violation occurred, distinguishing between social media, Over-The-Top (OTT) streaming, Internet Protocol Television (IPTV), linear TV, website, or mobile application.. Valid values are `social_media|ott_streaming|iptv|linear_tv|website|mobile_app`',
    `reporting_source` STRING COMMENT 'Identifies the source that originally reported or flagged the rights violation. Distinguishes between internal monitoring systems, rights holders, licensees, third-party monitoring vendors, regulatory bodies, or public tips.. Valid values are `internal_monitoring|rights_holder|licensee|third_party_vendor|regulatory_body|public_tip`',
    `resolution_date` DATE COMMENT 'Date on which the rights violation was fully resolved, meaning infringing content was removed, penalties were paid, or the case was formally closed.',
    `severity_level` STRING COMMENT 'Business-assessed severity classification of the rights violation based on factors such as audience reach, commercial impact, and violation type. Drives prioritization of enforcement response.. Valid values are `critical|high|medium|low`',
    `takedown_response_date` DATE COMMENT 'Date on which the infringing platform or party responded to the enforcement action, such as confirming content removal or filing a counter-notice. Used to measure platform compliance SLA.',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the geographic territory where the rights violation occurred or was accessible. Critical for geo-restriction breach analysis and territory-specific rights enforcement.. Valid values are `^[A-Z]{3}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this rights violation record, supporting audit trail and change tracking requirements.',
    `violation_reference_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to this violation for use in legal correspondence, DMCA filings, cease-and-desist letters, and enforcement tracking. Format: RV-YYYY-NNNNNN.. Valid values are `^RV-[0-9]{4}-[0-9]{6}$`',
    `violation_status` STRING COMMENT 'Current lifecycle status of the rights violation record, tracking progression from initial detection through enforcement action to resolution or closure.. Valid values are `detected|under_review|enforcement_initiated|resolved|escalated|closed`',
    `violation_type` STRING COMMENT 'Classification of the type of media rights violation detected. Covers unauthorized rebroadcasts, geo-restriction breaches, DRM circumvention, blackout non-compliance, unauthorized clip usage on social platforms, and Pay-Per-View (PPV) signal theft.. Valid values are `unauthorized_rebroadcast|geo_restriction_breach|drm_circumvention|blackout_non_compliance|unauthorized_clip_usage|ppv_signal_theft`',
    CONSTRAINT pk_rights_violation PRIMARY KEY(`rights_violation_id`)
) COMMENT 'Operational record of detected or reported media rights violations including unauthorized rebroadcasts, geo-restriction breaches, DRM circumvention, blackout non-compliance, and unauthorized clip usage on social platforms. Captures violation type, detection method (automated/manual/third-party), detected datetime, platform, territory, infringing party, evidence reference (screenshots, stream captures), enforcement action taken (DMCA takedown, cease-and-desist, financial penalty), resolution status, and legal case reference. Supports rights protection, legal compliance workflows, and rights deal enforcement reporting.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`audience_rating` (
    `audience_rating_id` BIGINT COMMENT 'Unique surrogate identifier for each audience rating measurement record in the broadcast domain. Primary key for the audience_rating data product.',
    `asset_id` BIGINT COMMENT 'Reference to the content asset or media item that was broadcast during the measured window, enabling rights valuation and scheduling optimization.',
    `broadcast_schedule_id` BIGINT COMMENT 'Reference to the scheduled broadcast window for which this audience measurement was captured. Links the rating record to the specific broadcast slot.',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel or streaming platform on which the content was delivered (e.g., linear TV network, OTT service, RSN feed).',
    `content_asset_id` BIGINT COMMENT 'Reference to the content asset or media item that was broadcast during the measured window, enabling rights valuation and scheduling optimization.',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: Audience ratings validate GRP and impression delivery commitments specified in sponsorship deals. Linking enables deal performance reporting and guarantee reconciliation — a standard post-broadcast sp',
    `digital_touchpoint_id` BIGINT COMMENT 'Foreign key linking to platform.digital_touchpoint. Business justification: Audience ratings are measured per delivery touchpoint. The plain delivery_platform column is a denormalized touchpoint reference. Linking to digital_touchpoint enables cross-platform audience analytic',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Franchise-level audience ratings (Team X games average Y million viewers) are a standard sports broadcast metric used directly in rights renewal negotiations and franchise valuation. A domain expert',
    `live_feed_id` BIGINT COMMENT 'Foreign key linking to broadcast.live_feed. Business justification: Audience ratings measure viewership for a specific live feed. While audience_rating already links to broadcast_schedule, the direct link to live_feed enables feed-level audience measurement, supportin',
    `media_asset_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_asset. Business justification: audience_rating has asset_id → content.asset (cross-domain) but no FK to broadcast.media_asset. The in-domain media_asset contains broadcast-specific metadata (resolution, format, rights) needed for a',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to content.platform_channel. Business justification: Audience ratings are measured per delivery platform. Linking audience_rating to content.platform_channel enables platform-level ratings reporting, which is required for audience guarantee validation i',
    `ppv_package_id` BIGINT COMMENT 'Foreign key linking to broadcast.ppv_package. Business justification: audience_rating has ppv_event (BOOLEAN) flag indicating PPV measurement. Replacing this with a FK to ppv_package provides the specific PPV package context for audience measurement, enabling PPV revenu',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to partner.vendor_contract. Business justification: Audience measurement data is provided by third-party measurement vendors (e.g., Nielsen) under specific contracts. Linking enables contract-based data quality SLA enforcement, invoice validation, and ',
    `ama_viewers` BIGINT COMMENT 'Average Minute Audience — the average number of viewers watching at any given minute during the broadcast window. The industry-standard linear TV metric used for GRP (Gross Rating Point) calculation and advertiser CPM (Cost Per Mille) pricing.',
    `audience_guarantee_target` BIGINT COMMENT 'Contractually committed minimum audience size (total viewers) for this broadcast window as specified in the media rights or advertising agreement. Used for contractual audience guarantee reconciliation against actual total_viewers. Confidential as it reflects negotiated contract terms.',
    `avg_viewing_duration_mins` DECIMAL(18,2) COMMENT 'Average number of minutes each viewer spent watching the broadcast during the measurement window. Used for audience engagement analysis, content scheduling optimization, and streaming platform retention reporting.',
    `blackout_applied` BOOLEAN COMMENT 'Indicates whether a broadcast blackout rule was in effect for this territory during the measurement window. Blackout rules are contractual restrictions in media rights agreements that limit broadcast in specific markets. Affects audience measurement scope.',
    `broadcast_date` DATE COMMENT 'Calendar date of the broadcast window in yyyy-MM-dd format. Used for day-level scheduling analysis, weekly ratings aggregation, and contractual audience guarantee reconciliation.',
    `content_genre` STRING COMMENT 'Genre classification of the broadcast content (e.g., Live Sport, Sports News, Sports Documentary, Concert, Esports, Magazine Show). Used for scheduling optimization and audience segmentation analysis. [ENUM-REF-CANDIDATE: Live Sport|Sports News|Sports Documentary|Concert|Esports|Magazine Show|Highlights|Other — promote to reference product]',
    `cpm_rate` DECIMAL(18,2) COMMENT 'Cost Per Mille — the advertising rate charged per 1,000 viewers for this broadcast window, in the applicable currency. Used for advertiser rate card justification and media rights deal valuation. Confidential as it reflects negotiated commercial pricing.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this audience rating record was first ingested into the Silver Layer data product. Supports data lineage, audit trail, and SLA (Service Level Agreement) compliance for measurement data delivery.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to the CPM rate and any monetary values in this record (e.g., USD, GBP, EUR, AUD). Required for multi-territory rights valuation and financial reporting.. Valid values are `^[A-Z]{3}$`',
    `demo_age_band` STRING COMMENT 'Age band of the primary target demographic for this audience measurement record. Standard age groupings used by Nielsen and BARB for advertiser targeting and rate card segmentation (e.g., Adults 18-49 is the primary US broadcast demographic).. Valid values are `18-24|25-34|35-44|45-54|55-64|65+`',
    `demo_gender` STRING COMMENT 'Gender segment of the audience demographic breakdown for this measurement record. Used for targeted advertising rate card differentiation and sponsor demographic guarantee reporting.. Valid values are `Male|Female|All|Unknown`',
    `demo_income_band` STRING COMMENT 'Household income band of the measured audience segment (e.g., Under $50K, $50K-$100K, $100K-$150K, $150K+). Used for premium advertiser targeting and sponsorship package valuation. [ENUM-REF-CANDIDATE: Under $50K|$50K-$100K|$100K-$150K|$150K-$200K|$200K+ — promote to reference product]',
    `demo_viewers_count` BIGINT COMMENT 'Number of viewers within the specific demographic segment (age band, gender, income band) defined for this record. Enables granular demographic reporting for advertiser guarantee reconciliation.',
    `drm_protected` BOOLEAN COMMENT 'Indicates whether the broadcast content was delivered with DRM (Digital Rights Management) protection active during the measurement window. Relevant for OTT and IPTV platform compliance and piracy impact assessment on audience figures.',
    `frequency` DECIMAL(18,2) COMMENT 'Average number of times a unique viewer was exposed to the broadcast during the measurement period. Used alongside reach to calculate GRP (Gross Rating Point) and assess advertising campaign effectiveness.',
    `grp_value` DECIMAL(18,2) COMMENT 'Gross Rating Point value for this broadcast window, representing the sum of ratings across the target audience. Calculated as rating_pct multiplied by frequency. Primary currency for advertising inventory pricing and sponsorship valuation.',
    `guarantee_met` BOOLEAN COMMENT 'Indicates whether the actual audience (total_viewers) met or exceeded the contractual audience guarantee target for this broadcast window. Drives make-good advertising inventory decisions and rights agreement penalty calculations.',
    `live_viewers` BIGINT COMMENT 'Number of viewers who watched the broadcast in real-time (live) as opposed to time-shifted. Distinguishes live audience from time-shifted for PPV event reporting and live sports rights valuation.',
    `market_name` STRING COMMENT 'Name of the designated market area (DMA) or broadcast market within the territory (e.g., New York DMA, London ITV Region, Sydney Metro). Used for sub-national audience reporting and RSN rate card justification.',
    `measurement_methodology` STRING COMMENT 'The data collection methodology used by the measurement source. Panel-based (Nielsen People Meter, BARB panel) uses a representative sample; Census measures all streams; Hybrid combines panel and census; Modeled uses statistical estimation; Self-Reported uses platform-provided data.. Valid values are `Panel|Census|Hybrid|Modeled|Self-Reported`',
    `measurement_reference_code` STRING COMMENT 'Externally-known unique identifier assigned by the measurement provider (e.g., Nielsen panel ID, BARB survey code, OzTAM report reference, Comscore stream ID) for cross-system reconciliation.. Valid values are `^[A-Z0-9_-]{4,50}$`',
    `measurement_source` STRING COMMENT 'The third-party or internal system that provided the audience measurement data. Determines methodology, panel composition, and credibility for advertiser and rights negotiations. [ENUM-REF-CANDIDATE: Nielsen|BARB|OzTAM|Comscore|Internal Streaming Analytics|Other — promote to reference product if additional sources are onboarded]. Valid values are `Nielsen|BARB|OzTAM|Comscore|Internal Streaming Analytics|Other`',
    `measurement_status` STRING COMMENT 'Current lifecycle state of the audience rating record. Preliminary ratings are released within 24 hours; confirmed ratings are validated by the measurement provider; revised ratings incorporate late-reported data; final ratings are locked for contractual use; disputed ratings are under review.. Valid values are `preliminary|confirmed|revised|final|disputed`',
    `peak_concurrent_viewers` BIGINT COMMENT 'Maximum number of viewers simultaneously watching the broadcast at any single minute during the window. Key metric for streaming platform capacity planning, CDN (Content Delivery Network) provisioning, and PPV event valuation.',
    `rating_pct` DECIMAL(18,2) COMMENT 'Percentage of the total universe of TV households or individuals that watched the broadcast, regardless of whether their TV was on. Distinct from share_pct which is based only on those actively viewing. Used for GRP (Gross Rating Point) calculation.',
    `rating_type` STRING COMMENT 'Classification of the audience measurement metric captured in this record. GRP (Gross Rating Point) represents total delivery; CPM (Cost Per Mille) supports advertiser rate card justification; Reach measures unique audience; Frequency measures average exposures; AMA (Average Minute Audience) is the standard linear TV metric; Share is the percentage of viewing universe. [ENUM-REF-CANDIDATE: GRP|CPM|Reach|Frequency|Viewership|AMA|Share — promote to reference product]',
    `reach` BIGINT COMMENT 'Total number of unique individuals who viewed at least one minute of the broadcast during the measured window. Distinct from total_viewers which may count repeat viewing. Used for unduplicated audience reporting to sponsors and rights holders.',
    `reporting_period_type` STRING COMMENT 'Defines the time-shifted viewing window included in this measurement record per Nielsen and BARB standards. Live = real-time only; Live+1 includes same-day DVR; Live+3 includes 3-day playback; Live+7 includes 7-day playback; Live+35 is the C35 standard; VOD is on-demand only.. Valid values are `Live|Live+1|Live+3|Live+7|Live+35|VOD`',
    `share_pct` DECIMAL(18,2) COMMENT 'Percentage of the total viewing universe (all households/individuals with TV/streaming access) that watched this broadcast during the window. Expressed as a decimal percentage (e.g., 12.500 = 12.5%). Core metric for competitive scheduling analysis.',
    `sport_type` STRING COMMENT 'The sport or entertainment category of the broadcast content (e.g., NFL Football, NBA Basketball, FIFA Soccer, UFC MMA, Concert). Enables sport-specific audience trend analysis and rights valuation benchmarking. [ENUM-REF-CANDIDATE: NFL Football|NBA Basketball|MLB Baseball|NHL Hockey|MLS Soccer|FIFA Soccer|UFC MMA|Tennis|Concert|Other — promote to reference product]',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code identifying the geographic territory in which the audience measurement was conducted. Critical for regional rights valuation, blackout rule enforcement, and RSN (Regional Sports Network) reporting.. Valid values are `^[A-Z]{3}$`',
    `time_shifted_viewers` BIGINT COMMENT 'Number of viewers who watched the broadcast on a time-shifted basis (DVR, catch-up, VOD replay) within the measurement window. Reported separately per Nielsen Live+3 and Live+7 standards for contractual audience guarantee reconciliation.',
    `total_viewers` BIGINT COMMENT 'Total number of individual viewers who watched the broadcast during the measured window. The primary headline metric used in media rights negotiations, advertiser rate cards, and contractual audience guarantees.',
    `universe_size` BIGINT COMMENT 'Total size of the viewing universe (total TV households or individuals) used as the denominator for rating_pct and share_pct calculations in the given territory and demographic. Provided by the measurement source.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this audience rating record was last modified, typically when preliminary ratings are revised or confirmed by the measurement provider. Supports audit trail and revised-rating reconciliation workflows.',
    `window_end_timestamp` TIMESTAMP COMMENT 'The precise date and time when the measured broadcast window ended. Combined with window_start_timestamp to define the exact measurement interval for AMA and share calculations.',
    `window_start_timestamp` TIMESTAMP COMMENT 'The precise date and time when the measured broadcast window began, in ISO 8601 format with timezone offset. Used as the principal business event timestamp for scheduling optimization and rights valuation.',
    CONSTRAINT pk_audience_rating PRIMARY KEY(`audience_rating_id`)
) COMMENT 'Transactional record of broadcast audience measurement data per scheduled broadcast window. Captures channel, territory, measurement source (Nielsen, BARB, OzTAM, Comscore, internal streaming analytics), rating type (GRP, CPM, reach, frequency, viewership), total viewers, demographic breakdown (age, gender, income), peak concurrent viewers, average minute audience (AMA), share percentage, and time-shifted viewing. Operational data used for rights valuation, advertiser rate card justification, scheduling optimization, and contractual audience guarantee reconciliation.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`broadcast_ad_inventory` (
    `broadcast_ad_inventory_id` BIGINT COMMENT 'Unique surrogate identifier for each advertising inventory slot record in the broadcast ad inventory master catalog. Primary key for this entity.',
    `advertiser_id` BIGINT COMMENT 'Reference to the advertiser or brand that has purchased or is associated with this ad slot. Null when the slot is unsold or available inventory.',
    `broadcast_drm_policy_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_drm_policy. Business justification: broadcast_ad_inventory has drm_policy_code (STRING) which is a denormalized reference to the DRM policy governing ad delivery. Replacing with a FK to broadcast_drm_policy enables proper DRM enforcemen',
    `broadcast_schedule_id` BIGINT COMMENT 'Reference to the broadcast schedule window within which this advertising slot is allocated. Links the ad slot to its parent broadcast programming block.',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel or streaming platform on which this ad slot is available (e.g., linear TV network, OTT platform, IPTV service, RSN).',
    `asset_id` BIGINT COMMENT 'Reference to the digital creative asset (ad unit) trafficked into this slot, as managed in the Digital Asset Management (DAM) system. Null when slot is unsold.',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: Broadcast ad inventory slots are sold and allocated against sponsorship deals. Linking enables contracted vs. delivered inventory reconciliation per deal — a core billing and fulfillment process. No e',
    `digital_touchpoint_id` BIGINT COMMENT 'Foreign key linking to platform.digital_touchpoint. Business justification: Ad inventory slots are allocated per digital touchpoint for programmatic and direct ad sales. The plain delivery_platform column is a denormalized touchpoint reference. Linking enables touchpoint-leve',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Broadcast ad inventory generates advertising revenue mapped to finance revenue streams for advertising P&L reporting and budget vs. actuals. Finance tracks ad revenue by revenue stream for advertiser ',
    `sponsor_id` BIGINT COMMENT 'Reference to the advertiser or brand that has purchased or is associated with this ad slot. Null when the slot is unsold or available inventory.',
    `sponsorship_activation_id` BIGINT COMMENT 'Foreign key linking to sponsorship.activation. Business justification: Broadcast ad inventory slots are the physical delivery mechanism for sponsorship activations. Linking connects the broadcast-side slot record to the sponsorship activation it fulfills, enabling cross-',
    `sponsorship_ad_inventory_id` BIGINT COMMENT 'Foreign key linking to sponsorship.sponsorship_ad_inventory. Business justification: Broadcast ad inventory slots correspond to sponsorship ad inventory assets in the catalog. Linking connects the sold broadcast slot to the sponsorship asset it represents, enabling cross-domain invent',
    `actual_air_timestamp` TIMESTAMP COMMENT 'The confirmed date and time when this advertising slot actually aired, as recorded by the broadcast playout system. May differ from scheduled_air_timestamp due to live event overruns or schedule changes. Null until slot has aired.',
    `actual_cpm_achieved` DECIMAL(18,2) COMMENT 'The realized Cost Per Mille (CPM) rate in USD for this slot after execution, reflecting the contracted or programmatically cleared rate. Null until slot is sold. Used for revenue reporting and yield optimization analysis.',
    `ad_category` STRING COMMENT 'IAB content taxonomy category of the advertisers product or service (e.g., Automotive, Financial Services, Consumer Electronics). Used for competitive separation enforcement and category exclusivity validation. [ENUM-REF-CANDIDATE: automotive|financial-services|consumer-electronics|food-beverage|retail|telecom|healthcare|entertainment|sports|travel — promote to reference product]',
    `agency_commission_pct` DECIMAL(18,2) COMMENT 'Percentage of gross revenue payable to the advertising agency as commission for placing the buy. Standard industry rate is 15%. Used to calculate net revenue and accounts payable to agencies.',
    `audience_demographic_target` STRING COMMENT 'Primary audience demographic target for this ad slot as defined in the media plan (e.g., Adults 18-49, Males 25-54, Households). Used for audience delivery validation against Nielsen GRP guarantees and CPM pricing.',
    `blackout_applicable` BOOLEAN COMMENT 'Indicates whether broadcast blackout rules apply to this ad slot in the specified territory, restricting distribution based on media rights agreements. True = blackout rules apply; False = no blackout restriction. Critical for rights compliance.',
    `break_number` STRING COMMENT 'Sequential number of the commercial break within the broadcast window to which this slot belongs (e.g., Break 1, Break 2). Used for scheduling and trafficking coordination.',
    `cdn_delivery_endpoint` STRING COMMENT 'The Content Delivery Network (CDN) endpoint URL or identifier used to serve the ad creative for OTT and streaming platform delivery. Null for linear TV slots. Used by ad operations for trafficking and delivery verification.',
    `content_rating` STRING COMMENT 'Audience content rating of the broadcast window in which this ad slot appears, used to enforce advertiser brand safety requirements and regulatory compliance. Restricts certain ad categories from appearing in age-restricted content.. Valid values are `G|PG|PG-13|TV-14|TV-MA|R`',
    `cpm_floor_rate` DECIMAL(18,2) COMMENT 'Minimum acceptable Cost Per Mille (CPM) rate in USD for this advertising slot, below which the slot will not be sold. Set by revenue management based on platform, slot type, and audience reach. Used as the baseline for programmatic and direct sales negotiations.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this advertising inventory slot record was first created in the system, in ISO 8601 format with timezone offset. Used for audit trail, data lineage, and compliance reporting.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to CPM rates and revenue values for this slot (e.g., USD, GBP, EUR). Supports multi-territory revenue reporting and FX conversion.. Valid values are `^[A-Z]{3}$`',
    `gross_revenue_amount` DECIMAL(18,2) COMMENT 'Total gross revenue in the slot currency generated from the sale of this advertising slot, before agency commissions or discounts. Populated upon sale confirmation. Used for revenue recognition and financial reporting per SAP S/4HANA FI.',
    `grp_value` DECIMAL(18,2) COMMENT 'Gross Rating Point (GRP) value associated with this ad slot, representing the percentage of the target audience reached multiplied by frequency. Used for media planning, audience delivery validation, and make-good calculations.',
    `impressions_delivered` BIGINT COMMENT 'Actual number of audience impressions delivered for this slot as measured post-broadcast by audience measurement systems (e.g., Nielsen). Null until slot has aired. Compared against impressions_guaranteed for make-good liability assessment.',
    `impressions_guaranteed` BIGINT COMMENT 'The number of audience impressions contractually guaranteed to the advertiser for this slot, based on audience ratings projections (GRP-based). Used for make-good calculations if delivery falls short.',
    `is_makegood` BOOLEAN COMMENT 'Indicates whether this slot is a make-good placement issued to compensate an advertiser for under-delivery of impressions on a previously aired slot. True = make-good; False = standard placement. Tracked for liability management and client relations.',
    `is_programmatic` BOOLEAN COMMENT 'Indicates whether this slot was sold via programmatic advertising technology (e.g., programmatic direct, private marketplace) rather than direct sales. True = programmatic; False = direct/manual sale. Used for channel mix analysis and yield optimization.',
    `is_sold` BOOLEAN COMMENT 'Indicates whether this advertising slot has been sold to an advertiser. True = sold; False = available or unsold inventory. Primary flag for inventory availability dashboards and yield management reporting.',
    `is_sponsorship_exclusive` BOOLEAN COMMENT 'Indicates whether this slot carries a sponsorship exclusivity restriction, preventing competing brands in the same product category from advertising within the same broadcast window. True = exclusive; False = non-exclusive. Governed by sponsorship partnership agreements.',
    `market_region` STRING COMMENT 'Broadcast market or designated market area (DMA) name for this ad slot (e.g., New York DMA, Los Angeles DMA, UK National). Used for regional sales targeting and RSN-specific inventory management.',
    `net_revenue_amount` DECIMAL(18,2) COMMENT 'Net revenue in the slot currency after deducting agency commissions and applicable discounts from gross revenue. Used for P&L reporting, EBITDA calculation, and broadcast rights deal performance tracking.',
    `notes` STRING COMMENT 'Free-text operational notes entered by ad operations or sales teams regarding special instructions, client requests, competitive separation requirements, or trafficking exceptions for this slot.',
    `order_reference_number` STRING COMMENT 'The externally-known sales order or insertion order (IO) number from the advertiser or agency, as recorded in SAP S/4HANA SD. Links this slot to the commercial sales transaction for billing and revenue recognition.. Valid values are `^[A-Z0-9_-]{4,40}$`',
    `placement_timestamp` TIMESTAMP COMMENT 'Date and time when the advertiser creative was formally trafficked and placed into this slot by the ad operations team. Marks the transition from sold to trafficked status.',
    `sales_channel` STRING COMMENT 'The channel through which this ad slot was sold or allocated. Values: direct (direct sales team), programmatic (automated buying platform), agency (media agency buy), house (internal/house ad), barter (trade/barter arrangement). Used for revenue attribution and sales performance reporting.. Valid values are `direct|programmatic|agency|house|barter`',
    `scheduled_air_timestamp` TIMESTAMP COMMENT 'The planned broadcast date and time when this advertising slot is scheduled to air, expressed in ISO 8601 format with timezone offset. Principal business event timestamp for scheduling and trafficking workflows.',
    `slot_code` STRING COMMENT 'Externally-known alphanumeric business identifier for this advertising inventory slot, used in trafficking systems, sales orders, and agency communications (e.g., SLOT-ESPN-MR-001). Unique within a broadcast schedule.. Valid values are `^[A-Z0-9_-]{4,30}$`',
    `slot_duration_seconds` STRING COMMENT 'Length of the advertising slot in seconds. Standard broadcast durations include 15, 30, 60, and 90 seconds. Used for scheduling, pricing, and trafficking validation.',
    `slot_position` STRING COMMENT 'Ordinal position of this ad slot within its commercial break or content block (e.g., 1 = first position, 2 = second position). First and last positions typically command premium CPM rates.',
    `slot_status` STRING COMMENT 'Current lifecycle state of the advertising inventory slot. Drives revenue recognition, trafficking workflows, and inventory availability reporting. Values: available (open for sale), reserved (held pending contract), sold (contracted), trafficked (creative assigned and scheduled), aired (broadcast confirmed), cancelled (removed from schedule).. Valid values are `available|reserved|sold|trafficked|aired|cancelled`',
    `slot_type` STRING COMMENT 'Classification of the advertising slot by its position and format within the broadcast window. Drives pricing, trafficking rules, and CPM floor rates. Values: pre-roll (before content), mid-roll (during content break), post-roll (after content), billboard (opening/closing brand card), in-break (standard commercial break), sponsorship-billboard (branded segment opener/closer).. Valid values are `pre-roll|mid-roll|post-roll|billboard|in-break|sponsorship-billboard`',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code identifying the geographic territory in which this ad slot is broadcast or streamed. Governs blackout rules, rights restrictions, and regulatory compliance (e.g., GDPR for EU territories).. Valid values are `^[A-Z]{3}$`',
    `trafficking_confirmation_code` STRING COMMENT 'Unique confirmation code issued by the ad trafficking system (e.g., Dalet Galaxy or third-party ad server) upon successful scheduling of the creative asset into this slot. Serves as the operational proof of trafficking completion.. Valid values are `^[A-Z0-9_-]{4,40}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this advertising inventory slot record was last modified, in ISO 8601 format with timezone offset. Used for change tracking, data freshness monitoring, and audit compliance.',
    CONSTRAINT pk_broadcast_ad_inventory PRIMARY KEY(`broadcast_ad_inventory_id`)
) COMMENT 'Master catalog and transactional record of advertising inventory slots and their placements within broadcast windows across linear TV, OTT, and streaming platforms. Captures slot type (pre-roll, mid-roll, billboard, in-break), duration, broadcast schedule reference, channel, territory, CPM floor rate, sold status, sponsorship exclusivity flag, and for executed placements: advertiser, creative asset, placement datetime, actual CPM achieved, impressions delivered, and trafficking confirmation. SSOT for broadcast advertising inventory management and placement execution. Distinct from sponsorship domain brand activations.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`ad_placement` (
    `ad_placement_id` BIGINT COMMENT 'Unique surrogate identifier for each advertising placement transaction executed within a broadcast window. Primary key for the ad_placement data product.',
    `ad_inventory_slot_broadcast_ad_inventory_id` BIGINT COMMENT 'Reference to the specific ad inventory slot within the broadcast window that was allocated for this placement, defining the break position, pod number, and slot duration.',
    `advertiser_id` BIGINT COMMENT 'Reference to the advertiser (brand or agency) who purchased this ad placement. Links to the sponsorship/CRM domain for brand-level reporting and sponsor relationship management.',
    `broadcast_ad_inventory_id` BIGINT COMMENT 'Reference to the specific ad inventory slot within the broadcast window that was allocated for this placement, defining the break position, pod number, and slot duration.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to broadcast.channel. Business justification: An ad placement occurs on a specific broadcast channel. ad_placement has channel_code (STRING) which is a denormalized reference to the channel. Replacing with a FK to channel enables channel-level ad',
    `broadcast_schedule_id` BIGINT COMMENT 'Reference to the broadcast schedule window within which this ad placement was executed. Links the placement to the specific program, channel, and air date context.',
    `asset_id` BIGINT COMMENT 'Reference to the specific creative asset (video spot, audio tag, graphic overlay) delivered during this placement, managed within the Digital Asset Management (DAM) system.',
    `digital_touchpoint_id` BIGINT COMMENT 'Foreign key linking to platform.digital_touchpoint. Business justification: Ad placements are delivered on specific digital touchpoints. The plain platform_type column is a denormalized touchpoint classification. Linking to digital_touchpoint enables precise ad delivery attri',
    `live_feed_id` BIGINT COMMENT 'Foreign key linking to broadcast.live_feed. Business justification: An ad placement is inserted into a specific live feed. This FK links the placement to the actual feed being distributed, enabling feed-level ad insertion tracking, CDN delivery confirmation, and live ',
    `original_placement_ad_placement_id` BIGINT COMMENT 'Self-referencing identifier pointing to the original ad placement that this make-good placement is compensating for. Populated only when make_good_flag is True. Enables make-good chain tracking and fulfilment reconciliation.',
    `ppv_package_id` BIGINT COMMENT 'Foreign key linking to broadcast.ppv_package. Business justification: ad_placement has ppv_placement (BOOLEAN) flag indicating placement within a PPV event. Replacing with a FK to ppv_package provides the specific PPV package context, enabling PPV-specific ad revenue at',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Ad placements generate advertising revenue that must be attributed to finance revenue streams for period revenue reporting, make-good tracking, and advertiser billing reconciliation. Finance maps plac',
    `sponsor_id` BIGINT COMMENT 'Reference to the advertiser (brand or agency) who purchased this ad placement. Links to the sponsorship/CRM domain for brand-level reporting and sponsor relationship management.',
    `deal_id` BIGINT COMMENT 'Reference to the parent sponsorship or media rights deal under which this placement was contracted. Enables brand-level revenue roll-up and deal fulfilment tracking.',
    `actual_duration_seconds` STRING COMMENT 'Actual on-air duration of the advertisement in seconds as measured by the broadcast playout system. Compared against spot_duration_seconds to identify truncation or overrun events.',
    `ad_break_position` STRING COMMENT 'Sequential position number of the ad break within the broadcast program (e.g., 1 = pre-show, 2 = first in-game break). Used for pod sequencing, premium positioning pricing, and break-level performance analysis.',
    `ad_server_confirmation_code` STRING COMMENT 'Unique confirmation or transaction ID returned by the ad server upon successful delivery of the placement. Used for third-party verification, discrepancy resolution, and audit trail.',
    `agency_commission_amount` DECIMAL(18,2) COMMENT 'Commission amount payable to the advertising agency for brokering this placement, typically a percentage of gross revenue. Deducted to arrive at net revenue for financial reporting.',
    `audience_demographic_target` STRING COMMENT 'The target audience demographic segment specified in the media buy (e.g., Adults 18-49, Males 25-54). Used for audience guarantee tracking, make-good eligibility, and demographic-level yield reporting.',
    `blackout_applied` BOOLEAN COMMENT 'Indicates whether a geographic blackout rule was applied to this placement, restricting delivery in specific territories per broadcast rights agreements. Aligns with blackout rules defined in the broadcast schedule.',
    `cdn_delivery_profile` STRING COMMENT 'The CDN (Content Delivery Network) profile code used to deliver this ad creative to the end platform. Relevant for OTT and digital streaming placements; used for CDN cost allocation and delivery performance monitoring.. Valid values are `^[A-Z0-9_]{2,30}$`',
    `competitive_separation_flag` BOOLEAN COMMENT 'Indicates whether competitive separation rules were applied to this placement, preventing direct competitor advertisements from appearing in the same ad pod. Required for premium advertiser contract compliance.',
    `cpm_achieved` DECIMAL(18,2) COMMENT 'The actual CPM (Cost Per Mille) rate achieved for this placement based on verified impressions delivered. May differ from cpm_contracted due to audience delivery variances, make-good adjustments, or programmatic clearing prices.',
    `cpm_contracted` DECIMAL(18,2) COMMENT 'The agreed CPM (Cost Per Mille — cost per 1,000 impressions) rate as specified in the media buy contract. Used as the billing baseline and compared against cpm_achieved for yield analysis.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this ad placement record was first created in the system, in ISO 8601 format with timezone offset. Used for audit trail, data lineage, and SLA compliance tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this placement record (e.g., USD, GBP, EUR). Required for multi-territory revenue consolidation.. Valid values are `^[A-Z]{3}$`',
    `drm_policy_applied` BOOLEAN COMMENT 'Indicates whether a Digital Rights Management (DRM) policy was enforced during delivery of this placement, relevant for OTT and IPTV platforms where content protection rules govern ad insertion.',
    `gross_revenue_amount` DECIMAL(18,2) COMMENT 'Gross revenue value of this ad placement before agency commissions, discounts, or adjustments, calculated as (impressions_delivered / 1000) × cpm_achieved. Core revenue transaction amount for broadcast advertising monetization.',
    `grp_delivered` DECIMAL(18,2) COMMENT 'Gross Rating Points (GRP) delivered by this placement, representing reach multiplied by frequency within the target demographic. Standard broadcast advertising currency for campaign delivery measurement and make-good calculations.',
    `impressions_delivered` BIGINT COMMENT 'Total number of audience impressions delivered by this ad placement as measured or estimated by the audience measurement system. Core metric for CPM (Cost Per Mille) billing and campaign performance reporting.',
    `language_code` STRING COMMENT 'BCP 47 language code of the ad creative delivered (e.g., en-US, es-MX, fr-CA). Required for multi-language broadcast markets and localization compliance reporting.. Valid values are `^[a-z]{2,3}(-[A-Z]{2,3})?$`',
    `make_good_flag` BOOLEAN COMMENT 'Indicates whether this placement is a make-good (compensatory) spot issued to replace a previously failed, pre-empted, or under-delivered placement. Make-good placements are tracked separately for billing and fulfilment reporting.',
    `net_revenue_amount` DECIMAL(18,2) COMMENT 'Net revenue recognized for this placement after deducting agency commissions and applicable discounts from gross_revenue_amount. Used for P&L reporting and EBITDA calculation.',
    `placement_datetime` TIMESTAMP COMMENT 'The actual real-world timestamp at which the advertisement began airing within the broadcast window. This is the principal business event timestamp for the placement transaction, recorded in ISO 8601 format with timezone offset.',
    `placement_end_datetime` TIMESTAMP COMMENT 'The actual timestamp at which the advertisement finished airing. Used with placement_datetime to calculate actual on-air duration and verify against contracted spot length.',
    `placement_reference_code` STRING COMMENT 'Externally-known alphanumeric trafficking confirmation code assigned by the ad server or traffic management system (e.g., Dalet Galaxy or third-party ad server) uniquely identifying this placement for reconciliation with agency and advertiser systems.. Valid values are `^ADV-[A-Z0-9]{4,12}-[0-9]{6,10}$`',
    `placement_status` STRING COMMENT 'Current lifecycle state of the ad placement transaction. make_good indicates a compensatory placement issued to replace a previously failed or pre-empted spot. [ENUM-REF-CANDIDATE: scheduled|confirmed|delivered|failed|cancelled|make_good — promote to reference product if additional states are required]. Valid values are `scheduled|confirmed|delivered|failed|cancelled|make_good`',
    `placement_type` STRING COMMENT 'Classification of the advertising placement format. Distinguishes standard spots from sponsorship billboards, product integrations, lower-third overlays, ticker sponsorships, and interstitial placements. [ENUM-REF-CANDIDATE: spot|sponsorship_billboard|product_integration|lower_third|ticker|interstitial — promote to reference product if additional types are required]. Valid values are `spot|sponsorship_billboard|product_integration|lower_third|ticker|interstitial`',
    `pod_position` STRING COMMENT 'Sequential position of this advertisement within its ad pod (break). First position (1) and last position command premium pricing. Used for competitive separation enforcement and yield management.',
    `region_code` STRING COMMENT 'Sub-national or market region code (e.g., DMA code, RSN footprint region) within the territory where the placement aired. Supports regional sports network (RSN) audience segmentation and local advertiser reporting.. Valid values are `^[A-Z]{2,6}$`',
    `sales_channel` STRING COMMENT 'The sales channel through which this placement was transacted. Distinguishes direct sales, programmatic (automated auction), agency-brokered, house (internal promotional), and trade/barter placements for revenue mix reporting.. Valid values are `direct|programmatic|agency|house|trade`',
    `scheduled_placement_datetime` TIMESTAMP COMMENT 'The originally scheduled timestamp for the advertisement to air as defined in the traffic order. Compared against placement_datetime to identify pre-emptions, delays, or make-good scenarios.',
    `sport_type` STRING COMMENT 'The sport or entertainment category of the broadcast program context in which this placement aired (e.g., NFL, NBA, MLB, MLS, UFC, concert). Enables sport-vertical advertising revenue analysis and CPM benchmarking. [ENUM-REF-CANDIDATE: nfl|nba|mlb|nhl|mls|ufc|tennis|golf|concert|esports|other — promote to reference product]',
    `spot_duration_seconds` STRING COMMENT 'Contracted length of the advertisement spot in seconds (e.g., 15, 30, 60). Used for inventory valuation, billing reconciliation, and compliance with break duration limits.',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code identifying the geographic territory in which the advertisement was distributed. Critical for rights compliance, blackout enforcement, and territory-level revenue reporting.. Valid values are `^[A-Z]{3}$`',
    `trafficking_order_number` STRING COMMENT 'The traffic order number from the broadcast traffic management system (e.g., Dalet Galaxy) authorizing this placement. Used for operational reconciliation between sales, traffic, and finance systems.. Valid values are `^TRF-[A-Z0-9]{4,16}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this ad placement record, in ISO 8601 format with timezone offset. Used for change tracking, reconciliation workflows, and Silver layer incremental processing.',
    CONSTRAINT pk_ad_placement PRIMARY KEY(`ad_placement_id`)
) COMMENT 'Transactional record of each advertising placement executed within a broadcast window. Captures ad inventory slot reference, advertiser, creative asset, placement datetime, actual CPM achieved, impressions delivered, platform, territory, and trafficking confirmation. Core revenue transaction for broadcast advertising monetization. Integrates with sponsorship domain for brand-level reporting.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`sublicense_agreement` (
    `sublicense_agreement_id` BIGINT COMMENT 'Unique system-generated identifier for the sublicense agreement record. Primary key for the sublicense_agreement data product in the broadcast domain.',
    `blackout_rule_id` BIGINT COMMENT 'Reference to the blackout rule governing geographic or conditional broadcast restrictions applicable to this sublicense agreement. Enforces territorial exclusivity and league-mandated blackout obligations.',
    `broadcast_drm_policy_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_drm_policy. Business justification: A sublicense agreement requires broadcast-specific DRM protection governing how the sublicensee distributes content. sublicense_agreement has drm_policy_id → content.drm_policy (cross-domain) but no F',
    `broadcast_rights_window_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_rights_window. Business justification: A sublicense agreement grants secondary rights derived from a specific broadcast rights window. This FK links the sublicense to the parent rights window it sublicenses, enabling rights chain tracking,',
    `content_license_id` BIGINT COMMENT 'Foreign key linking to content.license. Business justification: A broadcast sublicense agreement is downstream of a content license. Legal teams must trace sublicense agreements back to the originating content license to verify sublicensing_permitted flag, territo',
    `corporate_entity_id` BIGINT COMMENT 'Reference to the third-party distributor, Regional Sports Network (RSN) affiliate, or international broadcaster receiving the sublicensed rights.',
    `digital_touchpoint_id` BIGINT COMMENT 'Foreign key linking to platform.digital_touchpoint. Business justification: Sublicense agreements grant rights for specific digital platforms. The plain platform_rights text field is a denormalized reference. Linking to digital_touchpoint enables rights compliance checks — ve',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: RSN sublicense agreements are granted for specific franchise territorial markets. Linking sublicense_agreement to the franchise whose territorial broadcast rights are being sublicensed is essential fo',
    `matter_id` BIGINT COMMENT 'Foreign key linking to legal.legal_matter. Business justification: Sublicense breaches, fee disputes, and territory violations generate formal legal matters. Legal teams track outside counsel spend and litigation risk against the originating sublicense agreement. Spo',
    `media_rights_deal_id` BIGINT COMMENT 'Reference to the primary media rights deal from which this sublicense is derived. Establishes the upstream rights chain for compliance and audit purposes.',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Sublicense agreements in regulated territories require regulatory notification or competition authority filings. The sublicense_agreement has governing_law_country_code, anti_piracy_obligations, a',
    `regulatory_license_id` BIGINT COMMENT 'Foreign key linking to legal.regulatory_license. Business justification: Sublicensees must hold valid broadcast regulatory licenses in their operating territory before a sublicense can be executed. Legal compliance teams verify license status as a condition precedent. This',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Sublicense fees are a distinct revenue stream (sublicensing income) tracked separately in finance for P&L and segment reporting. Finance maps each sublicense agreement to its revenue stream for sublic',
    `rights_clearance_id` BIGINT COMMENT 'Foreign key linking to content.rights_clearance. Business justification: Before executing a sublicense agreement, legal teams must verify the upstream content rights clearance authorizes sublicensing. The rights clearance record contains sublicensing_permitted flag and ter',
    `rights_holder_id` BIGINT COMMENT 'Foreign key linking to broadcast.rights_holder. Business justification: Sublicense agreements are granted by rights holders who own the original media rights. Every sublicense must reference the rights holder who authorized the sublicensing. This is a critical relationshi',
    `licensee_id` BIGINT COMMENT 'Foreign key linking to broadcast.licensee. Business justification: Sublicense agreements grant rights to sublicensees (who are licensees in the broader rights ecosystem). The sublicensee is the party receiving the sublicensed rights. Adding sublicensee_licensee_id (l',
    `vendor_id` BIGINT COMMENT 'Reference to the third-party distributor, Regional Sports Network (RSN) affiliate, or international broadcaster receiving the sublicensed rights.',
    `agreement_reference_code` STRING COMMENT 'Externally-known alphanumeric reference code assigned to this sublicense agreement, used in correspondence with the sublicensee and in SAP S/4HANA SD contract documents.. Valid values are `^SLA-[A-Z0-9]{4,20}$`',
    `agreement_status` STRING COMMENT 'Current lifecycle state of the sublicense agreement. Drives operational workflows including rights enforcement, billing, and blackout rule activation.. Valid values are `draft|pending_execution|active|suspended|terminated|expired`',
    `agreement_title` STRING COMMENT 'Descriptive title of the sublicense agreement, typically including the sublicensee name, territory, and content scope (e.g., RSN West Coast NFL Package 2024-2026).',
    `agreement_type` STRING COMMENT 'Classification of the sublicense arrangement by distribution channel. Distinguishes RSN affiliates, international broadcasters, Over-The-Top (OTT) platforms, Internet Protocol Television (IPTV) distributors, Pay-Per-View (PPV) packagers, and cable operators. [ENUM-REF-CANDIDATE: rsn_affiliate|international_broadcast|ott_platform|iptv_distributor|ppv_packager|cable_operator|dtc_streaming|free_to_air — promote to reference product]. Valid values are `rsn_affiliate|international_broadcast|ott_platform|iptv_distributor|ppv_packager|cable_operator`',
    `anti_piracy_obligations` BOOLEAN COMMENT 'Indicates whether the sublicense agreement includes specific anti-piracy and Intellectual Property (IP) protection obligations binding on the sublicensee, such as watermarking, geo-blocking, and DRM enforcement.',
    `auto_renewal_flag` BOOLEAN COMMENT 'Indicates whether the sublicense agreement automatically renews at expiry unless either party provides notice of termination. Triggers renewal workflow alerts in contract management.',
    `content_rights_type` STRING COMMENT 'Classification of the content rights granted: live broadcast, replay/time-shifted, highlights packages, all rights, or video-on-demand (VOD) only. Determines permissible use by the sublicensee.. Valid values are `live|replay|highlights|all_rights|vod_only`',
    `content_scope_description` STRING COMMENT 'Narrative description of the specific content rights granted under this sublicense, including leagues, sports, events, or content packages covered (e.g., All regular season NFL games excluding playoffs).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the sublicense agreement record was first created in the system. Supports audit trail requirements under SOX and GDPR data governance obligations.',
    `dispute_resolution_mechanism` STRING COMMENT 'Contractually agreed mechanism for resolving disputes arising under this sublicense agreement. CAS arbitration is standard for international sports rights agreements.. Valid values are `arbitration|litigation|mediation|expert_determination`',
    `effective_from` DATE COMMENT 'Date on which the sublicense agreement becomes legally binding and rights are granted to the sublicensee. Aligns with the rights window start in the parent media rights deal.',
    `effective_until` DATE COMMENT 'Date on which the sublicense agreement expires and rights revert. Nullable for open-ended arrangements. Must not exceed the parent rights deal expiry.',
    `exclusivity_type` STRING COMMENT 'Indicates whether the sublicense grants exclusive, non-exclusive, or first-window exclusive rights within the defined territory and platform. Exclusive rights prevent Sports Entertainment from granting the same rights to another party.. Valid values are `exclusive|non_exclusive|first_window_exclusive`',
    `execution_date` DATE COMMENT 'Date on which the sublicense agreement was formally signed and executed by all parties. May differ from effective_from for agreements signed in advance.',
    `fee_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the sublicense fee and revenue share amounts (e.g., USD, GBP, EUR). Required for multi-territory international sublicense agreements.. Valid values are `^[A-Z]{3}$`',
    `fee_payment_schedule` STRING COMMENT 'Frequency or structure of sublicense fee payments from the sublicensee. Drives accounts receivable scheduling in SAP S/4HANA and financial planning in Workday Adaptive Planning.. Valid values are `annual|semi_annual|quarterly|monthly|lump_sum|per_event`',
    `governing_law_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the jurisdiction whose laws govern this sublicense agreement. Determines applicable regulatory frameworks including GDPR, CCPA, and local broadcast regulations.. Valid values are `^[A-Z]{3}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the sublicense agreement record. Supports change tracking, audit compliance, and Silver layer data lineage in the Databricks Lakehouse.',
    `league_code` STRING COMMENT 'Code identifying the sports league or governing body whose content is covered by this sublicense (e.g., NFL, NBA, MLB, NHL, MLS, FIFA). Drives league-specific compliance obligations.',
    `minimum_guarantee_amount` DECIMAL(18,2) COMMENT 'Minimum guaranteed payment amount the sublicensee must remit regardless of actual viewership or revenue performance. Provides revenue floor protection for Sports Entertainment.',
    `platform_rights` STRING COMMENT 'Distribution platforms on which the sublicensee is authorized to broadcast content. Covers linear TV, Over-The-Top (OTT), Internet Protocol Television (IPTV), mobile, or combinations thereof.. Valid values are `linear_tv|ott|iptv|mobile|all_platforms|linear_and_ott`',
    `renewal_notice_days` STRING COMMENT 'Number of calendar days prior to expiry by which either party must provide written notice of non-renewal or termination. Drives automated contract management alerts.',
    `reporting_frequency` STRING COMMENT 'Frequency at which the sublicensee must submit viewership, ratings, or revenue compliance reports. Applicable only when sublicensee_reporting_required is true.. Valid values are `monthly|quarterly|semi_annual|annual|per_event`',
    `revenue_share_pct` DECIMAL(18,2) COMMENT 'Percentage of the sublicensees downstream revenue that is remitted to Sports Entertainment as a revenue share component, in addition to or in lieu of a fixed sublicense fee. Expressed as a percentage (e.g., 15.00 = 15%).',
    `sport_type` STRING COMMENT 'Sport category covered by the sublicense agreement (e.g., American Football, Basketball, Baseball, Soccer, Hockey). Supports cross-sport analytics and rights portfolio management.',
    `sublicense_fee` DECIMAL(18,2) COMMENT 'Total contracted sublicense fee payable by the sublicensee to Sports Entertainment for the rights granted under this agreement. Represents the gross rights fee before any revenue share adjustments.',
    `sublicense_fee_paid_to_date` DECIMAL(18,2) COMMENT 'Cumulative sublicense fee amount received from the sublicensee as of the most recent payment posting in SAP S/4HANA AR. Supports revenue recognition and accounts receivable monitoring.',
    `sublicense_notes` STRING COMMENT 'Free-text field for capturing material deal-specific terms, special conditions, side letters, or compliance obligations not captured in structured fields. Reviewed during contract audits.',
    `sublicense_term_years` DECIMAL(18,2) COMMENT 'Duration of the sublicense agreement expressed in years. Supports rights portfolio planning, renewal forecasting, and Workday Adaptive Planning financial projections.',
    `sublicensee_reporting_required` BOOLEAN COMMENT 'Indicates whether the sublicensee is contractually obligated to provide viewership, ratings, or revenue reports to Sports Entertainment. Drives compliance monitoring workflows.',
    `sublicensor_entity_code` STRING COMMENT 'SAP company code identifying the Sports Entertainment legal entity acting as sublicensor under this agreement. Required for intercompany settlement and SOX financial controls.',
    `termination_date` DATE COMMENT 'Actual date on which the sublicense agreement was terminated prior to its scheduled expiry, if applicable. Null for agreements that run to their natural term.',
    `termination_reason` STRING COMMENT 'Reason code for early termination of the sublicense agreement. Supports rights reversion workflows and legal dispute tracking.. Valid values are `breach|mutual_agreement|regulatory|insolvency|rights_reversion|force_majeure`',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code identifying the primary territory in which the sublicensee is granted broadcast rights. Used for blackout rule enforcement and rights compliance.. Valid values are `^[A-Z]{3}$`',
    `territory_scope` STRING COMMENT 'Geographic breadth of the sublicensed rights within the designated territory. Distinguishes national, regional, local, international, and global distribution rights.. Valid values are `national|regional|local|international|global`',
    CONSTRAINT pk_sublicense_agreement PRIMARY KEY(`sublicense_agreement_id`)
) COMMENT 'Master record of sublicensing arrangements where Sports Entertainment grants secondary broadcast rights to third-party distributors, RSN affiliates, or international broadcasters derived from primary media rights deals. Captures parent rights deal, sublicensee, territory, content scope, sublicense fee, revenue share, term, and compliance obligations. Distinct from the primary media_rights_deal as it represents a downstream rights grant.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`rights_royalty` (
    `rights_royalty_id` BIGINT COMMENT 'Unique surrogate identifier for each royalty or rights fee payment record under a media rights deal or sublicense agreement. Primary key for the rights_royalty transactional entity.',
    `ap_invoice_id` BIGINT COMMENT 'Reference to the accounts receivable or accounts payable invoice generated for this royalty payment in the SAP S/4HANA FI module. Links the royalty record to the formal billing document.',
    `broadcast_rights_window_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_rights_window. Business justification: Rights royalty payments are calculated based on specific broadcast rights windows. Linking rights_royalty to broadcast_rights_window enables window-level royalty calculation, rights fee allocation tra',
    `content_drm_policy_id` BIGINT COMMENT 'Reference to the DRM policy governing the content distribution rights for which this royalty is being paid. Ensures royalty records are traceable to the specific DRM enforcement framework.',
    `content_license_id` BIGINT COMMENT 'Foreign key linking to content.license. Business justification: Royalty calculations are governed by content license terms (royalty_rate, revenue_share_pct, fee_structure). Finance teams need to link royalty records to the content license for accurate royalty comp',
    `corporate_entity_id` BIGINT COMMENT 'Reference to the business partner — broadcaster, RSN, OTT platform, or sublicensee — who owes or receives this royalty payment. Serves as the PARTY_REFERENCE for this transaction.',
    `cost_center_id` BIGINT COMMENT 'Reference to the SAP cost center responsible for this royalty transaction, enabling broadcast rights cost and revenue allocation by organizational unit.',
    `gl_account_id` BIGINT COMMENT 'Reference to the GL account in the chart of accounts to which this royalty revenue or expense is posted. Ensures correct financial statement classification for broadcast rights revenue recognition.',
    `matter_id` BIGINT COMMENT 'Foreign key linking to legal.legal_matter. Business justification: Royalty underpayment disputes, calculation disagreements, and withholding tax controversies generate formal legal matters. Legal and finance teams co-manage these disputes and need to link royalty rec',
    `media_rights_deal_id` BIGINT COMMENT 'Reference to the parent media rights agreement or sublicense deal under which this royalty obligation arises. Links to the master rights agreement record.',
    `licensee_id` BIGINT COMMENT 'Foreign key linking to broadcast.licensee. Business justification: Rights royalty payments are typically paid by licensees who are using the licensed content. Adding payer_licensee_id (labeled to indicate the paying party) enables tracking which licensee is responsib',
    `profit_center_id` BIGINT COMMENT 'Reference to the SAP profit center for P&L reporting of this royalty transaction. Supports EBITDA reporting by broadcast business unit.',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Royalty receipts and payments must be categorized by revenue stream for financial reporting and rights revenue analysis. Finance maps royalty records to revenue streams for sublicensing income trackin',
    `rights_clearance_id` BIGINT COMMENT 'Foreign key linking to content.rights_clearance. Business justification: Royalty calculations must be traced to the underlying content rights clearance to verify royalty_rate_percent, territory scope, and platform scope. Finance and rights teams require this link for royal',
    `rights_holder_id` BIGINT COMMENT 'Foreign key linking to broadcast.rights_holder. Business justification: Rights royalty payments are made to or received from rights holders. Every royalty transaction must identify the rights holder involved in the payment. This is essential for financial reconciliation a',
    `sublicense_agreement_id` BIGINT COMMENT 'Reference to the sublicense agreement if this royalty is generated under a sublicensed rights arrangement rather than a primary deal. Null when the royalty is directly under the primary rights deal.',
    `sublicense_sublicense_agreement_id` BIGINT COMMENT 'Reference to the sublicense agreement if this royalty is generated under a sublicensed rights arrangement rather than a primary deal. Null when the royalty is directly under the primary rights deal.',
    `tax_jurisdiction_id` BIGINT COMMENT 'Foreign key linking to finance.tax_jurisdiction. Business justification: Cross-border royalty payments are subject to withholding tax rates that vary by jurisdiction and tax treaty. Finance requires tax_jurisdiction linkage on royalty records for withholding tax calculatio',
    `vendor_id` BIGINT COMMENT 'Reference to the business partner — broadcaster, RSN, OTT platform, or sublicensee — who owes or receives this royalty payment. Serves as the PARTY_REFERENCE for this transaction.',
    `adjustment_amount` DECIMAL(18,2) COMMENT 'Net value of all adjustments applied to the calculated royalty, including credits, deductions, make-goods, or corrections from prior periods. Negative values represent deductions; positive values represent additions.',
    `approval_date` DATE COMMENT 'Date on which the royalty record was formally approved by the authorized finance officer. Required for SOX compliance and audit trail completeness.',
    `approved_by` STRING COMMENT 'Name or user ID of the finance or rights management officer who approved this royalty calculation and payment record. Required for SOX dual-control compliance on material financial transactions.',
    `audit_trail_notes` STRING COMMENT 'Free-text field capturing material adjustments, manual overrides, reconciliation comments, or compliance notes associated with this royalty record. Supports SOX audit trail requirements and internal review processes.',
    `calculated_royalty_amount` DECIMAL(18,2) COMMENT 'Gross royalty amount computed per the contractual formula for the payment period, before any adjustments, deductions, or withholding tax. This is the base amount used for invoicing and revenue recognition.',
    `content_category` STRING COMMENT 'Category of broadcast content covered by this royalty payment. Rights agreements often specify different royalty rates for live events versus replay or highlight packages. [ENUM-REF-CANDIDATE: live_event|replay|highlights|documentary|magazine_show|ppv_event — promote to reference product]. Valid values are `live_event|replay|highlights|documentary|magazine_show|ppv_event`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this royalty record was first created in the system. Serves as the RECORD_AUDIT_CREATED marker for the transaction lifecycle and supports data lineage tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the royalty amounts are denominated (e.g., USD, GBP, EUR). Determines the currency for invoicing, payment, and GL posting.. Valid values are `^[A-Z]{3}$`',
    `dispute_reference` STRING COMMENT 'Reference number or identifier for any formal dispute raised against this royalty record by either party. Populated when reconciliation_status is exception or royalty_status is disputed. Links to the dispute management workflow.',
    `distribution_platform` STRING COMMENT 'The media distribution platform or channel type for which this royalty is being calculated. Differentiates royalty streams by platform as rights deals often carry platform-specific rates. [ENUM-REF-CANDIDATE: linear_tv|rsn|ott|iptv|ppv|dtc|digital|radio — promote to reference product]',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Foreign exchange rate applied to convert the royalty amount from the contract currency to the functional reporting currency (USD) at the time of calculation or payment. Sourced from SAP FI exchange rate tables.',
    `functional_currency_amount` DECIMAL(18,2) COMMENT 'Net royalty amount converted to the company functional currency (USD) using the applicable exchange rate. Used for consolidated financial reporting and GL posting in the finance domain.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this royalty record, including status changes, amount adjustments, or reconciliation updates. Serves as the RECORD_AUDIT_UPDATED marker.',
    `late_payment_penalty_amount` DECIMAL(18,2) COMMENT 'Penalty amount assessed for late payment of the royalty, calculated per the contractual penalty clause. Zero if payment was made on or before the due date. Feeds into partner settlement and dispute management.',
    `league_code` STRING COMMENT 'Code identifying the sports league or competition whose content is covered by this royalty (e.g., NFL, NBA, MLB, NHL, MLS, FIFA). Used for league-level royalty reporting and CBA compliance tracking.. Valid values are `^[A-Z0-9]{2,10}$`',
    `minimum_guarantee_amount` DECIMAL(18,2) COMMENT 'Contractual minimum royalty floor amount for the payment period, regardless of actual performance metrics. If the calculated royalty falls below this threshold, the minimum guarantee applies. Null if no minimum guarantee is stipulated.',
    `net_royalty_amount` DECIMAL(18,2) COMMENT 'Final net amount due or received after applying adjustments and withholding tax deductions to the calculated royalty amount. This is the amount posted to the general ledger and used for partner settlement.',
    `payment_direction` STRING COMMENT 'Indicates whether this royalty record represents an amount owed TO Sports Entertainment (receivable, e.g., from a sublicensee) or an amount owed BY Sports Entertainment (payable, e.g., to a rights holder). Critical for GL posting logic.. Valid values are `receivable|payable`',
    `payment_due_date` DATE COMMENT 'Contractually agreed date by which the royalty payment must be received or remitted. Drives accounts receivable aging and late-payment penalty calculations.',
    `payment_method` STRING COMMENT 'Method by which the royalty payment is remitted or received (e.g., wire transfer, ACH, check, direct debit, or offset against a payable). Used for treasury and cash management reporting.. Valid values are `wire_transfer|ach|check|direct_debit|offset`',
    `payment_period_end_date` DATE COMMENT 'Last day of the royalty calculation period for which this payment obligation is computed. Together with payment_period_start_date defines the billing window.',
    `payment_period_start_date` DATE COMMENT 'First day of the royalty calculation period (e.g., monthly, quarterly) for which this payment obligation is computed. Used for revenue recognition period alignment.',
    `payment_received_date` DATE COMMENT 'Actual date on which the royalty payment was received and cleared in the financial system. Null if payment has not yet been received. Used for days-outstanding and cash flow reporting.',
    `reconciliation_status` STRING COMMENT 'Status of the reconciliation process between the calculated royalty amount and the actual payment received. Supports the broadcast rights revenue reconciliation workflow and partner settlement sign-off.. Valid values are `unreconciled|in_review|reconciled|exception`',
    `reporting_period_label` STRING COMMENT 'Human-readable label for the financial reporting period covered by this royalty (e.g., Q1-2025, JAN-2025, FY2025). Used for financial reporting, EBITDA analysis, and regulatory filings.. Valid values are `^(Q[1-4]-[0-9]{4}|[A-Z]{3}-[0-9]{4}|FY[0-9]{4})$`',
    `rights_territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code identifying the geographic territory for which this royalty payment applies. Supports multi-territory rights deals where royalties are tracked per territory.. Valid values are `^[A-Z]{3}$`',
    `royalty_basis_value` DECIMAL(18,2) COMMENT 'The underlying metric value on which the royalty is calculated, such as total subscriber count, gross revenue, PPV buy rate, or viewership impressions for the payment period. Provides audit trail for royalty computation.',
    `royalty_rate` DECIMAL(18,2) COMMENT 'Contractual rate applied to the royalty basis value to compute the calculated royalty amount. Expressed as a percentage (e.g., 0.125000 = 12.5%) for revenue-share types, or as a per-unit fee for per-subscriber or per-view types.',
    `royalty_rate_unit` STRING COMMENT 'Unit of measure for the royalty rate, indicating how the rate is applied to the basis value. Determines the calculation formula used in the royalty engine.. Valid values are `percentage|per_subscriber|per_view|per_impression|fixed`',
    `royalty_reference_number` STRING COMMENT 'Externally-known business identifier for this royalty payment record, used in partner settlement communications, remittance advices, and reconciliation with counterparty systems. Follows the format RR-YYYY-NNNNNN.. Valid values are `^RR-[0-9]{4}-[0-9]{6}$`',
    `royalty_status` STRING COMMENT 'Current lifecycle state of the royalty payment record. Drives workflow routing, collections activity, and financial reporting. [ENUM-REF-CANDIDATE: calculated|invoiced|disputed|paid|overdue|cancelled|written_off — promote to reference product]',
    `royalty_type` STRING COMMENT 'Classification of the royalty calculation methodology as defined in the rights agreement. Determines how the royalty amount is computed. [ENUM-REF-CANDIDATE: flat_fee|revenue_share|per_subscriber|per_view|minimum_guarantee|overage — promote to reference product]. Valid values are `flat_fee|revenue_share|per_subscriber|per_view|minimum_guarantee|overage`',
    `sport_type` STRING COMMENT 'Type of sport associated with the content covered by this royalty payment (e.g., American Football, Basketball, Baseball, Soccer, Hockey). Supports cross-sport royalty analytics and reporting.',
    `withholding_tax_amount` DECIMAL(18,2) COMMENT 'Amount of withholding tax deducted from the royalty payment as required by applicable tax treaties or local tax regulations for cross-border rights payments. Zero for domestic transactions where withholding does not apply.',
    CONSTRAINT pk_rights_royalty PRIMARY KEY(`rights_royalty_id`)
) COMMENT 'Transactional record of royalty and rights fee payments due or received under media rights deals and sublicense agreements. Captures rights deal or sublicense reference, payment period, calculated royalty amount, currency, payment due date, payment received date, and reconciliation status. Core financial transaction for broadcast rights revenue recognition and partner settlement. Feeds finance domain general ledger.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`rights_agreement` (
    `rights_agreement_id` BIGINT COMMENT 'Primary key for the broadcast_rights_agreement association',
    `channel_id` BIGINT COMMENT 'Foreign key linking this rights agreement to the specific broadcast channel authorized to carry the league content.',
    `league_id` BIGINT COMMENT 'Foreign key linking this rights agreement to the specific league whose content is being distributed under this agreement.',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Rights agreements (association between channel and league) are typically derived from or implement underlying media rights deals. Adding media_rights_deal_id enables tracking which master deal governs',
    `broadcast_rights_tier` STRING COMMENT 'Classification of the leagues broadcast rights value tier, used to categorize RSN (Regional Sports Network), national, and OTT (Over-The-Top Streaming) rights packaging. Drives revenue forecasting, CPM rate card setting, and DTC platform strategy. [Moved from league: The league-level broadcast_rights_tier is a summary/default classification, but the actual rights tier is per-channel-per-league agreement and varies by channel, territory, and exclusivity. The authoritative value belongs on the association as rights_tier. The league-level attribute may be retained as a summary/default but should not be the system of record.]. Valid values are `tier_1|tier_2|tier_3|regional|local`',
    `effective_from` DATE COMMENT 'Calendar date on which this channel-league broadcast rights agreement becomes active and the channel is authorized to distribute league content. Belongs to the agreement, not to either entity alone.',
    `effective_until` DATE COMMENT 'Calendar date on which this channel-league broadcast rights agreement expires or is scheduled to terminate. Drives rights window enforcement, blackout logic, and renewal workflows.',
    `exclusivity_type` STRING COMMENT 'Defines whether this channel holds exclusive rights to broadcast the league within the agreed territory and window, or whether other channels may simultaneously carry the same content. A core contractual term that belongs to the agreement itself.',
    `primary_flag` BOOLEAN COMMENT 'Indicates whether this channel is the primary (flagship) broadcast partner for this league within the agreed territory. A league may have multiple channels but only one primary partner per territory. Belongs to the agreement, not to the channel or league independently.',
    `rights_tier` STRING COMMENT 'Classification of the broadcast rights value tier for this specific channel-league agreement. Determines revenue sharing, production obligations, and promotional commitments. Belongs to the agreement, not to the channel or league independently.',
    `rights_window_end` DATE COMMENT 'End date of the current media rights window during which this channel is authorized to distribute content. Nullable for perpetual or open-ended rights. Critical for rights expiry alerting and contract renewal workflows. [Moved from channel: Same reasoning as rights_window_start — the per-league rights expiry belongs on the association as effective_until, not as a single value on the channel master record.]',
    `rights_window_start` DATE COMMENT 'Start date of the current media rights window during which this channel is authorized to distribute content. Aligns with the rights agreement effective period. Used for rights compliance monitoring and revenue recognition. [Moved from channel: This attribute on the channel represents a channel-level default rights window, but the operationally meaningful rights window is per-channel-per-league agreement. The per-agreement effective_from on the association supersedes this. If the channel has a single global rights window independent of any league, it may remain on the channel; however, if it was intended to capture league-specific rights start dates, it belongs on the association as effective_from.]',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code or structured region code defining the geographic territory within which this channel is authorized to broadcast the league under this agreement. Distinct from the channels general geographic_coverage — this is the rights-specific territory.',
    CONSTRAINT pk_rights_agreement PRIMARY KEY(`rights_agreement_id`)
) COMMENT 'This association product represents the Contract between a broadcast channel and a league governing the rights to distribute league content. It captures the operational terms of each channel-league broadcast rights deal — including rights tier, exclusivity, territory, and effective dates — that exist only in the context of this specific channel-league pairing. Each record is a discrete, actively managed rights agreement that the business creates, renegotiates, and terminates as part of its media rights operations.. Existence Justification: In sports entertainment, a single broadcast channel (e.g., ESPN) simultaneously carries multiple leagues (NFL, NBA, MLB), and a single league (e.g., NFL) is distributed across multiple channels (ESPN, Fox, NBC, CBS) under distinct rights agreements. The business actively manages these channel-league broadcast rights relationships as named contracts with their own attributes — rights tier, exclusivity type, territory, and effective dates — that belong to neither the channel nor the league alone. This is a genuine operational M:N where rights deals are created, renegotiated, and terminated as discrete business events.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`platform_rights_grant` (
    `platform_rights_grant_id` BIGINT COMMENT 'Primary key for the platform_rights_grant association',
    `broadcast_rights_window_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_rights_window. Business justification: Platform rights grants (linking media_rights_deal to digital_touchpoint) may be scoped to specific broadcast rights windows for granular rights management. Adding broadcast_rights_window_id enables tr',
    `digital_touchpoint_id` BIGINT COMMENT 'Foreign key linking to the digital touchpoint authorized to deliver content under the rights deal.',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to the media rights deal that grants the platform-level rights authorization.',
    `effective_from` DATE COMMENT 'The date on which this platform-level rights authorization becomes active. May differ from the parent deals effective_date if the touchpoint was added mid-deal.',
    `effective_until` DATE COMMENT 'The date on which this platform-level rights authorization expires. May differ from the parent deals expiry_date if the touchpoint authorization is terminated early.',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether the rights granted to this specific digital touchpoint are exclusive within the deals territory scope. Exclusivity may differ per touchpoint even within the same deal.',
    `grant_status` STRING COMMENT 'Current operational status of this platform rights authorization. Allows rights operations to suspend or terminate a specific touchpoints authorization without affecting the parent deal or other touchpoint grants.',
    `platform_rights_type` STRING COMMENT 'The category of rights granted to this specific digital touchpoint under this deal (e.g., live streaming, replay, highlights). A deal may grant live rights to the OTT app but only highlights rights to the web portal.',
    `revenue_share_pct` DECIMAL(18,2) COMMENT 'The revenue share percentage applicable to content delivered through this specific digital touchpoint under this deal. Per-platform revenue share terms may differ from the deal-level revenue_share_pct on the parent media_rights_deal.',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 territory code specifying the geographic scope of the rights grant for this specific touchpoint. A deal covering multiple territories may authorize different touchpoints per territory.',
    CONSTRAINT pk_platform_rights_grant PRIMARY KEY(`platform_rights_grant_id`)
) COMMENT 'This association product represents the Contract between media_rights_deal and digital_touchpoint. It captures the formal authorization granting a specific digital touchpoint the right to deliver content under a specific media rights deal, including the platform-level rights type, exclusivity terms, effective period, territory scope, and revenue share applicable to that specific deal-touchpoint combination. Each record links one media_rights_deal to one digital_touchpoint with attributes that exist only in the context of this per-platform rights authorization.. Existence Justification: A media rights deal licenses content delivery rights to multiple digital touchpoints simultaneously (e.g., an NFL deal may cover the OTT app, web portal, and IPTV endpoint under different terms), and each digital touchpoint can be covered by multiple rights deals across different sports, leagues, and territories. The business actively manages which touchpoints are authorized to deliver which rights, with per-touchpoint exclusivity flags, territory scopes, and revenue share terms that belong neither to the deal nor the touchpoint alone. This is a recognized operational concept in broadcast rights licensing — the authorization or platform rights grant — that rights operations teams create, update, and enforce.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`rights_window_channel_authorization` (
    `rights_window_channel_authorization_id` BIGINT COMMENT 'Primary key for the rights_window_channel_authorization association',
    `broadcast_drm_policy_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_drm_policy. Business justification: Rights window channel authorizations enforce DRM policies for content protection. The authorization currently has drm_policy_code (STRING) but should reference the broadcast_drm_policy table for full ',
    `broadcast_rights_window_id` BIGINT COMMENT 'Foreign key linking to the broadcast rights window that grants the distribution authorization',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to the platform channel authorized to distribute content under this rights window',
    `authorization_end` TIMESTAMP COMMENT 'The date and time at which this channel authorization expires. May align with or precede the parent rights window end, supporting early termination of a specific channels authorization without affecting the broader window.',
    `authorization_start` TIMESTAMP COMMENT 'The date and time from which this channel authorization is effective. May align with or be a subset of the parent rights window start, allowing phased channel rollouts within a single rights window.',
    `authorization_status` STRING COMMENT 'Current lifecycle state of this specific channel authorization. Drives whether the platform channel is permitted to distribute content under this rights window at any given moment.',
    `concurrent_stream_limit` STRING COMMENT 'Maximum number of simultaneous streams permitted on this platform channel under this specific rights window. This is a per-authorization term that may differ from the channels default concurrent_stream_limit, representing negotiated terms for this window-channel combination. Sourced from detection phase relationship data.',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether the rights granted under this window are exclusive to this specific platform channel. Belongs to the authorization record because exclusivity is a per-channel-window term, not a property of the window or channel alone. Sourced from detection phase relationship data.',
    `platform_type` STRING COMMENT 'The distribution platform category for which this rights window is valid. Distinguishes between linear TV, OTT (Over-The-Top Streaming), IPTV (Internet Protocol Television), PPV (Pay-Per-View), DTC (Direct-To-Consumer), RSN (Regional Sports Network), digital streaming, and radio. [ENUM-REF-CANDIDATE: linear_tv|ott|iptv|ppv|dtc|rsn|digital_streaming|radio — promote to reference product] [Moved from broadcast_rights_window: platform_type on broadcast_rights_window is a string classification (e.g., OTT, IPTV) that was used as a proxy for channel targeting in the absence of a proper association table. With the rights_window_channel_authorization in place, the specific platform channel is identified via FK to platform_channel, making the string-based platform_type on the window redundant for routing purposes. However, platform_type may be retained on broadcast_rights_window as a broad classification of the intended platform class for the window overall — this is a judgment call for the rights operations team.]',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code defining the geographic territory in which this specific channel is authorized under this rights window. May differ from the window-level territory scope when sub-territorial authorizations are issued. Sourced from detection phase relationship data.',
    CONSTRAINT pk_rights_window_channel_authorization PRIMARY KEY(`rights_window_channel_authorization_id`)
) COMMENT 'This association product represents the Contract between broadcast_rights_window and platform_channel. It captures the formal authorization record that grants a specific platform channel the right to distribute content under a specific broadcast rights window, including the technical compliance terms, exclusivity scope, DRM requirements, and stream limits that govern that specific channel-window combination. Each record links one broadcast_rights_window to one platform_channel with attributes that exist only in the context of this authorization relationship.. Existence Justification: In sports media rights operations, a single broadcast rights window (e.g., NFL Sunday Ticket, OTT, USA, 2024-2025) is actively distributed across multiple platform channels simultaneously — an OTT app, an IPTV portal, and a DTC streaming endpoint may all be authorized under the same window. Conversely, a platform channel like ESPN+ carries content from dozens of distinct rights windows covering different leagues, territories, and time periods. Rights operations teams actively manage which channels are authorized under which windows, with per-combination terms such as exclusivity scope, DRM policy, and concurrent stream limits that belong to neither entity alone.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`rights_holder` (
    `rights_holder_id` BIGINT COMMENT 'Primary key for rights_holder',
    `parent_rights_holder_id` BIGINT COMMENT 'Self-referencing FK on rights_holder (parent_rights_holder_id)',
    `bank_account_name` STRING COMMENT 'Name on the bank account used for payments to the rights holder.',
    `bank_account_number` STRING COMMENT 'Bank account number for remitting payments to the rights holder.',
    `bank_routing_number` STRING COMMENT 'Bank routing or transit number for the rights holder payment account.',
    `bank_swift_code` STRING COMMENT 'SWIFT/BIC code for international wire transfers to the rights holder.',
    `business_registration_number` STRING COMMENT 'Official business registration or incorporation number issued by the governing jurisdiction.',
    `content_category` STRING COMMENT 'Primary category or genre of content for which this rights holder typically controls media rights. [ENUM-REF-CANDIDATE: wrestling|boxing|mixed_martial_arts|live_events|concerts|sports|entertainment|documentary|reality — promote to reference product]',
    `contract_end_date` DATE COMMENT 'Date when the current master relationship or agreement with this rights holder expires or terminates.',
    `contract_start_date` DATE COMMENT 'Date when the master relationship or first agreement with this rights holder became effective.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the rights holder record was first created in the system.',
    `credit_rating` STRING COMMENT 'Credit rating assigned to the rights holder by recognized rating agencies for financial risk assessment.',
    `currency_code` STRING COMMENT 'Three-letter ISO currency code for the rights holder preferred payment currency.',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether this rights holder has exclusive rights to certain content or territories.',
    `headquarters_address_line1` STRING COMMENT 'Primary street address line for the rights holder headquarters location.',
    `headquarters_address_line2` STRING COMMENT 'Secondary address line for suite, floor, or building information at headquarters location.',
    `headquarters_city` STRING COMMENT 'City where the rights holder headquarters is located.',
    `headquarters_country_code` STRING COMMENT 'Three-letter ISO country code for the rights holder headquarters location.',
    `headquarters_postal_code` STRING COMMENT 'Postal or ZIP code for the rights holder headquarters location.',
    `headquarters_state_province` STRING COMMENT 'State or province where the rights holder headquarters is located.',
    `legal_entity_name` STRING COMMENT 'Official registered legal name of the rights holder entity as it appears in contracts and legal documents.',
    `minimum_guarantee_amount` DECIMAL(18,2) COMMENT 'Minimum guaranteed payment amount committed to this rights holder regardless of performance.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when the rights holder record was last modified or updated.',
    `notes` STRING COMMENT 'Additional notes, comments, or special instructions related to the rights holder relationship.',
    `parent_organization_name` STRING COMMENT 'Name of the parent company or organization if the rights holder is a subsidiary or division.',
    `payment_terms_days` STRING COMMENT 'Standard number of days for payment terms in agreements with this rights holder.',
    `preferred_payment_method` STRING COMMENT 'Preferred method of payment for rights fees and royalties to this rights holder.',
    `primary_contact_email` STRING COMMENT 'Primary email address for business communication with the rights holder organization.',
    `primary_contact_name` STRING COMMENT 'Full name of the primary business contact person at the rights holder organization.',
    `primary_contact_phone` STRING COMMENT 'Primary telephone number for contacting the rights holder organization.',
    `revenue_share_percentage` DECIMAL(18,2) COMMENT 'Standard revenue share percentage applicable to agreements with this rights holder.',
    `rights_holder_code` STRING COMMENT 'Unique business identifier or code assigned to the rights holder for operational reference and system integration.',
    `rights_holder_name` STRING COMMENT 'Full legal name of the rights holder organization or entity that owns or controls media rights.',
    `rights_holder_type` STRING COMMENT 'Classification of the rights holder entity based on organizational structure and business model.',
    `rights_holder_status` STRING COMMENT 'Current lifecycle status of the rights holder relationship indicating operational state.',
    `tax_identification_number` STRING COMMENT 'Government-issued tax identification number for the rights holder entity used for financial reporting and compliance.',
    `territory_scope` STRING COMMENT 'Geographic scope of rights typically held by this rights holder indicating the breadth of their territorial coverage.',
    `website_url` STRING COMMENT 'Official website URL for the rights holder organization.',
    CONSTRAINT pk_rights_holder PRIMARY KEY(`rights_holder_id`)
) COMMENT 'Master reference table for rights_holder. Referenced by rights_holder_id.';

