CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`production_team` (
    `production_team_id` BIGINT COMMENT 'Primary key for production_team',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast network or regional sports network (RSN) that this production team primarily produces content for.',
    `venue_id` BIGINT COMMENT 'Reference to the primary venue or production facility where this team is based and conducts most of their production work.',
    `parent_production_team_id` BIGINT COMMENT 'Self-referencing FK on production_team (parent_production_team_id)',
    `average_setup_time_hours` DECIMAL(18,2) COMMENT 'Average time in hours required for this production team to set up equipment and prepare for a live broadcast event.',
    `certifications` STRING COMMENT 'Comma-separated list of industry certifications held by the production team, such as broadcast engineering certifications, safety certifications, or specialized technical qualifications.',
    `cost_per_event` DECIMAL(18,2) COMMENT 'Average cost in USD to deploy this production team for a single event, including labor, equipment, and operational expenses.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this production team record was first created in the system.',
    `crew_size` STRING COMMENT 'Total number of crew members assigned to this production team including technical, creative, and support staff.',
    `disbanded_date` DATE COMMENT 'Date when this production team was disbanded or decommissioned, if applicable. Null for active teams.',
    `equipment_package_code` BIGINT COMMENT 'Reference to the standard equipment package assigned to this production team including cameras, audio gear, mobile units, and technical infrastructure.',
    `established_date` DATE COMMENT 'Date when this production team was officially formed and became operational.',
    `four_k_capable` BOOLEAN COMMENT 'Indicates whether this production team has the equipment and expertise to produce content in 4K ultra high definition resolution.',
    `hdr_capable` BOOLEAN COMMENT 'Indicates whether this production team can produce content with high dynamic range (HDR) video technology for enhanced visual quality.',
    `insurance_expiry_date` DATE COMMENT 'Date when the production teams insurance policy expires and requires renewal.',
    `insurance_policy_number` STRING COMMENT 'Insurance policy number covering liability, equipment, and crew for this production teams operations.',
    `languages_supported` STRING COMMENT 'Comma-separated list of languages that this production team can produce content in, including commentary, graphics, and on-screen text.',
    `last_assignment_date` DATE COMMENT 'Date of the most recent event or production assignment completed by this production team.',
    `lead_producer_name` STRING COMMENT 'Full name of the lead producer responsible for overseeing the production teams creative and operational output.',
    `live_streaming_capable` BOOLEAN COMMENT 'Indicates whether this production team has the technical capability and expertise to produce live streaming content for over-the-top (OTT) and direct-to-consumer (DTC) platforms.',
    `mobile_unit_capable` BOOLEAN COMMENT 'Indicates whether this production team is equipped and trained to operate mobile broadcast units for remote event coverage.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this production team record was last modified or updated in the system.',
    `multi_camera_capable` BOOLEAN COMMENT 'Indicates whether this production team is trained and equipped to handle multi-camera production setups for complex live events.',
    `next_available_date` DATE COMMENT 'Earliest date when this production team is available for new assignments based on current scheduling commitments.',
    `notes` STRING COMMENT 'Free-form text field for capturing additional information, special requirements, operational notes, or historical context about the production team.',
    `performance_rating` DECIMAL(18,2) COMMENT 'Overall performance rating score for this production team on a scale of 0.00 to 5.00, based on quality assessments, timeliness, and stakeholder feedback.',
    `primary_contact_email` STRING COMMENT 'Primary email address for coordinating with the production team for scheduling, logistics, and operational communications.',
    `primary_contact_phone` STRING COMMENT 'Primary phone number for reaching the production team coordinator or lead producer for urgent production matters.',
    `specialization` STRING COMMENT 'Primary area of expertise or content type the production team specializes in, such as wrestling events, concerts, sports broadcasts, or documentary production.',
    `team_code` STRING COMMENT 'Short alphanumeric code used to identify the production team in scheduling and resource allocation systems.',
    `team_name` STRING COMMENT 'Official name of the production team responsible for broadcast content creation and delivery.',
    `team_status` STRING COMMENT 'Current operational status of the production team indicating availability and assignment state.',
    `team_type` STRING COMMENT 'Classification of the production team based on their primary production focus and operational model.',
    `technical_director_name` STRING COMMENT 'Full name of the technical director responsible for managing the technical aspects of broadcast production including camera operations, audio, and video switching.',
    `total_events_produced` STRING COMMENT 'Cumulative count of all events and productions completed by this production team since formation.',
    `union_affiliated` BOOLEAN COMMENT 'Indicates whether the production team members are affiliated with labor unions such as International Alliance of Theatrical Stage Employees (IATSE) or other broadcast unions.',
    `union_local_number` STRING COMMENT 'The local union chapter number that represents the production team members, if union affiliated.',
    CONSTRAINT pk_production_team PRIMARY KEY(`production_team_id`)
) COMMENT 'Master reference table for production_team. Referenced by production_team_id.';

