    CONSTRAINT pk_distributor PRIMARY KEY(`distributor_id`)
) COMMENT 'Master reference table for distributor. Referenced by distributor_id.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`subscription_plan` (
    `subscription_plan_id` BIGINT COMMENT 'Primary key for subscription_plan',
    `upgraded_from_subscription_plan_id` BIGINT COMMENT 'Self-referencing FK on subscription_plan (upgraded_from_subscription_plan_id)',
    `ad_supported` BOOLEAN COMMENT 'Indicates whether the subscription plan includes advertising content during streaming or is ad-free.',
    `auto_renewal_enabled` BOOLEAN COMMENT 'Indicates whether the subscription automatically renews at the end of each billing cycle unless explicitly cancelled by the customer.',
    `base_price` DECIMAL(18,2) COMMENT 'Standard subscription price before any discounts, taxes, or promotional adjustments in the plans primary currency.',
    `billing_frequency` STRING COMMENT 'Recurring billing cycle interval for subscription charges indicating how often the customer is billed.',
    `blackout_rules_apply` BOOLEAN COMMENT 'Indicates whether regional blackout restrictions apply to certain live events or content based on broadcast rights agreements.',
    `cancellation_policy` STRING COMMENT 'Policy governing when and how customers can cancel their subscription and whether refunds are provided.',
    `content_library_access` STRING COMMENT 'Level of access to the content library indicating which content tiers and archives are available to subscribers.',
    `contract_term_months` STRING COMMENT 'Minimum commitment period in months for the subscription plan. Null indicates a month-to-month plan with no minimum commitment.',
    `corporate_license_eligible` BOOLEAN COMMENT 'Indicates whether this plan is available for corporate or enterprise licensing agreements with volume pricing and centralized billing.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this subscription plan record was first created in the system.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code indicating the denomination of all monetary amounts for this plan.',
    `subscription_plan_description` STRING COMMENT 'Detailed description of the subscription plan features, benefits, and included content for customer-facing materials and internal reference.',
    `dvr_enabled` BOOLEAN COMMENT 'Indicates whether subscribers can record live broadcasts for later viewing using cloud DVR functionality.',
    `dvr_storage_hours` STRING COMMENT 'Maximum hours of content that can be stored in cloud DVR. Null indicates DVR is not available or unlimited storage.',
    `effective_end_date` DATE COMMENT 'Date when the subscription plan is no longer available for new subscriptions. Null indicates an open-ended plan with no planned discontinuation.',
    `effective_start_date` DATE COMMENT 'Date when the subscription plan becomes available for purchase and activation by customers.',
    `family_sharing_enabled` BOOLEAN COMMENT 'Indicates whether the subscription can be shared among multiple family members with separate profiles under a single account.',
    `geographic_restriction` STRING COMMENT 'Geographic regions or countries where this subscription plan is available for purchase and use, enforcing content licensing and distribution rights.',
    `live_event_access` BOOLEAN COMMENT 'Indicates whether subscribers have access to live streaming of sports events, concerts, and entertainment programming.',
    `max_concurrent_streams` STRING COMMENT 'Maximum number of simultaneous video streams allowed under this subscription plan for multi-device viewing.',
    `max_devices` STRING COMMENT 'Maximum number of devices that can be registered and authorized to access content under this subscription plan.',
    `max_family_members` STRING COMMENT 'Maximum number of family member profiles that can be created under a family sharing subscription. Null if family sharing is not enabled.',
    `modified_by` STRING COMMENT 'Identifier of the user or system that last modified this subscription plan record for audit trail and change tracking.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this subscription plan record was last modified or updated.',
    `offline_download_enabled` BOOLEAN COMMENT 'Indicates whether subscribers can download content for offline viewing on authorized devices.',
    `parental_controls_available` BOOLEAN COMMENT 'Indicates whether parental control features are available to restrict content access based on ratings and categories.',
    `partner_program_eligible` BOOLEAN COMMENT 'Indicates whether this subscription plan is eligible for partner bundling programs with telecommunications providers, cable companies, or other distribution partners.',
    `plan_code` STRING COMMENT 'Externally-known unique business identifier for the subscription plan used in billing systems, customer communications, and marketing materials.',
    `plan_name` STRING COMMENT 'Human-readable marketing name of the subscription plan displayed to customers and used in promotional materials.',
    `plan_type` STRING COMMENT 'Classification of the subscription plan indicating the tier and target customer segment.',
    `ppv_discount_percentage` DECIMAL(18,2) COMMENT 'Percentage discount applied to pay-per-view event purchases for subscribers of this plan. Null indicates no PPV discount.',
    `promotional_code` STRING COMMENT 'Marketing promotional code associated with special offers or campaigns for this subscription plan. Null for standard non-promotional plans.',
    `subscription_plan_status` STRING COMMENT 'Current lifecycle status of the subscription plan indicating availability for new subscriptions and operational state.',
    `student_verification_required` BOOLEAN COMMENT 'Indicates whether student status verification is required to purchase and maintain this subscription plan, typically for discounted student plans.',
    `trial_period_days` STRING COMMENT 'Number of days for the free trial period before billing begins. Zero or null indicates no trial period is offered.',
    `video_quality` STRING COMMENT 'Maximum video resolution and quality level available to subscribers under this plan for streaming content.',
    `created_by` STRING COMMENT 'Identifier of the user or system that created this subscription plan record for audit and accountability purposes.',
    CONSTRAINT pk_subscription_plan PRIMARY KEY(`subscription_plan_id`)
) COMMENT 'Master reference table for subscription_plan. Referenced by plan_id.';

